-- Poems batch 191
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6a0a64d6-e519-4a24-a927-ceaadc4d16ef','挽劉文安公','蔡沈','宋','宋诗','song-poetry','','[]','考亭雲谷孰居先，名世悠然得正傳。',64,'全唐诗/poet.song.183000.json','["考亭雲谷孰居先，名世悠然得正傳。", "窮理致知須主敬，存心養性道齊賢。", "凌雲端擬陳三策，魂夢那知隔九泉。", "後世表章尊所學，四書功足繼朱宣。"]'),
('2b45ff46-94a1-4d5d-b607-432f60f23335','武夷自詠','蔡沈','宋','宋诗','song-poetry','','[]','武夷群岫高崔嵬，隠屏直聳天中開。',112,'全唐诗/poet.song.183000.json','["武夷群岫高崔嵬，隠屏直聳天中開。", "千尋拔地出圭壁，屼屼萬古封蒼苔。", "煙霞舒卷朝夕異，日月晝夜東西迴。", "寒流詰曲抱巖足，水清沙碧直蓬萊。", "紫京真人玉爲杯，瓊漿初發葡萄醅。", "醉來披雲卧松月，松花點點飄香雪。", "哀猿絕壁聲更長，惆悵懷人逮明發。"]'),
('9971587d-7dfc-4890-8392-144e311ec686','贈琴士翁明遠','蔡沈','宋','宋诗','song-poetry','','[]','膠漆本無意，絲桐非有情。',112,'全唐诗/poet.song.183000.json','["膠漆本無意，絲桐非有情。", "因緣醉翁指，發此無窮聲。", "蕭蕭秋風引，落葉渭水清。", "喧喧陽春歌，花明錦江城。", "離鸞月徘徊，別鶴雲杳冥。", "清泠洒毛髮，震蕩驚雷霆。", "曲度神莫測，調高妙難名。", "時方多艱虞，掩耳誰爲聽。", "無爲恩怨兒女語，疆場勇士軒昂行。"]'),
('097a1e42-e4fc-4d9e-bf3b-03a63398eebc','讀江西詩呈游光化料院','蔡沈','宋','宋诗','song-poetry','','[]','江西多秀士，卓躒相後先。',156,'全唐诗/poet.song.183000.json','["江西多秀士，卓躒相後先。", "其中最翹楚，無出黄陳前。", "森然插天幹，琢削草舍椽。", "羌童扣金石，越女調管絃。", "非無要妙音，難與韶濩傳。", "王風惜云遠，屈宋美獨專。", "沉濃玄暉詩，典雅淵明篇。", "少陵備衆體，太白真謫仙。", "微情寄風月，肺腑皆天然。", "自從句中眼，一字千金錢。", "于今百餘載，誦說如河懸。", "人惟屋下屋，何以千萬間。", "正聲日微茫，寂感空無邊。"]'),
('cdccd04a-5021-44f5-a9bd-6e6c95cc7371','古意二首  其一','蔡沈','宋','宋诗','song-poetry','','[]','古人不可見，末習徒紛然。',60,'全唐诗/poet.song.183000.json','["古人不可見，末習徒紛然。", "精微固難知，論議胡爾偏。", "郢曲聽者誰，巴唱和乃千。", "世道既若茲，淳風何當還。", "矯矯且自强，天運終來旋。"]'),
('9252c638-81bf-460e-8a10-2a2788caa9e0','古意二首  其二','蔡沈','宋','宋诗','song-poetry','','[]','種木必培根，清流必澄源。',60,'全唐诗/poet.song.183000.json','["種木必培根，清流必澄源。", "根源得其理，流末迺可言。", "聖賢本始務，條達蓋自然。", "時俗枝委求，持操空爾煩。", "存存此成性，道義斯其門。"]'),
('9276dc54-e44e-4447-b39a-00cd55bca243','偶題','蔡沈','宋','宋诗','song-poetry','','[]','作書與蜀客，止爲求知音。',48,'全唐诗/poet.song.183000.json','["作書與蜀客，止爲求知音。", "不料緣素絲，却與多黄金。", "今情既已異，古意何由尋。", "一笑陶靖節，雅趣無絃琴。"]'),
('31ba6089-ef13-4f66-ac17-d486b911dc76','偶題三首  其一','蔡沈','宋','宋诗','song-poetry','','[]','暮年無雜慮，何事更關情。',48,'全唐诗/poet.song.183000.json','["暮年無雜慮，何事更關情。", "入市非求利，居山豈爲名。", "誠存心自逸，足健步常輕。", "却是行遊處，春風日日生。"]'),
('1b3569a5-1cc0-451e-afe9-2cab80cac542','偶題三首  其二','蔡沈','宋','宋诗','song-poetry','','[]','寂寞園林迥，棲遲念慮寬。',48,'全唐诗/poet.song.183000.json','["寂寞園林迥，棲遲念慮寬。", "雨聲連砌響，風色入簾寒。", "義理無新得，交遊少舊懽。", "梅花自疇昔，歲晚獨相看。"]'),
('8c10e34f-144c-4697-bade-b3782f1c7836','偶題三首  其三','蔡沈','宋','宋诗','song-poetry','','[]','日日門前路，春風與物期。',48,'全唐诗/poet.song.183000.json','["日日門前路，春風與物期。", "早梅紛白雪，垂柳散青絲。", "把酒懷情久，吟詩遣興遲。", "閑來復閑往，携策謾逶迤。"]'),
('406a94cd-68e0-4f56-a0ef-03140478a97f','夜讀蘇州詩','蔡沈','宋','宋诗','song-poetry','','[]','夜讀蘇州詩，襟懷盡冰雪。',48,'全唐诗/poet.song.183000.json','["夜讀蘇州詩，襟懷盡冰雪。", "飄飄關塞雲，微微河漢月。", "秋蘭南窗前，清香靜中發。", "懷我千載心，歲晚更幽絕。"]'),
('16666a3d-47f4-4387-8431-9fc1baf70a34','歸自城中承介卿寵顧惠詩次韵','蔡沈','宋','宋诗','song-poetry','','[]','幽雅從君志，驅馳愧我人。',48,'全唐诗/poet.song.183000.json','["幽雅從君志，驅馳愧我人。", "無忘歲時舊，因得笑言親。", "心賞知非故，詩成語自新。", "一川風景會，樽酒且頻頻。"]'),
('fb34e7f8-1697-4c20-b950-f9e6f78bfb58','絕句','蔡沈','宋','宋诗','song-poetry','','[]','積雨添泉脈，寒來送兩山。',24,'全唐诗/poet.song.183000.json','["積雨添泉脈，寒來送兩山。", "南風北窗下，午夢聽潺湲。"]'),
('e5251bd0-567b-4184-aa45-b53dcba3fa0c','和伯氏用介卿韵惠詩二首  其一','蔡沈','宋','宋诗','song-poetry','','[]','信筆題詩學行餘，功名聊且付樵漁。',64,'全唐诗/poet.song.183000.json','["信筆題詩學行餘，功名聊且付樵漁。", "心閑獨玩三秋榦，足健時看數畝蔬。", "渺渺橘園聯草閣，疎疎竹徑傍田廬。", "是間日有無窮趣，月淡風清靜讀書。"]'),
('902f4709-6dab-4661-ae74-af12b454f2c8','和伯氏用介卿韵惠詩二首  其二','蔡沈','宋','宋诗','song-poetry','','[]','悄悄園林世味長，碧雲疎散暮天光。',64,'全唐诗/poet.song.183000.json','["悄悄園林世味長，碧雲疎散暮天光。", "且寬禮樂興江左，厭聽干戈暗洛陽。", "梨葉盡時無伏暑，竹陰深處有餘凉。", "從容領會精微旨，何用區區底事忙。"]'),
('b4083443-5e4a-4a63-8ec6-5aa2f9f11daa','次劉子融言詩之韵','蔡沈','宋','宋诗','song-poetry','','[]','試將風月共君哦，識處應須出舊科。',64,'全唐诗/poet.song.183000.json','["試將風月共君哦，識處應須出舊科。", "吟咏性情當自得，敷張華藻第差訛。", "入神致用何思慮，告往知來謾切蹉。", "欲達古詩三百義，一言而蔽不須多。"]'),
('98912ce9-fc30-429d-a9f2-fdafdbe4d140','劉子野携諸名公詩軸見過爲書其後','蔡沈','宋','宋诗','song-poetry','','[]','畏暑懶出戶，息心聊罷詩。',48,'全唐诗/poet.song.183000.json','["畏暑懶出戶，息心聊罷詩。", "諸公舊有作，其意已無遺。", "嶺表經行處，賢闕扣見時。", "悠然皆往事，勉務日新期。"]'),
('83698ba0-aaea-437b-b51e-bd78f98574d0','謝人惠詩','蔡沈','宋','宋诗','song-poetry','','[]','歲事已無幾，相過常少賓。',48,'全唐诗/poet.song.183000.json','["歲事已無幾，相過常少賓。", "扣門來剝啄，握手見情親。", "月窟文章客，花巖老病身。", "從茲襟義合，有約待新春。"]'),
('70db0e36-95ea-4333-812b-390c888c5b25','雙林壁間有人寫董仲達希字韵詩和者紛紛因用韵','蔡沈','宋','宋诗','song-poetry','','[]','寺古蒼松老，僧高俗客希。',24,'全唐诗/poet.song.183000.json','["寺古蒼松老，僧高俗客希。", "我來遊竟日，不用筍輿歸。"]'),
('4452a51d-d8d5-4bb2-86ad-99cc9790f987','曾景山猶子覓詩','蔡沈','宋','宋诗','song-poetry','','[]','勿謂參也魯，孔門最少年。',24,'全唐诗/poet.song.183000.json','["勿謂參也魯，孔門最少年。", "能於一唯間，頓悟冠三千。"]'),
('29ae5024-48af-4163-8119-70bdd856650f','送連惟馨之小湖兼簡程節推','蔡沈','宋','宋诗','song-poetry','','[]','本有瓜葛舊，况乃桑梓情。',84,'全唐诗/poet.song.183000.json','["本有瓜葛舊，况乃桑梓情。", "浮雲無定姿，飄泊湖溪濱。", "春晴百花發，忍對江頭別。", "垂楊弄柔絲，含愁不能折。", "湖溪故人心，寒潭照秋月。", "一別經十年，俯仰傷契闊。", "爲言山中友，青陽半華髮。"]'),
('8171064a-8971-4c01-9dca-3fd8a7d7c1df','題范伯詩顧齋','蔡沈','宋','宋诗','song-poetry','','[]','時人欲作聖賢歸，反己由來自不欺。',64,'全唐诗/poet.song.183000.json','["時人欲作聖賢歸，反己由來自不欺。", "談話每虞無十步，持循長恐有虛辭。", "硜硜固不爲茲必，踽踽寧求可善斯。", "喫緊此心常自在，一誠之外靡餘師。"]'),
('619352f3-bebc-45e2-8fb5-2062d1bd9ee9','玉堂真丈索毋自欺齋詩','蔡沈','宋','宋诗','song-poetry','','[]','人心具天德，氣稟有昏明。',144,'全唐诗/poet.song.183000.json','["人心具天德，氣稟有昏明。", "學以致其知，善惡義迺陳。", "惡既在必去，善即在持循。", "知之雖曰至，行之貴乎誠。", "念慮或未實，覆護尋亦生。", "遂令負初心，怛焉愧於人。", "君子必謹獨，暗室十目瞋。", "毫釐不苟徇，隠微常戰兢。", "好惡慊於己，擇言無在身。", "由中以達外，萬善皆精純。", "大書毋自欺，高齋扁新名。", "居常目在是，以况湯盤銘。"]'),
('24b4eb08-fdee-47c8-b783-234c90201888','和陳子公井齋韵','蔡沈','宋','宋诗','song-poetry','','[]','生來井井義誰窮，陽自初來位五中。',32,'全唐诗/poet.song.183000.json','["生來井井義誰窮，陽自初來位五中。", "若信此間方寸地，能安而慮即成功。"]'),
('661bd44b-f435-44ac-b5da-d66a850540ac','早梅寄周純臣','蔡沈','宋','宋诗','song-poetry','','[]','秋風日日吹芳草，山北山南跡如掃。',64,'全唐诗/poet.song.183000.json','["秋風日日吹芳草，山北山南跡如掃。", "江梅一夜暗將春，疎影橫斜水邊道。", "道逢驛使江南歸，袖中袖出天香老。", "英姿獨步霜雪中，清癯只爲風流早。"]'),
('ef83d593-5b2c-4055-b75e-8eb5964b4c64','和吳伯綸早梅','蔡沈','宋','宋诗','song-poetry','','[]','籬落當歲暮，春至無人知。',48,'全唐诗/poet.song.183000.json','["籬落當歲暮，春至無人知。", "鸞鶴倏爾集，蜂蝶還先期。", "月落步疎影，空明見幽姿。", "香氣誰與達，頼有清風吹。"]'),
('a4cf946f-48e5-443e-80d2-a0a97e4daea1','和介卿唐石道中早梅','蔡沈','宋','宋诗','song-poetry','','[]','六曲溪頭處士家，年年籬落萬枝花。',32,'全唐诗/poet.song.183000.json','["六曲溪頭處士家，年年籬落萬枝花。", "怪來驛使無消息，却報烟村一樹斜。"]'),
('293843ee-7af7-4c7f-9d5a-36048c7ea191','紅梅','蔡沈','宋','宋诗','song-poetry','','[]','一樹芳菲露短牆，綵霞千縷带斜陽。',32,'全唐诗/poet.song.183000.json','["一樹芳菲露短牆，綵霞千縷带斜陽。", "東君賦予知何意，剩與臙脂便嗇香。"]'),
('2a44f826-b929-4b6c-b9d2-3d42e3bbd41a','蠟梅','蔡沈','宋','宋诗','song-poetry','','[]','造物無窮巧，寒芳品更殊。',48,'全唐诗/poet.song.183000.json','["造物無窮巧，寒芳品更殊。", "花腴真類假，枝瘦嬾猶枯。", "帝子明黄表，宮人隠絳襦。", "若論風韵別，桃李亦爲奴。"]'),
('99ae4f18-96f3-480e-85da-b69f00c9e136','馬司戶所作墨梅並示佳作因次韵','蔡沈','宋','宋诗','song-poetry','','[]','誰把霜毫歸庾嶺，王孫去後久寥寥。',64,'全唐诗/poet.song.183000.json','["誰把霜毫歸庾嶺，王孫去後久寥寥。", "長時月夜橫疎影，鎮日春風上素綃。", "可笑兒童尋剪摘，如知蜂蝶亦邀招。", "人心造物無窮巧，頃刻功成永不摇。"]'),
('df5d1788-4654-4544-9de8-4a38ae3bcf73','和伯氏懷人韵','蔡沈','宋','宋诗','song-poetry','','[]','懷人復懷人，懷憂不能寫。',48,'全唐诗/poet.song.183000.json','["懷人復懷人，懷憂不能寫。", "滄浪有舟楫，便欲從東下。", "春寒雨淋淋，舟楫不可尋。", "臨流一惆悵，直下萬里深。"]'),
('100fec17-f9ee-4435-876b-0ec3641e1da2','胥村','蔡沈','宋','宋诗','song-poetry','','[]','楚國當年濫政刑，子胥何事亦鞭平。',32,'全唐诗/poet.song.183000.json','["楚國當年濫政刑，子胥何事亦鞭平。", "當時若有權輕重，止合終身去郢城。"]'),
('e010ea33-e799-4f83-8119-33a3f04f2a5c','送江端伯之隆興','蔡沈','宋','宋诗','song-poetry','','[]','人生辛苦惟別離，况復心相知。',270,'全唐诗/poet.song.183000.json','["人生辛苦惟別離，况復心相知。", "辛酸話別語不出，相看執手徒依依。", "問君西遊何歸期，長途巉巖不可思。", "春霜日暮山谷裏，寒風凜凜吹人衣。", "中林啞啞烏欲棲，猿猱虎豹夾路啼。", "路傍古屋掩柴扉，空房獨宿生新悲。", "家山昨夜春始至，桃花初破梅花飛。", "自非丈夫剛自許，誰不去住生狐疑。", "惟君與我同此志，西湘東越頻驅馳。", "番陽浩蕩六百里，南昌風物雄江西。", "西山中峙高崔嵬，滕王傑閣橫江開。", "五更東望紅浴日，魚龍蛟蜃驚相積。", "陽門青松青可挹，劍池清水清可吸。", "真人鶴嶺遺金丹，中峰蒼莽風常寒。", "遊人西遊止此地，眼明足健應忘還。", "閩山豈足展羽翮，湖光望極天地寬。", "鯤鵬變化知有托，歸來長鋏寧須彈。"]'),
('f649dd04-7f2f-45f5-965c-7e74d776acb1','南昌城','蔡沈','宋','宋诗','song-poetry','','[]','巍城十八里，雄壯稱洪都。',120,'全唐诗/poet.song.183000.json','["巍城十八里，雄壯稱洪都。", "北郭勢迤邐，南浦形縈紆。", "連亙控西江，囊括盡東湖。", "灌侯遺故址，李相規舊模。", "改築龍沙堤，三方第如初。", "得非彫殘後，民力不足歟。", "得非府庫竭，費用不給歟。", "當時廟堂上，不主公議歟。", "我來客城闉，感慨成欷吁。", "今古如一轍，有才能遠圖。"]'),
('972f5828-22ef-4e28-a095-bbaf9db83424','游靈巖分韵得從字','蔡沈','宋','宋诗','song-poetry','','[]','我來靈巖遊，坐石披蒙葺。',84,'全唐诗/poet.song.183000.json','["我來靈巖遊，坐石披蒙葺。", "翛然忘世紛，便欲脫屣從。", "外峻懸絕磴，中寬峙高峰。", "精廬三數間，歲久蒼苔封。", "寒藤結暝色，秋花歛愁容。", "哀猿發清聲，月影山重重。", "扁舟暮江下，疎林聞夜鍾。"]'),
('59962e46-fba7-4e6f-8fd2-a07b07c37098','送王禹玉遊西巖','蔡沈','宋','宋诗','song-poetry','','[]','幽人欲往西巖巔，臨風送目心悠然。',80,'全唐诗/poet.song.183000.json','["幽人欲往西巖巔，臨風送目心悠然。", "芒鞋竹杖風月冷，千山萬壑開晴煙。", "人生適意多掣肘，窮欲入山山不受。", "嚴光終老釣臺春，李白謾醉長安酒。", "殷勤爲我語山靈，白頭管取相看守。"]'),
('5c8756d6-b51d-4327-8fbb-8ac906e55728','寄贈江寧劉明府','蔡沈','宋','宋诗','song-poetry','','[]','南陸晝日永，北窗風氣清。',120,'全唐诗/poet.song.183000.json','["南陸晝日永，北窗風氣清。", "端居玩時物，園林綠陰成。", "新竹梢已繁，脩梧葉初榮。", "翩翩有幽禽，睍睆發清聲。", "豈無樽酒歡，撫景難自傾。", "親朋天一端，別我歲倏更。", "衷丹寄秋毫，香煤染霜藤。", "耿耿嘆離羣，拳拳懷友生。", "珍重萬金抵，契闊千恨平。", "欲題尺書報，惻愴若爲情。"]'),
('d085e2c0-a68a-49eb-b52f-47396dbf97cc','讀王莽傳寄廖判府','蔡沈','宋','宋诗','song-poetry','','[]','噫吁嚱，噫嚱一曲難爲聽，桑麻壠畝今荆榛。',148,'全唐诗/poet.song.183000.json','["噫吁嚱，噫嚱一曲難爲聽，桑麻壠畝今荆榛。", "子規夜訴倉庚鳴，時至氣化能無聲。", "高皇神武百世業，安漢小子爲憑陵。", "九十六萬目可掩，奈何從臾皆羣臣。", "臣乎臣乎胡乃爾，富汝貴汝庸何生。", "炎精白晝欲晦蝕，日角眉目尤精神。", "古來權柄不早去，止爲魚肉塗生靈。", "生靈塗炭自茲始，古往今來祇如此。", "重華一去何時還，志士幽人淚如雨。"]'),
('70dfb97f-abf9-449f-bb39-65e90aa3bb9d','贈武夷熊聖功隠士','蔡沈','宋','宋诗','song-poetry','','[]','里閈皆華族，雲山獨草廬。',48,'全唐诗/poet.song.183000.json','["里閈皆華族，雲山獨草廬。", "非求龍虎鼎，爰傍聖賢居。", "石聳千尋直，溪涵萬頃虛。", "文公精爽在，風月夜何如。"]'),
('20d0faa3-475f-449e-87e8-e26d0c0d8c91','張才叔屢作文公先生像如其生焉亦託名不朽矣二首  其一','蔡沈','宋','宋诗','song-poetry','','[]','才叔傳神筆更奇，一分爲二兩無疑。',32,'全唐诗/poet.song.183000.json','["才叔傳神筆更奇，一分爲二兩無疑。", "心追造物無窮巧，後代能名今可知。"]'),
('7a00e50c-8574-429a-ae90-d9934c13d262','張才叔屢作文公先生像如其生焉亦託名不朽矣二首  其二','蔡沈','宋','宋诗','song-poetry','','[]','紫陽遺像壁間開，誰寫當年道義懷。',32,'全唐诗/poet.song.183000.json','["紫陽遺像壁間開，誰寫當年道義懷。", "從此春風百千億，化身皆自筆端來。"]'),
('93be306c-ba00-4c7c-bce4-6e196456b6df','句  其一','蔡沈','宋','宋诗','song-poetry','','[]','游魚顧影驚寒月，宿鷺迷群下夕陽。',16,'全唐诗/poet.song.183000.json','["游魚顧影驚寒月，宿鷺迷群下夕陽。"]'),
('1ae1ed5d-9531-426b-bf77-92bb87b6565f','句  其二','蔡沈','宋','宋诗','song-poetry','','[]','靜尋啄木藏身處，閒看游絲到地時。',16,'全唐诗/poet.song.183000.json','["靜尋啄木藏身處，閒看游絲到地時。"]'),
('7b3460d5-5059-463b-a28b-ed5894505c98','次韵安撫侍郎勸耕喜雨之什','度正','宋','宋诗','song-poetry','','[]','田家何所樂，所樂日未曛。',240,'全唐诗/poet.song.183000.json','["田家何所樂，所樂日未曛。", "男耕而禾稼，女桑而襦裙。", "面垢落塈塗，目眩濕薪熏。", "婦子饁南畝，詩人嘗云云。", "使車出東郊，好雨清塵氛。", "會集諸父老，申之以儉勤。", "父老歌且舞，未飲意已醺。", "峩峩欲傾欹，眊眊聳聽聞。", "扶携兩階上，瀲灧泛十分。", "丁寧付訓詞，歸詔爾仍雲。", "或笑言唯唯，或喜氣氳氳。", "俯首側玄冠，駢肩望朱幩。", "通宵得膏澤，綠波漲河濆。", "輕風扇微和，草木亦欣欣。", "正也何其幸，連年與禮文。", "念昔在農畝，備嘗辛與葷。", "朅來充邑官，簿書困紛紛。", "書生適我願，端頼賢使君。", "人苟得所依，何畏乎織紋。", "感知無以報，茅塞當深耘。"]'),
('90c7f049-46df-4111-a4de-1ecf90ff710c','青松一首送楊侍郎丈赴闕','度正','宋','宋诗','song-poetry','','[]','東山種青松，西山種榿木。',288,'全唐诗/poet.song.183000.json','["東山種青松，西山種榿木。", "三年已成林，十載盤空谷。", "榿成供烹爨，松成架巨屋。", "所用各兩塗，成功異遲速。", "早作起攬袂，庖人已炊玉。", "盈車載束薪，軋軋鳴車轂。", "萬家爭欲買，須臾無一束。", "樵夫喜易售，不知山已禿。", "朝夕手不停，采采嘗不足。", "人情貴適用，那復問榮辱。", "落落青松子，歲寒抱孤獨。", "大可充棟梁，小亦宜桁楅。", "奈何人不顧，偃蹇傲芻牧。", "牽補芘風雨，無復思營築。", "有如命召公，往欲尋洛卜。", "首當開明堂，號令於此肅。", "明堂禮有制，伻圖載簡牘。", "殷人崇以三，周制加其六。", "廣袤度尤嚴，所冀容羣服。", "奉璋列左右，天顔中穆穆。", "規恢既宏遠，制作難逼促。", "當資合抱幹，一柱扶天軸。", "切勿用小材，小材必傾覆。", "操斤走宇內，濯濯無遺育。"]'),
('8fadbb09-2d64-4729-851b-66949750df7a','正同諸丈餞別制幹郎中','度正','宋','宋诗','song-poetry','','[]','春風來戶牖，春雨過庭隅。',288,'全唐诗/poet.song.183000.json','["春風來戶牖，春雨過庭隅。", "攬袂送征車，去去不須臾。", "借問何人斯，玉立美且姝。", "慶曆丞相孫，太學學爲儒。", "一日上震怒，大姦伏其辜。", "議者不深計，但惟和是圖。", "直欲函其首，而往獻匈奴。", "君言國大柄，不過賞與誅。", "況此非常刑，何言歸之歟。", "日月天之經，山河地之樞。", "綱維在名分，臣子當力扶。", "大義儻一失，自今難枝吾。", "此事如君家，曾老姑之夫。", "又如和議初，編修澹齋胡。", "精誠貫金石，勇氣激頑懦。", "北庭聞此言，何敢更凶愚。", "公卿顧之嘆，識者空嗟吁。", "有如此英才，一第豈足汙。", "便當司獻納，朝夕贊廟謨。", "奈何遺之外，沈浮在江湖。", "應聘入賓筵，萬里來成都。", "我昔聞其名，英聲震八區。", "今幸見其面，堂堂六尺軀。", "胸中浩無際，萬卷儲經郛。"]'),
('55ee4c84-107c-4032-b913-527a5dfb1e11','送新四川茶馬','度正','宋','宋诗','song-poetry','','[]','慶元二年春，有詔來自東。',252,'全唐诗/poet.song.183000.json','["慶元二年春，有詔來自東。", "曰東川漕臣，憂國盡變通。", "東川十五郡，連年歲不豐。", "國計僅以足，民力幾窮空。", "頼茲經綸手，調護遂奏功。", "曰維榷牧司，有言驚聖聰。", "咨爾予漕臣，僉言爾惟忠。", "往哉其撫事，惟和惟其中。", "蜀人聞天書，喜氣如春風。", "竊思斟酌權，大概不可窮。", "在昔元祐間，委付失狂童。", "苞苴肆分行，錐刀到心胸。", "小蘇抗章論，大蘇以詩攻。", "至今百世下，得失爛如烘。", "明公冰霜姿，材業尤雄雄。", "剸割一指間，妙用付天工。", "鳥獸雖無知，好惡人則同。", "覿德自來馴，遇暴輒興戎。", "從茲三邊人，稽首不敢凶。", "蜀人願公留，天子將思公。", "謂公曰還歸，其以來年冬。"]'),
('9d843cf6-9249-4de3-91f2-768ca177e2a4','送王中父制幹東歸探韵得限字分韵用離別不堪無限意艱危深仗濟時才','度正','宋','宋诗','song-poetry','','[]','漢使東南來，幕府皆異産。',144,'全唐诗/poet.song.183000.json','["漢使東南來，幕府皆異産。", "英英江左家，浩浩富編簡。", "幾年翔學海，屢薦升士版。", "大焉合訏謨，小亦堪論譔。", "橫身借前箸，逸氣薄雲棧。", "向雖稔聲名，曾未陪笑莞。", "邂逅解白眉，軒豁蒙青眼。", "俊遊得從容，微辭略往返。", "扁舟賦歸程，駿馬馳平坂。", "上策今安在，時髦貴謹柬。", "中規儻前定，外患豈足剗。", "善保千金軀，欲語意無限。"]'),
('fb242ce2-139a-416a-bcef-965001e31453','送張伯修省幹歸省重慶府一首','度正','宋','宋诗','song-poetry','','[]','我昔赴集英，涪陵見尊公。',180,'全唐诗/poet.song.183000.json','["我昔赴集英，涪陵見尊公。", "尊公一世豪，一飲能千鍾。", "君時年尚少，已有尊公風。", "舉動如成人，吐語非凡童。", "別去已十載，一牋不得通。", "憂患催我老，飄流寄西東。", "逐食來益昌，執經司學宮。", "故人昂昂來，天涯復相逢。", "憐我久憔悴，訪我寂寞中。", "相從不知極，春去秋復冬。", "慈親促歸輈，歸步留無從。", "入則孝與悌，出則信與忠。", "君看語孟篇，問學何終窮。", "寸陰如隙駒，大道如冥鴻。", "重來定何時，願言加新功。"]'),
('d5c897f5-f27a-4f88-b69c-bca8d04a91ac','送唐寺丞丈解郡紱東歸一首','度正','宋','宋诗','song-poetry','','[]','北溟有脩鱗，其大無匹儔。',216,'全唐诗/poet.song.183000.json','["北溟有脩鱗，其大無匹儔。", "化而爲羽翼，頃刻徧九州。", "天地吾一體，日月吾雙眸。", "一飲萬斛泉，一飯萬頭牛。", "藏修丘壑間，昂昂亦無求。", "塵寰何迫隘，飛鳴不自由。", "蝦蟹及蛙黽，孤豚及青鼩。", "紛紛如蝟毛，乘時恣喧咻。", "其耳若不聞，其聲轉清幽。", "其貌甚閒暇，其心亦休休。", "長思日月明，西天雲霧收。", "東至于蓬萊，西至于崑丘。", "北至于窮髮，南至于不周。", "宇宙渺一視，去息無拘留。", "我欲效鶴雛，鳴和聲相酬。", "終焉附其翼，一旦凌空遊。", "使彼毛羽蟲，垂頭自懷羞。", "此心如白璧，秋陽照江流。"]'),
('710cd6f2-54ea-4dde-981b-a956737c55d1','奉別劉思中','度正','宋','宋诗','song-poetry','','[]','憶昨我初往，斗杓正南陬。',180,'全唐诗/poet.song.183000.json','["憶昨我初往，斗杓正南陬。", "陽氣已汗漫，伏陰纔如勾。", "既見御史公，文書煩校讎。", "時時延上坐，不聽毀者謀。", "公兄東溪老，博我詩之幽。", "軒然肯相顧，妙語吐如流。", "諸郎冰雪姿，學問誰朋儔。", "其長遇我厚，久要何綢繆。", "感知不忍去，坐閲四月周。", "寒暑無停機，忽忽今已秋。", "我學曾幾何，我懷良獨憂。", "親庭催我歸，歲晏無寒不。", "朋友催我歸，仁義相講求。", "山林本其性，麋鹿本其遊。", "再拜謝所知，去去毋苦留。"]'),
('9c5ec62d-97b5-4e6a-8086-7cef5714b331','奉別唐寺丞丈一首','度正','宋','宋诗','song-poetry','','[]','正家巴山陽，占田纔百畝。',288,'全唐诗/poet.song.183000.json','["正家巴山陽，占田纔百畝。", "春秋自耕稼，亦足餬其口。", "中年或水旱，采蕨充飯糗。", "四壁固屢空，滿屋貯蝌蚪。", "少蒙義方訓，交口相傳授。", "日記數百言，勇氣摩星斗。", "既長遊鄉校，稍稍別妍醜。", "父曰爾勉哉，學問貴悠久。", "悚然銘諸內，庶幾造淵藪。", "奈何天降割，纍纍若孤狗。", "三年抱憂患，忍復言進取。", "洪惟太上皇，下詔羅瓊玖。", "提筆入貢士，肝肺始一嘔。", "時年二十四，一得殆天偶。", "自茲青衫縛，連年事奔走。", "得官涪江上，距家纔百九。", "一年一歸安，親族相聚首。", "留連輒數月，官長怒訶吼。", "三書下下考，薦者一邱叟。", "浩然賦歸歟，忽復失箕箒。", "獨身當門闌，內外事紛糾。", "母曰毋自棄，一出庸可咎。", "迺趨光範門，所志在升斗。", "是時京宰相，來者無不受。"]'),
('a0dbf33c-3850-4895-a589-ed33e6b91557','校書西衙枕上呈劉原朝','度正','宋','宋诗','song-poetry','','[]','夜雨不肯曉，擁衾獨長嘆。',48,'全唐诗/poet.song.183000.json','["夜雨不肯曉，擁衾獨長嘆。", "借問嘆何爲，嘿嘿終無言。", "迴風起相薄，萬物無歡顔。", "我心如古人，作詩歌歲寒。"]'),
('6888a722-a714-4ec3-868c-5fd698f5b208','昨蒙謂卿機宜學士佳章寵寄謹依元韵酬謝乞幸笑覽','度正','宋','宋诗','song-poetry','','[]','君家謫仙人，豪俠好駡譏。',168,'全唐诗/poet.song.183000.json','["君家謫仙人，豪俠好駡譏。", "脫靴辱權幸，捧硯誇寵妃。", "風月三千首，百卉弄春暉。", "恭惟紫微公，執筆贊萬幾。", "大行或差舛，考驗在璿璣。", "同時三君子，日月爭光輝。", "我生百年後，覽之神奮飛。", "粵從志學來，斯文力發揮。", "瓦劄带塵壤，羊毛拂煙霏。", "言詞雖不工，往往造精微。", "邂逅逢名世，如何尚布衣。", "爲我特傾倒，我心亦依依。", "從今願卜隣，窮空不思歸。", "厚意敢虛辱，三尺橫金徽。"]'),
('acfcd0ae-f8e3-48d4-b32d-c6eb8c5ba96f','寄襄陽楊侍郎三丈','度正','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','茫茫天地間，萬象森紛羅。',288,'全唐诗/poet.song.183000.json','["茫茫天地間，萬象森紛羅。", "迺眷蜀三川，神氣尤雄豪。", "一川發于岷，一川分於洮。", "一川啟母來，其名爲江沱。", "洮江得三陳，經綸參夔皋。", "協心裨興運，廟社遺勳勞。", "岷江得兩蘇，議論丘與軻。", "只今元祐碑，輝華萬丈高。", "沱江當其中，瀰漫而委佗。", "中興得五楊，其三真英髦。", "綿州號魁磊，射策登巍科。", "嘉謨洊入告，旋進旋蹉跎。", "南部最逸才，氣欲星斗摩。", "遺墨數千言，往往皆離騷。", "惜哉天下士，中道迷山阿。", "三丈寬宇量，中立而不它。", "事業照錦屏，文章爛岷峨。", "縮手不近前，三年淹禮曹。", "翻然念鄉舍，屢乞分旌旄。", "天子勉從之，出鎮姑養痾。", "荆南古都會，十萬雄干戈。", "閉閣閲詩書，人物如春和。", "襄陽控敵衝，鐵騎連兩河。", "撫之以仁義，敵人不敢過。"]'),
('41cdc577-b46c-46d5-b0f7-8f1ccf907c30','壽章漕','度正','宋','宋诗','song-poetry','','[]','蒼蒼閩山高，悠悠閩水清。',288,'全唐诗/poet.song.183000.json','["蒼蒼閩山高，悠悠閩水清。", "厥初萃瑰琦，而世生豪英。", "恭惟皇慶曆，當天開文明。", "風雲千載會，羅列皆名卿。", "當時郇國公，致身爲阿衡。", "勳德著廟社，雲仍爛瑶瓊。", "迨茲中興來，接武扶炎精。", "先烈益以震，煌煌照天京。", "藍田得佳種，歷世勤鋤耕。", "荏苒歲月久，斗杓符南撐。", "得此希代寶，異奏如䪫韺。", "堂堂粹德容，度量何恢宏。", "俾之典風憲，官邪當震驚。", "俾之職獻納，國論當丕平。", "俾之領樞柄，邊疆當不兵。", "俾之坐廟堂，帝業當盈成。", "翻懷千里綬，尺澤揚修名。", "皇慈有遠聽，褒章畀一旌。", "驅車振末俗，雅意先文盟。", "賤子偶在泮，錫朋賦莪菁。", "佳節慶親逢，黄流酌金觥。", "願公接皋夔，願公齊喬彭。", "百年起世德，一旦收家聲。", "從容趨玉陛，懷哉一儒生。"]'),
('e34172d1-e326-4c02-b082-d71eb93b786b','賦張袁州隠齋三首  其一','度正','宋','宋诗','song-poetry','','[]','齊王非愛牛，厲人非愛子。',84,'全唐诗/poet.song.183000.json','["齊王非愛牛，厲人非愛子。", "秉彜未殄滅，生意不可已。", "儻能克其端，萬物均一體。", "胡爲隔形骸，强自分彼此。", "達人有大觀，俯仰盡天理。", "從渠美與惡，不與我慍喜。", "敬問何以然，請先事克己。"]'),
('0dad6e7e-12b3-4245-a852-2b1f596f13a8','賦張袁州隠齋三首  其二','度正','宋','宋诗','song-poetry','','[]','少時見敲搒，濈濈背欲汗。',84,'全唐诗/poet.song.183000.json','["少時見敲搒，濈濈背欲汗。", "及壯事州縣，稍稍覺不憚。", "由來祇一心，今昔非異見。", "君子遠庖厨，夫豈惡芻豢。", "長恐惡念熟，此道出無間。", "是隠乃在我，扁榜安用辦。", "君侯退歸來，此意却無限。"]'),
('75438cb6-41e0-47c2-a7b6-4f268b43bb5c','賦張袁州隠齋三首  其三','度正','宋','宋诗','song-poetry','','[]','殺麑無戚容，活蟻有德色。',84,'全唐诗/poet.song.183000.json','["殺麑無戚容，活蟻有德色。", "不如未見蟻，生道猶不息。", "心如隔窗月，光不見微隙。", "不患無發時，却患發無益。", "一矜障萬善，千悔無一得。", "要加持養功，跬步見天則。", "宇宙渺無窮，此道足充塞。"]'),
('36db438a-d5e0-479f-a783-15d3bae7c36a','八月中澣同官會于塵外亭分韵得煙字','度正','宋','宋诗','song-poetry','','[]','放步超闤闠，濯纓俯漪漣。',288,'全唐诗/poet.song.183000.json','["放步超闤闠，濯纓俯漪漣。", "清風來徐徐，玉宇明娟娟。", "平疇卷黄雲，遠浦凝寒煙。", "橫空六六峰，一一來當筵。", "秋光助顔色，相對如高賢。", "三峩眇遐思，彷彿窺其顛。", "悠悠城南道，鬰鬰惠陵阡。", "懷哉千載人，喬木今參天。", "回頭子雲宅，池塘亦依然。", "奈何傍人門，不幾喪我玄。", "沿河西復西，草草屋數椽。", "唐儒杜先生，向來此周旋。", "食我西山英，飲我西澗泉。", "吐出五色絲，無愧三百篇。", "遂令浣溪上，草木皆光鮮。", "我欲於其間，結茅近英躔。", "尚論古之人，永謝區中緣。", "鷦鷯翔蓬蒿，庶幾避鷹鸇。", "但欲一區宅，不用二頃田。", "念昔懷此心，只今已十年。", "平生百事拙，爲計亦可憐。", "家有萬卷書，而囊無一錢。", "登臨每悵望，興味徒拳拳。", "珍重金石交，議論相磨研。"]'),
('671dfd07-d68e-4450-93b0-5392c33c47eb','步自玉局會飲于判院塗丈廨舍正得日字','度正','宋','宋诗','song-poetry','','[]','肩輿訪藥市，散步困兩膝。',288,'全唐诗/poet.song.183000.json','["肩輿訪藥市，散步困兩膝。", "行行初及門，品第已不一。", "細閲廊宇下，紛然莫窮詰。", "席地堆雄附，連盤佇參朮。", "雲乳色晶熒，沈檀氣芬苾。", "溪毛極草莽，水族包蟲蛭。", "貴者如丹砂，賤者如乾漆。", "苦者如膽礬，甘者如石蜜。", "陳者如酺醢，新者如棗栗。", "來爲中國用，往往四夷出。", "海賈冒風濤，蠻商經崒嵂。", "厚利誘其前，顛沛不遑恤。", "小亦挾千鐶，多至金百鎰。", "開張自寅卯，收拾過酉戌。", "富豪盛僮奴，羸老携兒姪。", "車馬浩駢填，坌然皆迸溢。", "晚飲各酩酊，歸裝滿箱帙。", "人生天地間，稟賦陰陽質。", "寒溫儻乖誤，未免生衆疾。", "至人窮物性，扶世方開術。", "春冬別根苗，南北辨枳橘。", "形色與氣味，審訂皆具述。", "庸夫肆胸腑，妄以甲代乙。", "聵聵莫知誡，十療宜十失。"]'),
('a1d5a165-931f-4751-918e-6c4b68237ddc','食筍','度正','宋','宋诗','song-poetry','','[]','早筍自香美，欲食不得嘗。',96,'全唐诗/poet.song.183000.json','["早筍自香美，欲食不得嘗。", "晚筍已惡臭，頓頓充庖漿。", "蔬食苦不繼，且復幾其良。", "陋巷有佳人，簞瓢不充腸。", "其人久已死，至今有耿光。", "所以天下士，貧者惟其常。", "得失固了然，是非何較量。", "大烹幸列鼎，嗟爾其勉强。"]'),
('bb38efa4-9939-42a4-a5c0-9d4861711ec7','籠雞','度正','宋','宋诗','song-poetry','','[]','籠中畜一雞，飲啄頗云足。',48,'全唐诗/poet.song.183000.json','["籠中畜一雞，飲啄頗云足。", "其雞渾不顧，引頸欲逃出。", "旁雞大愛之，貪食籠中食。", "回旋欲歸籠，不省籠拘束。"]'),
('e7fe41ea-a802-4401-ac7c-5bdb72d67fe9','貫之學士寵示佳作欻然有丘壑之思因反其意以招之亦朋友相勉之義伏幸采矚','度正','宋','宋诗','song-poetry','','[]','夫君隆隆如長車，方途萬里無塵沙。',144,'全唐诗/poet.song.183000.json','["夫君隆隆如長車，方途萬里無塵沙。", "天公生材要有用，安得嘿嘿吟窗紗。", "辛勤學問求大指，求不在他心而已。", "解將歲月作工夫，定使枯株發春媚。", "我家傳家詩與書，家徒四壁一錢無。", "年來行李環天下，直從南海薰香爐。", "先生曰來子可語，以手手地傳心圖。", "歸來日日鋤其惡，陶然一室皆真樂。", "他年努力回羲皇，更把天心驗圭角。"]'),
('268c7757-c4b3-456e-a2c8-5a5d4b05f3a1','今春大震電雨雹南峰無之黄夢得詩來有天意因以旌遺逸之句正恐其輕忽災異失聖人迅雷風烈必變之意用其韵以解之','度正','宋','宋诗','song-poetry','','[]','仲春戊申日之夕，牛羊下來猶未畢。',144,'全唐诗/poet.song.183000.json','["仲春戊申日之夕，牛羊下來猶未畢。", "迴風烈烈漲黄壤，陰雲衝衝蒙白日。", "騰光初覺火燒空，打屋乍疑天隕石。", "出門愁見荒山徑，高卧徒驚墮四壁。", "嘗聞正直天所祐，又聞豪橫天所疾。", "盲風怪雨豈徒然，顛倒橫縱未遑卹。", "老農慘怛心欲死，羣蛙號呼興自逸。", "那知殺菽困黔首，但指嘉禾歌赤舄。", "何人漫讀周官書，更笑深山間小艗。"]'),
('22b0c061-4240-43f2-981a-02e660f57be6','廖良譽棹小舟載酒追別至故縣而還','度正','宋','宋诗','song-poetry','','[]','馬鳴溪上想英概，牛口莊頭訪故廬。',64,'全唐诗/poet.song.183000.json','["馬鳴溪上想英概，牛口莊頭訪故廬。", "登場羅列萬石廩，插架縱橫千卷書。", "有懷西山古鳳鳥，更看北壑今鯤魚。", "江水江花兩無盡，後之來者應何如。"]'),
('09672b7c-fab8-414b-88fb-3114151a9908','送後溪先生龍門賦別','度正','宋','宋诗','song-poetry','','[]','皇帝龍飛慶元元，盡收耆舊爲羽翰。',344,'全唐诗/poet.song.183000.json','["皇帝龍飛慶元元，盡收耆舊爲羽翰。", "誰生黨論中譁諠，一旦剪落堪悲酸。", "謂曲爲直忠爲姦，謂麟爲虎鴟爲鸞。", "朱劉章陳坐譏彈，彭呂繼之何摧殘。", "自從阿衡扃九原，至今草木猶銜冤。", "餘波滔天如驚湍，一落其中無全安。", "五年天子御金鑾，恭己南面朝衣冠。", "有一新進當諫垣，前言劉某入祠官，乞加竄逐風朝端。", "天子曰噫子甘盤，鬚髮雪白心甚丹。", "徙居房陵聖恩寬，公心怡然無怨顔。", "秋風蕭蕭零露漙，浮雲散開雨脚乾。", "公今度棧車北轅，有客越境追征鞍。", "天之降材良獨難，達則致君窮立言。", "曩時夫子投杏壇，刪詩定書傳淵騫。", "春秋一字誅黄泉，萬世賊亂心膽寒。", "子輿賦歸辭惠宣，仁義七篇皆肺肝。", "伏羲六畫義深玄，文王明之當憂患。", "降周迄孔世莫傳，東溪先生抽關鍵。", "發揮絕學窮根源，惜哉遺藁今未完。", "先生亂思真奇觀，庶幾後生窺成編。", "君王舊學非終捐，願言珍重勤加餐。"]'),
('b40f670b-f90d-404f-ac23-c40b3092b9c0','送張義立制幹赴闕探韵得東字','度正','宋','宋诗','song-poetry','','[]','皇家科目周家同，三歲大比羅英雄。',208,'全唐诗/poet.song.183000.json','["皇家科目周家同，三歲大比羅英雄。", "六龍渡江念幽遠，賜之貢額令選充。", "載戢干戈講經藝，詩書比屋陶儒風。", "堂堂衛公千人傑，振鬣長鳴萬馬空。", "一時諸老皆斂避，束带廊廟熙羣工。", "地靈育秀殊未已，有偉男子如衛公。", "龍門逸步已突兀，鳳穴神彩尤昭融。", "襟懷洒落志慷慨，風格俊爽材疏通。", "源泉混混回倒海，力量恢恢扶頹嵩。", "幾年名震動旒冕，一日詔下來旌弓。", "天之降材要有用，士之用世良無窮。", "蕭曹事業皆土苴，堯舜規摹宜磨礲。", "支持大厦要梁棟，努力自愛毋匆匆。"]'),
('07bfca4a-0e9d-440a-9083-9b862d999052','送唐宗道制幹赴闕探韵得書字','度正','宋','宋诗','song-poetry','','[]','妙年璧水充豐儲，一日變化拖長裾。',256,'全唐诗/poet.song.183000.json','["妙年璧水充豐儲，一日變化拖長裾。", "五色神彩丹鳳好，一襟和氣春風如。", "東薄扶桑畧牛斗，西遊陸海環坤輿。", "詔書奕奕九天下，雲程冥冥一步初。", "吾君選士作舟楫，豈特文館讎詩書。", "曩時黨論既喧鬨，往往儒學遭驅除。", "鄙哉小夫自貽戚，因循封植成癰疽。", "祖宗在天實啟祐，忽然潰決今無餘。", "雖然四體已清泰，無奈元氣猶空虛。", "調和脈絡勿草草，整頓罅漏當徐徐。", "咨詢芻蕘下謗木，收召耈老來安車。", "堂堂國勢儻前定，蠢蠢强敵誰侮予。", "明時得意好展盡，書生長慮元非疎。", "毋爲袖手事緘嘿，願以正論開宸居。", "豈惟民畝望芘頼，亦有草澤思吹噓。", "江頭送客重感慨，勉之行矣毋躊躇。"]'),
('b616bc3e-2ad9-4a82-a47e-526fbd6a9881','送李君亮安撫赴闕','度正','宋','宋诗','song-poetry','','[]','皇帝龍飛十四載，拱手垂衣功不宰。',336,'全唐诗/poet.song.183000.json','["皇帝龍飛十四載，拱手垂衣功不宰。", "誰生厲階起甲胄，天下岌岌幾於殆。", "赫然烹阿封即墨，神機獨斷定四海。", "內酬勳庸清列位，外召諸老仍博采。", "自古聖人聞至治，不貴無過貴能改。", "三池先生已先入，諫閣經幃行遂拜。", "遂寧先生又繼起，老手便當調鼎鼐。", "冬官侍郎何遲遲，幾日涪江下寒瀨。", "恭聞促詔已屢下，雲漢昭回九天外。", "吾君寤寐在良弼，其意豈不望啟乃。", "往年袖手固其理，今日緘口庸何待。", "祖宗至仁育疎戚，常使無權免驕泰。", "宣仁聖烈重貶損，功參堯舜光萬代。", "當時若不甚快意，其奈無憂近葅醢。", "前乎六一論堯佐，後日了翁陳二蔡。", "一從一違事已判，得失了然爲世戒。", "況今政事歸中書，國體堂堂方正大。", "春宮仁孝且英睿，多士盈庭復藹藹。", "先生而言言易入，及其事至恐不逮。", "姑置區區論商鑒，覆轍不遠那容再。", "行看正道動前席，盛時難逢願自愛。"]'),
('d22a4866-e1cc-4190-9e5d-326a167f52eb','送茶使趙伯川赴闕','度正','宋','宋诗','song-poetry','','[]','三王垂世何煌煌，詩書所稱周尤長。',272,'全唐诗/poet.song.183000.json','["三王垂世何煌煌，詩書所稱周尤長。", "雖云積累日源遠，其實本支由宗彊。", "內環旦奭扶九陸，外列毛原鎮四方。", "宣王中興恢大業，復有虎臣如鷹揚。", "卜年過曆前未有，邈哉夏商矧漢唐。", "皇家揖遜古舜禹，建宗作屏周成康。", "巍乎神廟有遺訓，作而新之進厥良。", "振振信厚皆麟趾，翽翽羽儀多鳳凰。", "扶持天日豈易事，往歲一段尤輝光。", "無何讒口亂白黑，至欲疎遠空藩牆。", "天相宗社迄感悟，重惟孤立當懲創。", "有偉丈夫在遠外，是嘗拒賊賊莫傷。", "淵洪胸次自磊磊，慷慨顔貌真堂堂。", "吾君想象日已久，急下詔書來取將。", "旁招俊乂第一義，理亂之機戒履霜。", "名世之卿夫豈少，貴戚之卿人所望。", "有懷器業得施用，感激爲賦維城章。"]'),
('a3873593-ea75-4afd-9323-79214ed7f06f','和黄侍郎韵','度正','宋','宋诗','song-poetry','','[]','君不見君家涪翁居戎州，只爲山月來登樓。',198,'全唐诗/poet.song.183000.json','["君不見君家涪翁居戎州，只爲山月來登樓。", "又不見君家繡衣老使君，傳家文物如卿雲。", "兩仙仙去今百載，雲冠霞佩儼如在。", "數行妙墨留壁間，九頂三峩屹相對。", "竹坡先生駐歸步，來拜翁祠還少佇。", "水光山色爲改容，收拾奇觀入新著。", "世間好景苦留人，無奈催歸作霖雨。", "山谷先生心好客，爲愛橫空雪山白。", "慇懃載酒清音亭，一抹雲間真絕色。", "鴻飛天際去冥冥，風入松間聽琴瑟。", "浮雲聚散兩茫茫，大川東注何終極。", "茲遊應不減風雩，清和正值春三月。"]'),
('e7d5baa6-a3c2-4276-81f5-2dd4b6f2d49c','壽制置吳侍郎','度正','宋','宋诗','song-poetry','','["\u8861\u5c71"]','洙泗之根枯無芽，千五百年復生花。',384,'全唐诗/poet.song.183000.json','["洙泗之根枯無芽，千五百年復生花。", "章通句解到聖處，格高調古意易差。", "南嶽一登光萬丈，下照百物窮幽遐。", "天公欲振斯文緒，卓爾大雅生長沙。", "淡如清廟有遺味，粹如白璧無纖瑕。", "周旋禮樂今冠冕，彈壓妖怪古鏌鋣。", "翺翔祕館育儀羽，岌嶪殿中峩觸邪。", "忽驚雲霧蔽日月，一落湖海潜煙霞。", "浮言既空望逾遠，欻起仍乘使者車。", "急祗臨遣護襄漢，旋奉溫詔來三巴。", "春風所及自和氣，坐令四境還桑麻。", "五月渡瀘臣敢憚，晝日三接恩意加。", "皇心念爾蜀父老，因以與爾毋咨嗟。", "但見田畝興孝悌，已無稂莠勞梳爬。", "洋洋韶頀出正始，一洗下俚之淫哇。", "夤緣末學被羅致，得以文藝陪絳紗。", "作興詩書盛樂育，謂之文翁寧非耶。", "蜀人德公盛於衛，思厚報之吟木瓜。", "二陽寖長今初度，門無雜賓賓則嘉。", "欲酌北斗薦眉壽，聽我祝辭人無譁。", "先生直上作舟楫，領袖夔契承勛華。", "心回元化位天地，手挈魁柄扶邦家。", "工師作室貴兼用，施置寧遺負與叉。", "自憐愚魯無所似，獨於詩書涉津涯。"]'),
('39b81ae3-0b4d-4ce1-9dc6-984a34767aed','壽黄侍郎','度正','宋','宋诗','song-poetry','','[]','玉井之泉其源深，淵涵停蓄包千尋。',240,'全唐诗/poet.song.183000.json','["玉井之泉其源深，淵涵停蓄包千尋。", "風行於上渺河漢，諸子淺陋其蹄涔。", "茫無畔岸容鼉鼈，富有磊落潛球琳。", "大原自出號學海，餘波散及蕃儒林。", "有如霽月當空照，羅列萬象中森森。", "恭惟王明可用汲，一勺沃我思賢心。", "推之四海澤焦槁，元戎十乘來駸駸。", "銅梁玉壘日澄浄，夜氣晨光煥井參。", "區區賤子愚且魯，非曰能之學鼓琴。", "慇懃三弄衆掩耳，莞然一笑遭知音。", "推琴而作喜欲舞，慨我得此踰兼金。", "上方穆穆回元化，捨爾其誰扶當今。", "傳聞丹詔九霄下，衮舄未至虛宸襟。", "請書國紀開皇極，雍容調燮陽與陰。", "願公自愛毋久外，天下蒼生思作霖。"]'),
('4b046f4a-9df8-4250-bd97-c04569379edb','壽寺丞唐丈','度正','宋','宋诗','song-poetry','','[]','維時皇輿駐吳門，三光五嶽之氣元未分。',308,'全唐诗/poet.song.183000.json','["維時皇輿駐吳門，三光五嶽之氣元未分。", "鍾而爲木爲杞梓，結而爲玉爲瑶琨。", "先生獨得之，表裏何粹溫。", "淵然之學妙今古，浩然之氣充乾坤。", "探月窟，躡天根，朝蟠木，夕崑崙。", "超軼絕塵有如此，餘子瞠若誰追奔。", "紛紛何所知，駭歎空云云。", "君不見蔡家太師倡紹述，當時流毒并雞豚。", "魯國抱其學，屹如中岳尊。", "又不見秦家太師握和議，羣邪噏噏迷天倫。", "紫微於是時，橫身扶正論。", "天公下監世忠義，畀以斯道昌其孫。", "胡不遊東觀，胡不遊西崑。", "胡爲尚婆娑，萬里乘朱轓。", "依然不磷緇，炯炯超塵昏。", "昔堯登彭叟，歷佐周與殷。", "後來磻溪翁，辛勤晚策勳。", "况茲才之難，典刑諒誰存。", "玉律回孟陬，瑞氣如雲屯。", "請賦嵩高篇，萬口同一言。", "願公上玉堂，願公登金門。", "功成名遂歸鄉枌，賤子年年開金罇。"]'),
('915904b9-f14f-47b6-a968-1fce847dba8e','壽外舅富順趙使君','度正','宋','宋诗','song-poetry','','[]','天家積慶如江河，千枝萬葉魯衛毛。',338,'全唐诗/poet.song.183000.json','["天家積慶如江河，千枝萬葉魯衛毛。", "聲名赫赫照今古，骨相飄飄多俊髦。", "惟安懿王邁種德，當時廟社遺勳勞。", "本支百世端未艾，綿綿瓜瓞更崇高。", "只今中興得旦奭，夾輔日月參夔皋。", "自餘材德踵相望，磊落抱負皆英豪。", "或持皮帛登臺省，或奉符竹分旌旄。", "金川丈人最後出，平生力學勤持操。", "高談奧論不可到，一灑萬字無停毫。", "聊將圭撮試當世，已被天語加崇褒。", "從此公道更開泰，未必奔走懸三刀。", "念昔南宮陪俊翮，偶附驥尾辭蓬蒿。", "因蒙顧盼被收錄，得拜門下恩則叨。", "自憐薄命薄如葉，十年再爾吟離騷。", "世間情態已百轉，每歎慈愛終堅牢。", "今逢佳節揆初度，欲薦眉壽酬甄陶。", "丈人丈人聽我語，我語憔悴空啾嘈。", "白圭三復古亦少，緇衣改爲今可遭。", "人言愷悌必富貴，愷悌富貴何由逃。", "不願歸來一尊酒，但願努力登三鼇。", "我欲執鞭追壺中之日月，薦海上之蟠桃。"]'),
('2ff6450b-3119-44fb-a083-1e355c4bc515','壽憲使大卿','度正','宋','宋诗','song-poetry','','[]','自昔天之生大賢，其間往往幾千年。',288,'全唐诗/poet.song.183000.json','["自昔天之生大賢，其間往往幾千年。", "前日顔曾乃並世，後來孫樂還齊肩。", "參稽疏數未一概，廢興大抵關諸天。", "恭惟皇家受眷命，五星集奎光芒懸。", "復振斯文自洙泗，渙然遺響聞伊瀍。", "微言奧論揭日月，九州四海俱流傳。", "浩齋先生本自得，聞風特起吾東川。", "當時造入自孟子，善養其氣氣浩然。", "配合道義期充足，至大而剛直以全。", "後來豈不有繼者，要之聞道先生先。", "今夕何夕天氣好，虞琴初奏南薰絃。", "正陽之月月幾望，於時蓋得乾之乾。", "宜其秀質溫如玉，不磷不緇白且堅。", "吾君好學古未有，直上便可升經筵。", "力闢淫邪開正道，雍容堯舜陳王前。", "仰視蒼蒼豈無意，如此大器堪扶顛。", "諸生載酒來薦壽，山肴野蔌徒拳拳。", "躋彼公堂喜拜舞，正也請賦嵩高篇。"]'),
('d3cb78b9-4a0c-405e-97cd-14042797ddb0','壽黄運使','度正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','南海之中三神山，高出天宇超人寰。',234,'全唐诗/poet.song.183000.json','["南海之中三神山，高出天宇超人寰。", "上有神仙百萬宅，瓊欄瑶楯相回還。", "四方鱗鱗中傑觀，不知誰氏當中間。", "或云黄帝之後已百世，雲仍詵詵褒衣博带千官班。", "向來山澤癯，晦伏潛深灣。", "是家老仙伯，下顧目所瞷。", "中夜舞鸞鳳，明朝排天關。", "自從放出一頭地，長江大河聲潺湲。", "東皇回蹕鼓萬象，和氣襲人春初頒。", "雲裾霞珮來何所，巍峩步趨貌則閑。", "生香馥郁浮四座，得未曾有天非慳。", "至人之子飫芳味，欲揭北斗高莫攀。", "丹霄爭看來驛騎，衮衣直上承天顔。", "上論唐虞開稷契，下及草野兼庸孱。", "嗣德之繼發餘響，未必政爾詩書刪。"]'),
('7e65e0f1-5ee6-4606-ad8f-03d412e58352','謁新漢州范文叔  其一','度正','宋','宋诗','song-poetry','','[]','歎息中興後，斯文一髮如。',48,'全唐诗/poet.song.183000.json','["歎息中興後，斯文一髮如。", "廢興天有命，用捨道何疎。", "太史遺風在，南翁絕學餘。", "君王欲堯舜，安得賦歸歟。"]'),
('fb9a4b35-2db3-42b8-a763-f7b501af3803','謁新漢州范文叔  其二','度正','宋','宋诗','song-poetry','','[]','來紆廣漢紱，却近子雲居。',48,'全唐诗/poet.song.183000.json','["來紆廣漢紱，却近子雲居。", "風月誰同會，林泉樂有餘。", "卑詞老中允，分宅卜橫渠。", "後來端有望，吾道竟何如。"]'),
('fecae508-6338-4ec0-ae9a-ef2a4ac1f9e1','謁新漢州范文叔  其三','度正','宋','宋诗','song-poetry','','[]','巴岳東峰下，舂陵別駕蹤。',48,'全唐诗/poet.song.183000.json','["巴岳東峰下，舂陵別駕蹤。", "陳編新德業，陋質古心胸。", "雅得千秋契，那知並世逢。", "樂哉開後覺，乞我一中庸。"]'),
('77c9fbba-3c4c-4678-982a-d66da38af9a6','送別羅堅文  其一','度正','宋','宋诗','song-poetry','','[]','共席勝冠日，分頭既壯年。',48,'全唐诗/poet.song.183000.json','["共席勝冠日，分頭既壯年。", "許身要到聖，論德未能賢。", "歲月於何駐，工夫在力肩。", "有言堪記憶，隨處是耕佃。"]'),
('d5111aa5-6240-44d0-87c0-9e62ae94f4f4','送別羅堅文  其二','度正','宋','宋诗','song-poetry','','[]','重違直諒友，失入斗筲羣。',48,'全唐诗/poet.song.183000.json','["重違直諒友，失入斗筲羣。", "眇眇初晴日，濛濛欲暮雲。", "已荒三徑菊，無奈萬家薰。", "莫厭山中惡，山中妙莫云。"]'),
('c83e9dbc-8ed8-4797-b88a-9db90cac9d71','奉輓近故制置侍郎畏齋先生吳公  其一','度正','宋','宋诗','song-poetry','','[]','人物雄三楚，師傳自五峰。',48,'全唐诗/poet.song.183000.json','["人物雄三楚，師傳自五峰。", "求仁居廣大，學道到從容。", "世仰堂堂表，天知磊磊胸。", "斯文真不幸，海內失儒宗。"]'),
('76f04365-1c4e-4f8c-bbc7-977440cb65d0','奉輓近故制置侍郎畏齋先生吳公  其二','度正','宋','宋诗','song-poetry','','[]','訃音來嶽麓，天下想遺忠。',48,'全唐诗/poet.song.183000.json','["訃音來嶽麓，天下想遺忠。", "金匱嘉言在，清朝雅望空。", "漢庭悲賈傅，蜀學祀文翁。", "沒世名逾盛，方知此道公。"]'),
('91ff2d6b-63f8-471f-b8ac-c499a4910054','奉輓近故制置侍郎畏齋先生吳公  其三','度正','宋','宋诗','song-poetry','','[]','當年王事急，盛夏歎馳驅。',48,'全唐诗/poet.song.183000.json','["當年王事急，盛夏歎馳驅。", "振鐸宣皇化，登車禮碩儒。", "薛公推一范，張老得三蘇。", "擾擾成何事，千年美意俱。"]'),
('dc37bd10-3e6e-4371-8186-dcff71b513a3','奉輓近故安撫侍郎龍學劉公  其一','度正','宋','宋诗','song-poetry','','[]','有開元祐相，世世出英才。',48,'全唐诗/poet.song.183000.json','["有開元祐相，世世出英才。", "堅正由天得，高明自學來。", "清忠通聖鑑，雅望應公台。", "渭上明星落，山山草木哀。"]'),
('d9449669-b6e3-4aa3-8368-b21973de668a','奉輓近故安撫侍郎龍學劉公  其二','度正','宋','宋诗','song-poetry','','[]','學術原三代，文章自兩京。',48,'全唐诗/poet.song.183000.json','["學術原三代，文章自兩京。", "公朝推宿德，近世號名卿。", "楚俗思羊祜，陳人泣孔明。", "平生知己淚，今日爲公傾。"]'),
('2bf7512c-b63a-482d-a2ff-bb3aea4c33f3','輓劉大監思恭  其一','度正','宋','宋诗','song-poetry','','[]','簪紱源流遠，詩書氣味香。',48,'全唐诗/poet.song.183000.json','["簪紱源流遠，詩書氣味香。", "啼鶑翔澗谷，鳴鳳瑞朝陽。", "壯志欣辰告，羸軀痛夕亡。", "萬夫今失望，擬欲問蒼蒼。"]'),
('22683032-caa6-4928-b0c0-cf7525d41427','輓劉大監思恭  其二','度正','宋','宋诗','song-poetry','','[]','一門金玉友，仲也更高明。',48,'全唐诗/poet.song.183000.json','["一門金玉友，仲也更高明。", "天粹仁幾熟，心融義亦精。", "有懷殊未究，所論畧施行。", "握手悲無日，臨風涕泗橫。"]'),
('71311f24-2b70-4531-87c7-539f8fa0a7d7','奉輓友三舅知縣還山  其一','度正','宋','宋诗','song-poetry','','[]','衣冠推甲族，詩禮自深長。',48,'全唐诗/poet.song.183000.json','["衣冠推甲族，詩禮自深長。", "雅意如諸謝，名章似晚唐。", "亂流浮小艇，繞屋種脩篁。", "胸次渾如許，行藏已兩忘。"]'),
('3764b356-e13f-4289-9538-f7c61ff89cbc','奉輓友三舅知縣還山  其二','度正','宋','宋诗','song-poetry','','[]','晚來爲令尹，此意亦云聊。',48,'全唐诗/poet.song.183000.json','["晚來爲令尹，此意亦云聊。", "舉箑清風滿，彈琴白日消。", "精神元未瘁，魂魄竟難招。", "回首梅溪路，傷心過畫橋。"]'),
('a3332419-aded-46a7-b295-f15a27495504','送輓監簿游子正詩  其一','度正','宋','宋诗','song-poetry','','[]','早年馳偉譽，晚歲奮奇才。',48,'全唐诗/poet.song.183000.json','["早年馳偉譽，晚歲奮奇才。", "奔走千官冗，經綸萬慮開。", "忠謀扶日上，切諫挽天回。", "大厦方如許，云何柱石摧。"]'),
('e1047205-b35f-4a01-a3cc-0361d4d5724b','送輓監簿游子正詩  其二','度正','宋','宋诗','song-poetry','','[]','捐軀陳大義，協力濟多艱。',48,'全唐诗/poet.song.183000.json','["捐軀陳大義，協力濟多艱。", "賢相尋遷死，明公亦放還。", "俄聞姦黨敗，僅見聖恩頒。", "已矣埋黄壤，傷哉涕淚潸。"]'),
('06dfb50a-7ce5-48dc-9c60-13cb5ee64ac2','哀射洪陳隠居','度正','宋','宋诗','song-poetry','','[]','憶昔牝晨日，孤忠貫日星。',48,'全唐诗/poet.song.183000.json','["憶昔牝晨日，孤忠貫日星。", "川流平處靜，山色本來青。", "浩浩何終極，嗟嗟尚典型。", "我思人不見，極目涕雙零。"]'),
('9baae158-cd1e-4665-91e8-2079f6481197','哀通泉李僉判','度正','宋','宋诗','song-poetry','','[]','豐基根也厚，枝葉固其龐。',48,'全唐诗/poet.song.183000.json','["豐基根也厚，枝葉固其龐。", "地域雲夢九，天街石笋雙。", "圭璋沉下國，桃李爛他邦。", "寂寞涪江上，聞風意已降。"]'),
('da19c53b-6890-4bab-b817-19767a0bde98','哀金堂張通判','度正','宋','宋诗','song-poetry','','[]','豫章驚早世，修節凜風林。',48,'全唐诗/poet.song.183000.json','["豫章驚早世，修節凜風林。", "松柏山中友，江湖物外心。", "茂陵多異賦，梁甫又悲吟。", "琢句藏深谷，他年尚德音。"]'),
('72c876aa-6d20-4fdc-b5f9-e0b27e05a49d','徐夫人輓章','度正','宋','宋诗','song-poetry','','[]','芬芳蘭蕙畹，籩豆有司存。',48,'全唐诗/poet.song.183000.json','["芬芳蘭蕙畹，籩豆有司存。", "抱燭丹心苦，深居德性尊。", "庭前桑有附，戶外竹生孫。", "遺範章章古，新詩詔後昆。"]'),
('74a085eb-3dcb-478d-b325-d94658771525','奉輓近故太夫人史氏二首  其一','度正','宋','宋诗','song-poetry','','[]','佩服詩書訓，周旋禮義中。',48,'全唐诗/poet.song.183000.json','["佩服詩書訓，周旋禮義中。", "春風三月永，淑氣四時融。", "當戶能安節，傳家務教忠。", "真成滂也母，百世仰高風。"]'),
('009e256c-a4c6-415d-86e1-07b339392cd2','奉輓近故太夫人史氏二首  其二','度正','宋','宋诗','song-poetry','','[]','有子來爲牧，孜孜奉母慈。',48,'全唐诗/poet.song.183000.json','["有子來爲牧，孜孜奉母慈。", "涵濡千里潤，雍睦一家推。", "壽考國人願，循良聖主知。", "詔書催令伯，歎息想遺規。"]'),
('86b9a79a-c5c0-4b51-a64d-1143013f38c2','金堂涂恭甫奉其母夫人謝氏還山爲賦輓詩一章以送之','度正','宋','宋诗','song-poetry','','[]','族姓源江左，來歸禹外家。',48,'全唐诗/poet.song.183000.json','["族姓源江左，來歸禹外家。", "懿文吟柳絮，淑質詠桃華。", "蘭室雙芽秀，萱堂隻影斜。", "他年修郡志，遺範照三巴。"]'),
('64817570-ea9b-46b8-85ff-f9a00111ecd2','殿中覆考進士','度正','宋','宋诗','song-poetry','','[]','宮漏傳籌趨絳幘，御盤行炙出黄金。',64,'全唐诗/poet.song.183000.json','["宮漏傳籌趨絳幘，御盤行炙出黄金。", "春餘花氣香寧重，雨足林光綠更深。", "通籍不須羞暮齒，好文何幸獲初心。", "東風似借魚龍便，一夜奔雷數振音。"]'),
('e20b123e-45d5-4eff-91bc-9a49b5ecd6f3','燕漕司進士小詩奉勉','度正','宋','宋诗','song-poetry','','[]','奮迹山林志甚疎，濫當春棘品賢書。',64,'全唐诗/poet.song.183000.json','["奮迹山林志甚疎，濫當春棘品賢書。", "學開鄒魯人無異，文到卿雲士有餘。", "力戰吝驕存廣大，深培根本黜浮虛。", "此中幾許經綸地，萬里先看一步初。"]'),
('436557a8-a332-4095-a1f6-078027b748bf','暢伯圭父子下第歸鄉携嗣由廣文書并手佳章寵貺正舊讀程門遺書知有潛道者列由求之間今見伯圭父子姓名不勝驚喜因問家世出處果潛道近族遂用其韵反其意出鄙語以謝庶幾朋友相與切磋之義也','度正','宋','宋诗','song-poetry','','[]','先正傳家逮泗濱，一言一論本諸身。',64,'全唐诗/poet.song.183000.json','["先正傳家逮泗濱，一言一論本諸身。", "是間極力窺真際，物外何心逐像人。", "蹈履若迷天所賦，奔馳猶誤實之賓。", "都將出處束高閣，明日從容儻細陳。"]'),
('dea3f560-7dff-468c-a691-419071d5735e','去年微之國史讀易徹章夢謁晦翁相與從容話言今年讀周官再用前韵錄以垂教正謹依韵酬謝  其一','度正','宋','宋诗','song-poetry','','[]','伊人寤寐自求之，鑽仰應無咫尺違。',64,'全唐诗/poet.song.183000.json','["伊人寤寐自求之，鑽仰應無咫尺違。", "試看後來身願學，便如當日自歸依。", "及門定許偕行止，下筆何由謬是非。", "好把遺編還指示，也教都識大音希。"]'),
('1f7af932-eee6-4834-a2d3-991ae111150d','去年微之國史讀易徹章夢謁晦翁相與從容話言今年讀周官再用前韵錄以垂教正謹依韵酬謝  其二','度正','宋','宋诗','song-poetry','','[]','禮經遺子略聞之，大法昭然世莫違。',64,'全唐诗/poet.song.183000.json','["禮經遺子略聞之，大法昭然世莫違。", "初學卑卑由禮立，終身懇懇欲仁依。", "芸苗自我持三勿，克己從頭絕四非。", "往教舊盟如可踐，警其懈惰久心希。"]'),
('c3d935d4-ca3b-453b-a06e-c8fc0f6f3a51','臨川吳子達以揲蓍遊成都訪余寺中見堂上晦翁像作而曰向亦嘗得見之且見問蜀之易學子雲以來代有其人近世何如某歎其用意精切拳拳如此因爲出數語以勉之','度正','宋','宋诗','song-poetry','','[]','千古羲皇一片心，何人此地口微吟。',64,'全唐诗/poet.song.183000.json','["千古羲皇一片心，何人此地口微吟。", "鑿開未濟言無幾，說破先幾義極深。", "此事舊傳師友記，斯文今見火珠林。", "成都自昔多真隠，著眼稠人更訪尋。"]'),
('3e74c8c1-b7b3-4108-a6a4-7aecf593ea4b','南平教授勾子甲見訪於益昌自言正在華陽時渠方待試石室屢過縣齋勾重慶人將至蒼溪又訪舟中且以佳篇爲贈次韵謝之二首  其一','度正','宋','宋诗','song-poetry','','[]','頃年應聘漫談經，喜向寒窗訪聚螢。',64,'全唐诗/poet.song.183000.json','["頃年應聘漫談經，喜向寒窗訪聚螢。", "撫字昨慚書下下，佩衿今羨領青青。", "儻來富貴皆塵土，無盡詩書自日星。", "珍重聖賢垂軌範，不尤臧氏不尤邢。"]'),
('03703148-dc87-4984-b12d-4a4d4a677dcd','南平教授勾子甲見訪於益昌自言正在華陽時渠方待試石室屢過縣齋勾重慶人將至蒼溪又訪舟中且以佳篇爲贈次韵謝之二首  其二','度正','宋','宋诗','song-poetry','','[]','漢威西被浹燉煌，已覺邊塵不復揚。',64,'全唐诗/poet.song.183000.json','["漢威西被浹燉煌，已覺邊塵不復揚。", "一別可堪論世事，異鄉聊共舉空觴。", "只愁山月嫌清淡，不怕江梅笑醉狂。", "慣涉風波神不動，流行坎止未須荒。"]'),
('d18db383-f8ca-4719-8dbb-568e7b14dc86','臨邛計次魏自言六世祖破荒先生晚居景陵因葬焉後世子孫歲時不能拜掃日負樵牧不禁之憂慨然欲往携其所藏遺書一卷求書紙尾且云是行并之武昌省運使表兄迤邐觀光上國用正巖字韵賦詩一章以言志正亦用巖字韵爲賦三章以勉之云  其一','度正','宋','宋诗','song-poetry','','[]','如何袖手伏山巖，頃刻猶能草百函。',64,'全唐诗/poet.song.183000.json','["如何袖手伏山巖，頃刻猶能草百函。", "胸次宏規標衆正，筆端勁氣磔羣讒。", "行看雲漢翻鴻羽，更喜秋風送馬銜。", "南國諸公共推轂，從今不復厭卑凡。"]'),
('f68a0cf2-f3d9-44f5-8ffe-83c262bab7ae','臨邛計次魏自言六世祖破荒先生晚居景陵因葬焉後世子孫歲時不能拜掃日負樵牧不禁之憂慨然欲往携其所藏遺書一卷求書紙尾且云是行并之武昌省運使表兄迤邐觀光上國用正巖字韵賦詩一章以言志正亦用巖字韵爲賦三章以勉之云  其二','度正','宋','宋诗','song-poetry','','[]','涵養工夫自野巖，淹該萬卷一空函。',64,'全唐诗/poet.song.183000.json','["涵養工夫自野巖，淹該萬卷一空函。", "何須識者方能識，自是讒人不敢讒。", "騏驥栖栖垂皂櫪，駑駘擾擾被金銜。", "不妨希價咸陽市，未必人人眼目凡。"]'),
('d159e31c-f2b7-41f5-95a1-3d0ce7d323c0','臨邛計次魏自言六世祖破荒先生晚居景陵因葬焉後世子孫歲時不能拜掃日負樵牧不禁之憂慨然欲往携其所藏遺書一卷求書紙尾且云是行并之武昌省運使表兄迤邐觀光上國用正巖字韵賦詩一章以言志正亦用巖字韵爲賦三章以勉之云  其三','度正','宋','宋诗','song-poetry','','[]','不及摳衣拜紫巖，尚能什襲寶書函。',64,'全唐诗/poet.song.183000.json','["不及摳衣拜紫巖，尚能什襲寶書函。", "掃除荆棘扶初日，投畀烟嵐困老讒。", "四海時無伸國論，百年人自仰台銜。", "南軒衣鉢今何似，見說諸孫也不凡。"]'),
('d3d83585-be55-42a1-a4ba-d5c7cd396735','奉謁夔州何異侍郎','度正','宋','宋诗','song-poetry','','[]','浩蕩江南春更和，幾回風月又婆娑。',64,'全唐诗/poet.song.183000.json','["浩蕩江南春更和，幾回風月又婆娑。", "夔門外戶千鈞重，灧澦中流一節高。", "蜀國移花今日事，上林種柳舊年窠。", "殘膏餘馥知何恨，徙倚江皋揖晉波。"]'),
('72711da4-374f-4688-9f48-8c073cf010ed','制置侍郎閣學台座俯從鄉論營求勝地改建貢闈嚴嚴翼翼實稱朝廷所以賓興賢能之意父老觀者莫不稱歎今工已告成命客飲之正獲與焉謹賦詩三章以紀盛事詞鄙意拙亦各言志儻蒙采察曷勝榮幸  其一','度正','宋','宋诗','song-poetry','','[]','中興詔下九重天，分建科場貢蜀賢。',64,'全唐诗/poet.song.183000.json','["中興詔下九重天，分建科場貢蜀賢。", "急就佛宮嫌北面，載開儒館墮西偏。", "得人自昔英才盛，擇地於今氣象全。", "多士深思公雅意，要收鴻碩副詳延。"]'),
('bdcb66b4-7bb9-40c6-a05b-9edfc771d011','制置侍郎閣學台座俯從鄉論營求勝地改建貢闈嚴嚴翼翼實稱朝廷所以賓興賢能之意父老觀者莫不稱歎今工已告成命客飲之正獲與焉謹賦詩三章以紀盛事詞鄙意拙亦各言志儻蒙采察曷勝榮幸  其二','度正','宋','宋诗','song-poetry','','[]','殿角西頭闢禮闈，崢嶸棟宇更巍巍。',64,'全唐诗/poet.song.183000.json','["殿角西頭闢禮闈，崢嶸棟宇更巍巍。", "碧鷄金馬連環繞，雲頂峩眉聳翠圍。", "陳范蘇張應並駕，龍章譙郭亦橫飛。", "東都行復充鄉賦，却望秦關入帝畿。"]'),
('2f1b7bc8-3bda-4519-8484-b4e4dc7c5ffe','制置侍郎閣學台座俯從鄉論營求勝地改建貢闈嚴嚴翼翼實稱朝廷所以賓興賢能之意父老觀者莫不稱歎今工已告成命客飲之正獲與焉謹賦詩三章以紀盛事詞鄙意拙亦各言志儻蒙采察曷勝榮幸  其三','度正','宋','宋诗','song-poetry','','[]','皇家科目釣英豪，手大方能得巨鼇。',64,'全唐诗/poet.song.183000.json','["皇家科目釣英豪，手大方能得巨鼇。", "考論勳庸推虎榜，講求師友自鸞刀。", "泉翁竟被盲夫棄，雲叟空勞聖主褒。", "細看當年權造化，歐公眼目獨清高。"]'),
('ed560d07-d00c-4472-a4c6-c781b0032b0d','上制置侍郎  其一','度正','宋','宋诗','song-poetry','','[]','龍虎西頭象更雄，巍然坐覺馬羣空。',64,'全唐诗/poet.song.183000.json','["龍虎西頭象更雄，巍然坐覺馬羣空。", "三千威已行方外，百萬兵元貯腹中。", "蜀國歡聲連上國，秋風和氣似春風。", "只今欲薦斯文壽，大雅篇中願賦崧。"]'),
('3ae200e7-7093-4aa2-8371-bf2e9221d54b','上制置侍郎  其二','度正','宋','宋诗','song-poetry','','[]','堂堂漢使到天涯，覆芘西南億萬家。',64,'全唐诗/poet.song.183000.json','["堂堂漢使到天涯，覆芘西南億萬家。", "禮樂化行真有道，强梁氣懾自無譁。", "坐觀狼狽奔牛角，敢復猖狂犯虎牙。", "措置得宜歸妙算，更歌豐樂慶中華。"]'),
('2b5488a8-5e87-4df5-bd36-ba76ebe55115','上制置侍郎  其三','度正','宋','宋诗','song-poetry','','[]','武侯落落舊規摹，千載誰能發壯圖。',64,'全唐诗/poet.song.183000.json','["武侯落落舊規摹，千載誰能發壯圖。", "撫定南方無後顧，感通北面自前孚。", "但於號令教心服，自是歡忻聽指呼。", "羣策不遺光竹帛，方知儒術本非迂。"]'),
('4ed29357-2444-4be1-9482-f0813fca5342','上李大參  其一','度正','宋','宋诗','song-poetry','','[]','坐對江山古與稽，熏爐一線入雲霓。',64,'全唐诗/poet.song.183000.json','["坐對江山古與稽，熏爐一線入雲霓。", "聞思草木憂春雨，軫念桑麻病夏畦。", "有美荇蘺泥不滓，無言桃李下成蹊。", "青天瑩徹明如鑑，下照毫釐自不迷。"]'),
('3e0d730e-2066-4ebc-8633-0ed8c5741dce','上李大參  其二','度正','宋','宋诗','song-poetry','','[]','雲間龍鶴隠峰巒，袖手何妨此考槃。',64,'全唐诗/poet.song.183000.json','["雲間龍鶴隠峰巒，袖手何妨此考槃。", "秋老未須愁菊悴，春回寧復訝梅酸。", "風吹鴈字成簪盍，雪壓鷗盟閲歲寒。", "萬卷皇墳誰可續，爲言執事勸加餐。"]'),
('96eb1c3c-eaa5-49b8-8ba6-3d912656d10e','上趙茶馬  其一','度正','宋','宋诗','song-poetry','','[]','仙源奕葉滿皇州，人物於今第一流。',64,'全唐诗/poet.song.183000.json','["仙源奕葉滿皇州，人物於今第一流。", "蹈履詩書宗孔孟，扶持日月繼伊周。", "更觀河滸盤根出，已自風雩向上求。", "異說掃除昌此道，方來勳業掩前修。"]'),
('bb415f6c-2b25-432c-8880-1839b49ef139','上趙茶馬  其二','度正','宋','宋诗','song-poetry','','[]','聖門絕學歎中微，天祐斯文再發揮。',64,'全唐诗/poet.song.183000.json','["聖門絕學歎中微，天祐斯文再發揮。", "宗衮爰升陪國論，黨魁特起贊經闈。", "麒麟復見公朝瑞，虎兕何憂我道非。", "千載明良相慶會，更歌既醉醉無歸。"]'),
('d9d3a394-e4f3-4306-babd-352f8b54d26f','上茶使趙伯川  其一','度正','宋','宋诗','song-poetry','','[]','六陽浩蕩奏薰風，白雨肥梅纂纂紅。',64,'全唐诗/poet.song.183000.json','["六陽浩蕩奏薰風，白雨肥梅纂纂紅。", "學到狼胡心湛湛，性同麟趾步融融。", "已鋤漢戚更王化，行建周宗輔聖聰。", "師友一源端復振，世間從此卜興隆。"]'),
('3c9600f8-bfe4-4f85-8309-abd31e13cff1','上茶使趙伯川  其二','度正','宋','宋诗','song-poetry','','[]','幾年題筆决文圍，妙手元堪補衮衣。',64,'全唐诗/poet.song.183000.json','["幾年題筆决文圍，妙手元堪補衮衣。", "不訐不諛持正大，能經能濟洞幾微。", "天高且作茶星現，地迥行親海月輝。", "萬歲池塘神興逸，總教西子賦東歸。"]'),
('d7f1d112-6ef4-4436-9388-97e0cc0e3632','謁茶使','度正','宋','宋诗','song-poetry','','[]','劍南劍北盡儀型，妙墨題名入畫屏。',64,'全唐诗/poet.song.183000.json','["劍南劍北盡儀型，妙墨題名入畫屏。", "風卷渥洼來汗血，天開井絡得茶星。", "照人一點應神會，回首三年更眼青。", "雲外脩程橫九萬，附渠飛翼上青冥。"]'),
('f5265136-f7ca-4d5e-90d2-8118ba9585ca','謁江州易彥章','度正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','經帷諫閣竟云何，且著蓮花峰下麽。',64,'全唐诗/poet.song.183000.json','["經帷諫閣竟云何，且著蓮花峰下麽。", "書院凄凉安處問，廬山突兀爲誰高。", "依依松柏經年好，泛泛鶑花逐日過。", "萬世清芬懸日月，元來得失一毫毛。"]'),
('b67cd84a-2f49-4343-a90c-b5af4f2c7aa2','呈晏制幹二首  其一','度正','宋','宋诗','song-poetry','','[]','隴西公府俱名勝，元獻曾孫號最賢。',64,'全唐诗/poet.song.183000.json','["隴西公府俱名勝，元獻曾孫號最賢。", "玉陛新題翻墨榜，金門舊事付青氈。", "遠遊行橐詩千首，退食高齋易一編。", "再世起家調鼎鼐，中興榜樣更蟬聯。"]'),
('14d3c7d5-ef81-4290-a4f7-c7715e515f1f','呈晏制幹二首  其二','度正','宋','宋诗','song-poetry','','[]','憶昔歸來自建溪，徘徊擬峴訪前題。',64,'全唐诗/poet.song.183000.json','["憶昔歸來自建溪，徘徊擬峴訪前題。", "江山秀偉鍾靈傑，文物光輝煥斗奎。", "歷數儒紳真冀北，推源宗派孕江西。", "鳳雛驥子今如許，稱兕公堂儻許躋。"]'),
('2da7cf68-6963-4300-be04-a6705ec1cee9','奉呈制機','度正','宋','宋诗','song-poetry','','[]','三弄薰風再入絃，東堂珠履壓初筵。',64,'全唐诗/poet.song.183000.json','["三弄薰風再入絃，東堂珠履壓初筵。", "紅蓮喜泛西來日，蓬矢欣逢北伐天。", "一句緇衣真舊詠，幾章綠竹更新箋。", "中興事業皆餘地，何用糢糊佛與仙。"]'),
('595b7352-ef28-4439-a8da-63a20b43f32f','和制置喜雨之什','度正','宋','宋诗','song-poetry','','[]','靈均一寸了纖埃，坐看雲根萬仞開。',64,'全唐诗/poet.song.183000.json','["靈均一寸了纖埃，坐看雲根萬仞開。", "不用揮戈方掃去，等閒噀酒便呼來。", "清風濯我知何限，霖雨思賢想幾回。", "更向日邊勤一溉，盡蘇海宇亦奇哉。"]'),
('4317fd99-06a9-40e2-b1e6-636b1f1e4ac7','次合州新趙使君阻雨','度正','宋','宋诗','song-poetry','','[]','時髦濟濟盛經綸，自愧空疎忝字民。',64,'全唐诗/poet.song.183000.json','["時髦濟濟盛經綸，自愧空疎忝字民。", "槐下日光憂杲杲，麥秋雨勢厭頻頻。", "化工付物難占命，精意回天亦在人。", "閉閤焚香惟靜坐，一回思念一眉顰。"]'),
('ecd5944f-7fd7-4a1e-a986-88c924e47c2c','奉別運判劉公侍御十四丈','度正','宋','宋诗','song-poetry','','[]','漢庭諸老盡忠良，何事臺頭獨抗章。',64,'全唐诗/poet.song.183000.json','["漢庭諸老盡忠良，何事臺頭獨抗章。", "萬里還家心似水，三年憂國鬢成霜。", "盛時好去金毛鼠，明主應思鐵面郎。", "聖世工夫須著力，心中一點要明光。"]'),
('b70ab866-6b25-49c5-8cce-5d2a0dca132f','正伏承澤深僉判學士賢友以正生朝寵貺佳篇輒次元韵  其一','度正','宋','宋诗','song-poetry','','[]','當年霽月正光凝，坐對窗前草吐英。',64,'全唐诗/poet.song.183000.json','["當年霽月正光凝，坐對窗前草吐英。", "已羨同時希潔白，更高異代繼澄清。", "蒲盧有道應知化，花柳無私自應誠。", "世重世輕皆自樂，登壇還與蒞斯盟。"]'),
('2f28de32-dcf3-4d4c-830b-0551776cc045','正伏承澤深僉判學士賢友以正生朝寵貺佳篇輒次元韵  其二','度正','宋','宋诗','song-poetry','','[]','特立誰能爲道謀，千鈞豈可委庸流。',64,'全唐诗/poet.song.183000.json','["特立誰能爲道謀，千鈞豈可委庸流。", "正塗壅底如叢棘，此意蕭條若綴旒。", "指掌人歸容景慕，傳心書在正研求。", "恭惟天道何由謬，服力田疇自有秋。"]'),
('127eb54a-543d-484f-b189-208642ae68ea','正伏承澤深僉判學士賢友以正生朝寵貺佳篇輒次元韵  其三','度正','宋','宋诗','song-poetry','','[]','清獻重逢在永陽，方知此道浸明昌。',64,'全唐诗/poet.song.183000.json','["清獻重逢在永陽，方知此道浸明昌。", "非聰何以聞天籟，有畀終須辨國香。", "不貳見知忠肅瓘，逸民晚遇太師光。", "聖賢出處寧無意，捨則深藏用束裝。"]'),
('c7d3e9e4-5eb4-4292-90c4-7c41e0148947','正伏承澤深僉判學士賢友以正生朝寵貺佳篇輒次元韵  其四','度正','宋','宋诗','song-poetry','','[]','自洛而閩幸有傳，更相私淑百餘年。',64,'全唐诗/poet.song.183000.json','["自洛而閩幸有傳，更相私淑百餘年。", "面言猶及金爲口，手墨何妨錦作箋。", "在昔見聞迷卓約，至今鑽仰歎高堅。", "分明太極圖中意，更續源源付後賢。"]'),
('633b2cbe-3b80-4d27-9f95-04080dc7bdc3','奉壽季章大參相公','度正','宋','宋诗','song-poetry','','[]','卓立三峰萬仞高，依然兄弟並雄褒。',64,'全唐诗/poet.song.183000.json','["卓立三峰萬仞高，依然兄弟並雄褒。", "卷懷經濟藏三徑，震起聲音滿九皋。", "曾向黄扉參道論，詎容綠野恣閒遨。", "紫雲山下梅偏早，欲送清香薦玉醪。"]'),
('6d2a7ff7-3b27-4e6e-ba37-cc6cb83e7297','太孺人生朝','度正','宋','宋诗','song-poetry','','[]','萬事隨緣處處安，分明淡泊有餘歡。',64,'全唐诗/poet.song.183000.json','["萬事隨緣處處安，分明淡泊有餘歡。", "癡兒解賦蟠桃頌，拙婦能炊脫粟餐。", "天上神仙誰羨慕，人間真樂我團欒。", "願如松柏堅剛壽，相與年年保歲寒。"]'),
('215503ee-f785-4bc4-8a12-751ad076a313','賀張儀立弄璋','度正','宋','宋诗','song-poetry','','[]','弄月吟風泮水湄，幾回占喜誤蛛絲。',64,'全唐诗/poet.song.183000.json','["弄月吟風泮水湄，幾回占喜誤蛛絲。", "三鱣講罷爭傳易，一鯉祥開想學詩。", "天傅梅花凝蝶粉，春歸柳葉畫蛾眉。", "何時得踐凌雲約，領畧山中一段奇。"]'),
('b15a0294-72d8-46b7-a9ff-3957e981c352','別堅甫伯修','度正','宋','宋诗','song-poetry','','[]','幾日馳來別浩齋，偶然良晤盡吾儕。',64,'全唐诗/poet.song.183000.json','["幾日馳來別浩齋，偶然良晤盡吾儕。", "苛留歸思主人惡，少駐征鞍客子佳。", "栗烈侵膚凝臘雪，縱橫塞路困山崖。", "三家白髮元相似，放去從教慰母懷。"]'),
('3517206d-01cd-4fb6-84ca-3ce42a46fb14','送胡茶馬赴京西漕','度正','宋','宋诗','song-poetry','','[]','夾岸黄花弄夕曛，歸艎擊汰不堪聞。',64,'全唐诗/poet.song.183000.json','["夾岸黄花弄夕曛，歸艎擊汰不堪聞。", "愁容政想峩眉月，喜氣遥占峴首雲。", "酒罷樓頭觀妙算，公餘壠畔訪清汾。", "明年入奏明光殿，前席雍容細剖分。"]'),
('5b72bfcf-b2c9-44aa-8fa8-cbe23d12d678','送錢國博解成都漕節詳刑湖右  其一','度正','宋','宋诗','song-poetry','','[]','坐於黄卷得新功，學海波中號老龍。',64,'全唐诗/poet.song.183000.json','["坐於黄卷得新功，學海波中號老龍。", "雅以明經空四海，何曾屈膝拜三公。", "漢庭耿耿千回夢，蜀道依依一節東。", "帷幄儻求真學士，當今難捨狀頭翁。"]'),
('82e59f5c-5446-40a0-bfa2-74776467e5a1','送錢國博解成都漕節詳刑湖右  其二','度正','宋','宋诗','song-poetry','','[]','難弟堂堂玉立峰，當年同奏大明宮。',64,'全唐诗/poet.song.183000.json','["難弟堂堂玉立峰，當年同奏大明宮。", "早慚遊子迷求益，晚侍賓筵喜發蒙。", "妙境妄能窺鴈蕩，春風留得滿蠶叢。", "從今午夜占星斗，弱水之西望大逢。"]'),
('3c2b997c-d5ca-4283-bb38-c5a038390b5e','奉送游子正監簿解嘉定郡紱赴利漕詩  其一','度正','宋','宋诗','song-poetry','','[]','中興人物爛如星，西海之濱起一經。',64,'全唐诗/poet.song.183000.json','["中興人物爛如星，西海之濱起一經。", "皇極虛懷咨讜直，遠人却立望儀形。", "回天萬宇光衝斗，夾日一心夢繞庭。", "何草不黄風雨後，更看老柏獨青青。"]'),
('0b3f6d1b-0c1c-4019-bfef-192bbd89a16a','奉送游子正監簿解嘉定郡紱赴利漕詩  其二','度正','宋','宋诗','song-poetry','','[]','君王神武念京都，關洛規恢入廟謨。',64,'全唐诗/poet.song.183000.json','["君王神武念京都，關洛規恢入廟謨。", "渭水新屯觀定勢，木牛成算付真儒。", "馳驅莫惜銷人髀，矍鑠還堪發壯圖。", "會看詩書真事業，摩挲劍石爲平鋪。"]'),
('b313b208-a7ca-4755-b186-224a8ec0c9bf','送曹機宜','度正','宋','宋诗','song-poetry','','[]','溫公早歲侍天章，萬里西來漕益昌。',64,'全唐诗/poet.song.183000.json','["溫公早歲侍天章，萬里西來漕益昌。", "講學於時資友鎮，留題到處著男光。", "春秋比較年相似，詩禮漸摩日正長。", "發策决科自餘事，要須器業踵前芳。"]'),
('d6235e07-ad3d-4f89-bd3c-8e1a78f24a83','送博寺丞','度正','宋','宋诗','song-poetry','','[]','白日青天曉色開，太虛澄澈絕纖埃。',64,'全唐诗/poet.song.183000.json','["白日青天曉色開，太虛澄澈絕纖埃。", "三陽不與寒威盡，一氣還從暖律回。", "更向中巖收桂子，佇看上苑薦黄梅。", "幾多湖上閒風月，舞詠應堪屬後來。"]'),
('d02078c8-1cfa-41df-84ca-fdfe9326782f','送李左之制幹東歸探韵得今字','度正','宋','宋诗','song-poetry','','[]','萬卷胸中貯古今，西遊蜀道手捫參。',64,'全唐诗/poet.song.183000.json','["萬卷胸中貯古今，西遊蜀道手捫參。", "寶彜殘刻窺心畫，清廟遺音振學林。", "雅行瓊瑰殊慰我，每陪樽俎定論心。", "飄飄衣袂青雲去，佇立東風聽惠音。"]'),
('0f1484a3-d7b7-45be-b396-7e68345a6337','送張季修歸簡州兼簡伯修','度正','宋','宋诗','song-poetry','','[]','屈子文章似六經，縉雲重與振遺音。',64,'全唐诗/poet.song.183000.json','["屈子文章似六經，縉雲重與振遺音。", "一門秀出金閨彥，三峽光摇玉宇參。", "挾冊夙潛心學海，揮毫今獨步儒林。", "橫飛脫去科場累，更去騷人向上尋。"]'),
('be4bc90e-1b73-4bdc-9b71-1dc91424f1ca','送許仁叔解組東歸','度正','宋','宋诗','song-poetry','','[]','萬里來官蜀錦城，西南籍籍飲清名。',64,'全唐诗/poet.song.183000.json','["萬里來官蜀錦城，西南籍籍飲清名。", "幕中議論誰爲敵，天下交遊我與盟。", "聖處工夫須自得，明時事業只安行。", "草堂擬作終焉計，便翼飛來總寄聲。"]'),
('25bb3ac9-79cd-40e3-86c7-270626723f3c','送張西和南歸','度正','宋','宋诗','song-poetry','','[]','長記春風拂拂吹，烏奴江上濯漣漪。',64,'全唐诗/poet.song.183000.json','["長記春風拂拂吹，烏奴江上濯漣漪。", "便論槃叟心傳日，更及南翁指授時。", "戎貊也應知姓字，親朋未必記芝眉。", "公朝有意開皇極，不用溪頭理釣絲。"]'),
('48b429db-7652-4128-aa88-612f67cfaa2a','君錫知丞僚友錄示諸公所賦介壽堂詩謹次後溪先生元韵以記盛事','度正','宋','宋诗','song-poetry','','[]','老翁神氣亦輕强，鑿井耕田種豫章。',64,'全唐诗/poet.song.183000.json','["老翁神氣亦輕强，鑿井耕田種豫章。", "扶植高標盤石壑，養成合抱棟明堂。", "風雷海運非人力，日月天開盛寵光。", "既醉詩書餐道德，坐觀晚節更清香。"]'),
('c93c864b-9280-4b98-a0b7-8d261b78ae57','至喜亭詩','度正','宋','宋诗','song-poetry','','[]','扁舟三峽備艱難，幸脫風波魄未安。',64,'全唐诗/poet.song.183000.json','["扁舟三峽備艱難，幸脫風波魄未安。", "山已陵夷成㟝嶁，水無約束漸瀰漫。", "半天堤柳垂春暖，滿地江梅怯歲寒。", "坎坷一生何所用，它年湖海一漁竿。"]'),
('38082919-e94c-4e81-8cf3-665633fdd351','題錦屏山','度正','宋','宋诗','song-poetry','','[]','積翠浮空老不枯，英靈今此定何如。',64,'全唐诗/poet.song.183000.json','["積翠浮空老不枯，英靈今此定何如。", "萬章松柏還蒙密，千載風雲頗闊疎。", "一氣周流無間斷，四時變化有盈虛。", "憑高極目懷嵩華，此憤何時可一攄。"]'),
('62c7dfa6-e4a4-4a09-a982-7b3b9b8c7540','奉送溫甫主簿赴昌元新任','度正','宋','宋诗','song-poetry','','[]','年來昌合頗多儒，滿目青山秀不枯。',64,'全唐诗/poet.song.183000.json','["年來昌合頗多儒，滿目青山秀不枯。", "隠者能通三聖易，賢良更纘六經圖。", "簿書整暇拋官事，朋友從容味道腴。", "我已倦遊還舊隠，新吟時寄幾篇無。"]'),
('49e1e358-ae85-416d-bd50-853f1d787ccf','奉輓靈泉明府東叔學士','度正','宋','宋诗','song-poetry','','[]','西州文物起雷霆，四海一家仰聚星。',64,'全唐诗/poet.song.183000.json','["西州文物起雷霆，四海一家仰聚星。", "五鳳翺翔橫碧落，雙鳬朝謁墮青冥。", "疑歸天上修仙史，恥向人間駕說鈴。", "長歎良朋難再得，更憂吾道太彫零。"]'),
('050211d4-bfea-49c0-9ee7-b20397d6f282','輓史教授子正','度正','宋','宋诗','song-poetry','','[]','獨抱遺經手不停，振衣藝苑自雷霆。',64,'全唐诗/poet.song.183000.json','["獨抱遺經手不停，振衣藝苑自雷霆。", "文如曾子反居亞，才過高軒又短齡。", "共歎麒麟封白壤，喜看鴻鴈在青冥。", "慈顔莫作虛空想，西簡先生千字銘。"]'),
('911a9ac8-78a9-4fdd-9cc6-b5fdaa50f701','輓黄通判明叔座主','度正','宋','宋诗','song-poetry','','[]','政在伾文過十年，幾多巖穴老英賢。',64,'全唐诗/poet.song.183000.json','["政在伾文過十年，幾多巖穴老英賢。", "公車牘上皆亨路，夜壑舟移閟下泉。", "事業鼎彜千古恨，文章衣鉢萬燈傳。", "兌齋遺稿今無恙，更看諸郎各勉旃。"]'),
('8fc2bc13-5adb-487e-86cb-5f315dc82ae9','奉輓浦江譙夫人','度正','宋','宋诗','song-poetry','','[]','天資高朗識精微，千載興亡洞是非。',64,'全唐诗/poet.song.183000.json','["天資高朗識精微，千載興亡洞是非。", "子美詩中聞鳳語，羲之筆下相鸞飛。", "口傳諸子今爲盛，心念宗周古亦稀。", "喜懼高懷如履薄，西瞻白鶴重歔欷。"]'),
('767b9a2e-2ea8-469b-8cba-a45f1b070650','知縣九十一丈應聘成都賦詩爲別','度正','宋','宋诗','song-poetry','','[]','珍重圭璋彥，經綸半世閒。',216,'全唐诗/poet.song.183000.json','["珍重圭璋彥，經綸半世閒。", "紛紛徒自黠，默默了非頑。", "懷道心雖泰，憂時鬢已斑。", "操存期入室，得失詎踰閑。", "忽遇風雲會，應思雨露頒。", "慨言全蜀病，均是一家患。", "友愛惟天性，侵牟可厚顔。", "未能忘狗鼠，安得及孤鰥。", "昔志詞何屈，今行勢莫艱。", "坎離交接地，損益覆翻間。", "戶外元無盜，山前怎有蠻。", "都緣人好事，所以物生姦。", "善惡無他道，廉貪是要關。", "但令歸似水，何用積如山。", "問政文而上，論心武以還。", "未言齊地利，當念破天慳。", "公議尤相傃，愚言殆未刪。", "君王何必利，孟叟語非訕。"]'),
('6f0812d7-e59c-466b-acf7-659ec4cff37b','殿中覆考進士','度正','宋','宋诗','song-poetry','','[]','交戟重門間九閽，彤庭紫殿切星辰。',32,'全唐诗/poet.song.183000.json','["交戟重門間九閽，彤庭紫殿切星辰。", "能來此地連宵直，即是驂鸞駕鶴人。"]'),
('562fab3e-16d1-4f20-8abd-e02de29a130a','兼考遂寧補試鎖宿在學戲題一絕','度正','宋','宋诗','song-poetry','','[]','壯士縛雞聊爾耳，小兒相鼎竟何如。',32,'全唐诗/poet.song.183000.json','["壯士縛雞聊爾耳，小兒相鼎竟何如。", "眼前萬事不堪說，惟有秋風解得渠。"]'),
('27cbd606-209f-4d36-8905-011b775eb5d0','贈䨥先生','度正','宋','宋诗','song-poetry','','[]','眼如明月口如神，閒裏乾坤物外身。',32,'全唐诗/poet.song.183000.json','["眼如明月口如神，閒裏乾坤物外身。", "世上窮通都莫問，粹然生色幾何人。"]'),
('1e2a466c-615c-4ddd-888f-45ea92e9c417','制幹判院初度載臨謹以梅起興賦三絕句爲斯文壽一笑幸甚  其一','度正','宋','宋诗','song-poetry','','[]','江梅吐出五花新，綽約林間早占春。',32,'全唐诗/poet.song.183000.json','["江梅吐出五花新，綽約林間早占春。", "多謝天公孕佳實，中心渾是那仁仁。"]'),
('2afdf817-d8c6-461e-8132-f9efcdaf47e8','制幹判院初度載臨謹以梅起興賦三絕句爲斯文壽一笑幸甚  其二','度正','宋','宋诗','song-poetry','','[]','冰魂玉質映霜林，四月飛成點點金。',32,'全唐诗/poet.song.183000.json','["冰魂玉質映霜林，四月飛成點點金。", "遥想清香能止渴，應知此意可爲霖。"]'),
('0b1eaa50-1511-47b3-b301-e1dcfb323343','制幹判院初度載臨謹以梅起興賦三絕句爲斯文壽一笑幸甚  其三','度正','宋','宋诗','song-poetry','','[]','傅巖人起應旁招，道德光明相業高。',32,'全唐诗/poet.song.183000.json','["傅巖人起應旁招，道德光明相業高。", "試問當年調鼎事，非梨非栗不能桃。"]'),
('00aabad8-ae8f-4b1d-ac99-95a3d4fc0bfc','正蒙主文教授大著寵示佳章輒繼嚴韵仰酬盛意之辱兼呈諸契丈幸賜采矚正皇恐再拜  其一','度正','宋','宋诗','song-poetry','','[]','珍重知音審五聲，也從紙上得張程。',32,'全唐诗/poet.song.183000.json','["珍重知音審五聲，也從紙上得張程。", "設科久矣何曾見，想像雙瞳萬古驚。"]'),
('cef74b32-aa80-4bbd-b905-36e8c0810617','正蒙主文教授大著寵示佳章輒繼嚴韵仰酬盛意之辱兼呈諸契丈幸賜采矚正皇恐再拜  其二','度正','宋','宋诗','song-poetry','','[]','眼空未可歎賢無，瓦礫中間有寶珠。',32,'全唐诗/poet.song.183000.json','["眼空未可歎賢無，瓦礫中間有寶珠。", "多謝三峩孕清淑，安排貢籍貢鴻儒。"]'),
('acf1c9e5-b70c-42d4-9f68-db69d2fee7a0','正蒙主文教授大著寵示佳章輒繼嚴韵仰酬盛意之辱兼呈諸契丈幸賜采矚正皇恐再拜  其三','度正','宋','宋诗','song-poetry','','[]','學禁初行好斷魂，中庸大學委塵昏。',32,'全唐诗/poet.song.183000.json','["學禁初行好斷魂，中庸大學委塵昏。", "如今天子都除却，正學何憂更屈伸。"]'),
('9030b669-2498-40b4-8bd3-85481a54e1f5','正蒙主文教授大著寵示佳章輒繼嚴韵仰酬盛意之辱兼呈諸契丈幸賜采矚正皇恐再拜  其四','度正','宋','宋诗','song-poetry','','[]','外省風雷亦壯哉，曾將科目放顔回。',32,'全唐诗/poet.song.183000.json','["外省風雷亦壯哉，曾將科目放顔回。", "因尋俊秀傳衣鉢，笑指凌雲得得來。"]'),
('b53261ae-9b39-4273-98da-b5c21fcf7e6a','正蒙主文教授大著寵示佳章輒繼嚴韵仰酬盛意之辱兼呈諸契丈幸賜采矚正皇恐再拜  其五','度正','宋','宋诗','song-poetry','','[]','冥搜竊歎眼俱高，我欲還家備百牢。',32,'全唐诗/poet.song.183000.json','["冥搜竊歎眼俱高，我欲還家備百牢。", "三十三人齊上去，舉盃帆外送洪濤。"]'),
('cb2bc26c-2616-4e25-893c-5abc413d7436','昨幸甚得見子玉教授丈得一論其說出於訂頑克己銘詞致超絕輒借前韻以慶兼呈諸丈幸乞一笑正再拜上  其一','度正','宋','宋诗','song-poetry','','[]','天作斯文鼓大聲，賢科今已定章程。',32,'全唐诗/poet.song.183000.json','["天作斯文鼓大聲，賢科今已定章程。", "諸生自此升堂去，讒說安能復震驚。"]'),
('d3cd603e-b974-4e59-8856-8a04b42d2763','昨幸甚得見子玉教授丈得一論其說出於訂頑克己銘詞致超絕輒借前韻以慶兼呈諸丈幸乞一笑正再拜上  其二','度正','宋','宋诗','song-poetry','','[]','廣文人物世間無，兩眼晶熒照乘珠。',32,'全唐诗/poet.song.183000.json','["廣文人物世間無，兩眼晶熒照乘珠。", "拈出便應人歎服，粹然議論到先儒。"]'),
('f6c91132-208c-413a-a7d2-7b8f06e39330','昨幸甚得見子玉教授丈得一論其說出於訂頑克己銘詞致超絕輒借前韻以慶兼呈諸丈幸乞一笑正再拜上  其三','度正','宋','宋诗','song-poetry','','[]','新泉瀹茗濯詩魂，繙閱如飛徹曉昏。',32,'全唐诗/poet.song.183000.json','["新泉瀹茗濯詩魂，繙閱如飛徹曉昏。", "是石無瑕終是石，莫教抱璞退聲冤。"]'),
('9c0a9676-4c18-4285-a983-0d4a1538b442','昨幸甚得見子玉教授丈得一論其說出於訂頑克己銘詞致超絕輒借前韻以慶兼呈諸丈幸乞一笑正再拜上  其四','度正','宋','宋诗','song-poetry','','[]','鑒別毫釐豈易哉，逢奇何惜讀千回。',32,'全唐诗/poet.song.183000.json','["鑒別毫釐豈易哉，逢奇何惜讀千回。", "充囊未可矜前得，如積薪焉看後來。"]'),
('13954f6a-a8b2-4ec6-aca7-98392f93d1d4','昨幸甚得見子玉教授丈得一論其說出於訂頑克己銘詞致超絕輒借前韻以慶兼呈諸丈幸乞一笑正再拜上  其五','度正','宋','宋诗','song-poetry','','[]','淺陋微邦望不高，偶同齊晉會蟲牢。',32,'全唐诗/poet.song.183000.json','["淺陋微邦望不高，偶同齊晉會蟲牢。", "進賢受賞非吾事，拭目龍門躍巨濤。"]'),
('e45fa3e0-c9bc-4fab-91e2-4758130aace6','漕司檄勸稼望見資州憶王褒李鼎祚  其一','度正','宋','宋诗','song-poetry','','[]','文王既沒易中沒，孔子重明漢又衰。',32,'全唐诗/poet.song.183000.json','["文王既沒易中沒，孔子重明漢又衰。", "可惜李生真力學，但求象數不求詞。"]'),
