('d171a29d-6471-4ca7-b90f-724dd60fe601','頌古五十三首  其三一','釋文禮','宋','宋诗','song-poetry','','[]','賸噇生菜似頭馿，臨濟堂前捉敗渠。',32,'全唐诗/poet.song.183000.json','["賸噇生菜似頭馿，臨濟堂前捉敗渠。", "聳耳長鳴隨踢踏，不知業債倩誰除。"]'),
('7789c312-c5a5-48bc-9360-07093bb56493','頌古五十三首  其三二','釋文禮','宋','宋诗','song-poetry','','[]','階頭放下劫初鈴，相撲呼它馬使名。',32,'全唐诗/poet.song.183000.json','["階頭放下劫初鈴，相撲呼它馬使名。", "五棒打來無雪處，却言渠不是官行。"]'),
('b494d43d-d75e-4aee-bcdc-97c021086d3a','頌古五十三首  其三三','釋文禮','宋','宋诗','song-poetry','','[]','禍福無門口自招，三遭瞎棒打馿腰。',32,'全唐诗/poet.song.183000.json','["禍福無門口自招，三遭瞎棒打馿腰。", "可憐敗國亡家恨，萬古春風吹不消。"]'),
('33e87e7b-1308-465f-9339-c8483a27adeb','頌古五十三首  其三四','釋文禮','宋','宋诗','song-poetry','','[]','家常添鉢繞村行，驀地一聲無厭生。',32,'全唐诗/poet.song.183000.json','["家常添鉢繞村行，驀地一聲無厭生。", "化主分明嫌少在，籬門掩却强惺惺。"]'),
('e2e0ce47-5941-4757-acb4-92c615aaa2c2','頌古五十三首  其三五','釋文禮','宋','宋诗','song-poetry','','[]','烏藤倒掛向平田，便把羸牛痛下鞭。',32,'全唐诗/poet.song.183000.json','["烏藤倒掛向平田，便把羸牛痛下鞭。", "更說養來經五歲，始終只是老婆禪。"]'),
('deac821e-310c-42db-b920-220479da968d','頌古五十三首  其三六','釋文禮','宋','宋诗','song-poetry','','[]','師之一字太孤危，文□□無作者知。',32,'全唐诗/poet.song.183000.json','["師之一字太孤危，文□□無作者知。", "不領韶陽提起處，且從默處認殘碑。"]'),
('fee88689-4551-4503-a929-501b0e76b72a','頌古五十三首  其三七','釋文禮','宋','宋诗','song-poetry','','[]','親到龍潭已暗投，夜深誰共御街遊。',32,'全唐诗/poet.song.183000.json','["親到龍潭已暗投，夜深誰共御街遊。", "紙燈吹滅狼烟息，坐斷中原四百州。"]'),
('d99dba74-331b-49c6-95dd-aba1550516cc','頌古五十三首  其三八','釋文禮','宋','宋诗','song-poetry','','[]','山邊水邊待月明，暫向人間借路行。',32,'全唐诗/poet.song.183000.json','["山邊水邊待月明，暫向人間借路行。", "如今還向山邊去，只有湖水無行路。"]'),
('9b24e3f9-2465-4988-864a-b523abd8fba6','頌古五十三首  其三九','釋文禮','宋','宋诗','song-poetry','','[]','住山境界問如何，女子雙鬟鬢已皤。',32,'全唐诗/poet.song.183000.json','["住山境界問如何，女子雙鬟鬢已皤。", "覿面不逢休更會，白雲飛過舊山河。"]'),
('b609df64-1c25-4b5c-b4da-d30091e09228','頌古五十三首  其四○','釋文禮','宋','宋诗','song-poetry','','[]','菴僧真實濟兇人，一喝分明出差珍。',32,'全唐诗/poet.song.183000.json','["菴僧真實濟兇人，一喝分明出差珍。", "莫道賊魁非別者，當頭雪刃用來親。"]'),
('173c3c55-d69f-455f-8d3a-2f3985dfb734','頌古五十三首  其四一','釋文禮','宋','宋诗','song-poetry','','[]','四方八面沒邊疆，暴雨狂風無處藏。',32,'全唐诗/poet.song.183000.json','["四方八面沒邊疆，暴雨狂風無處藏。", "古廟裏頭休軃避，移舟別有好商量。"]'),
('af7c4410-cb1f-4a94-8235-e2d0d8012c2f','頌古五十三首  其四二','釋文禮','宋','宋诗','song-poetry','','[]','法戰場開驗克賓，解施武略對將軍。',32,'全唐诗/poet.song.183000.json','["法戰場開驗克賓，解施武略對將軍。", "如何有罪全無賞，待展奇謀自策勛。"]'),
('fde73f98-6f77-4b2f-8303-2eaf2cac7ff3','頌古五十三首  其四三','釋文禮','宋','宋诗','song-poetry','','[]','不動蒲帆問一言，大魚却被小魚吞。',32,'全唐诗/poet.song.183000.json','["不動蒲帆問一言，大魚却被小魚吞。", "直從意外超唇吻，始信巖頭無腦門。"]'),
('fe5b5da1-649d-40c0-bf37-71563b9dbb0a','頌古五十三首  其四四','釋文禮','宋','宋诗','song-poetry','','[]','從來六箇不知音，一箇全拋惡浪深。',32,'全唐诗/poet.song.183000.json','["從來六箇不知音，一箇全拋惡浪深。", "義斷情忘無處覓，三千剎海冷沉沉。"]'),
('e7ad6c19-b065-428a-bd1c-fc29130d8b45','頌古五十三首  其四五','釋文禮','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',40,'全唐诗/poet.song.183000.json','["有句無句，如藤倚樹。", "回避無門，毒蛇當路。", "樹倒藤枯，句歸何處。", "明眼衲僧，一場罔措。"]'),
('98f64ad0-8b55-449f-82ca-3e9b55303ed2','頌古五十三首  其四六','釋文禮','宋','宋诗','song-poetry','','[]','磐陀漠漠秘蒼苔，終日跏趺兩鬢摧。',32,'全唐诗/poet.song.183000.json','["磐陀漠漠秘蒼苔，終日跏趺兩鬢摧。", "縱使不曾呼喚著，何嘗謾得阿師來。"]'),
('f043e08a-4eda-44db-ab13-37c129878da1','頌古五十三首  其四七','釋文禮','宋','宋诗','song-poetry','','[]','因我得禮你，事從叮囑起。',24,'全唐诗/poet.song.183000.json','["因我得禮你，事從叮囑起。", "誰知白蘋風，不在秋江裏。"]'),
('f52c2936-e4f4-4425-9317-e3f25c893297','頌古五十三首  其四八','釋文禮','宋','宋诗','song-poetry','','[]','讀書人報來，豈在之乎者。',24,'全唐诗/poet.song.183000.json','["讀書人報來，豈在之乎者。", "孔子與周公，皆不及門也。"]'),
('312d04c1-ba05-406b-8394-f2801b469b60','頌古五十三首  其四九','釋文禮','宋','宋诗','song-poetry','','[]','天地廣無邊，何云藏北斗。',24,'全唐诗/poet.song.183000.json','["天地廣無邊，何云藏北斗。", "跛脚老雲門，未明三八九。"]'),
('3e2e2b8e-1ba2-4c4c-bcf1-9dc6859af167','頌古五十三首  其五○','釋文禮','宋','宋诗','song-poetry','','[]','樹凋葉落聊伸問，體露金風錯指蹤。',32,'全唐诗/poet.song.183000.json','["樹凋葉落聊伸問，體露金風錯指蹤。", "带累兒孫無豹變，等閒落在草窠中。"]'),
('917f2efb-89a6-4ef6-a0b9-d29cd48b17e3','頌古五十三首  其五一','釋文禮','宋','宋诗','song-poetry','','[]','賀家湖上天華寺，一一軒窗面水開。',32,'全唐诗/poet.song.183000.json','["賀家湖上天華寺，一一軒窗面水開。", "不是閉門防俗客，愛閑能有幾人來。"]'),
('45beb55d-b015-4774-9218-93e0fae45735','頌古五十三首  其五二','釋文禮','宋','宋诗','song-poetry','','[]','大龍景物最幽妍，澗水山花照眼鮮。',32,'全唐诗/poet.song.183000.json','["大龍景物最幽妍，澗水山花照眼鮮。", "堅固法身何必問，風光長在劫壺先。"]'),
('824d2ba4-def7-4651-955f-17e943fb1ceb','頌古五十三首  其五三','釋文禮','宋','宋诗','song-poetry','','[]','白牛烹了正熙熙，皮角官中却要追。',32,'全唐诗/poet.song.183000.json','["白牛烹了正熙熙，皮角官中却要追。", "將下帽簷輸納了，燈前更鼓夜遲遲。"]'),
('b1a2cf5f-10cc-483a-964f-a5c2b54b4b4a','偈二首  其一','釋文禮','宋','宋诗','song-poetry','','[]','黄鍾纔起時，九數從頭數。',66,'全唐诗/poet.song.183000.json','["黄鍾纔起時，九數從頭數。", "相將幽谷鶑啼，次第雕梁燕語。", "田父祭勾芒，叢祠敲社鼓。", "農父狎牛郎，村姑教蠶婦。", "光陰老盡世間人，冬至寒食一百五。"]'),
('e53462f1-d67d-486f-87fa-5661de3b60cd','偈二首  其二','釋文禮','宋','宋诗','song-poetry','','[]','此力分明在不欺，不欺能有幾人知。',32,'全唐诗/poet.song.183000.json','["此力分明在不欺，不欺能有幾人知。", "要明象兔全提句，看取陞階正笏時。"]'),
('090b130a-312a-4d1a-8022-97d2c027583f','偈頌五首  其一','釋文禮','宋','宋诗','song-poetry','','[]','震忽雷，飛閃電。',16,'全唐诗/poet.song.183000.json','["震忽雷，飛閃電。", "夜叉頭，菩薩面。"]'),
('d9d964c8-cd4d-425d-8ceb-9595805d0170','偈頌五首  其二','釋文禮','宋','宋诗','song-poetry','','[]','萬松關迥，九隴烟橫。',20,'全唐诗/poet.song.183000.json','["萬松關迥，九隴烟橫。", "谷風傳響，澗水流聲。"]'),
('3f8baa59-aced-491e-b6c8-27812553036c','偈頌五首  其三','釋文禮','宋','宋诗','song-poetry','','[]','衆生本不曾迷，夜闌雞向五更啼。',46,'全唐诗/poet.song.183000.json','["衆生本不曾迷，夜闌雞向五更啼。", "諸佛本不曾悟，秋清雁度長空去。", "西窗昨夜月華明，涼飆已到梧桐樹。"]'),
('581e23dc-aa91-468e-9b30-54f9f3c7faeb','偈頌五首  其四','釋文禮','宋','宋诗','song-poetry','','[]','七尺單前，一蒲團地。',20,'全唐诗/poet.song.183000.json','["七尺單前，一蒲團地。", "橫亙十方，豎窮三際。"]'),
('c0682391-9370-49e4-adae-066116588899','偈頌五首  其五','釋文禮','宋','宋诗','song-poetry','','[]','夜明簾外，寶鑑臺前。',36,'全唐诗/poet.song.183000.json','["夜明簾外，寶鑑臺前。", "元無兼带，豈有偏圓。", "古渡無人霜月冷，蘆花風靜鷺鷥眠。"]'),
('a9439abe-bb17-444d-b021-829e8cc4dc21','頌七賢女遊屍陀林','釋文禮','宋','宋诗','song-poetry','','[]','七珍八寶任君需，三物從來的是無。',32,'全唐诗/poet.song.183000.json','["七珍八寶任君需，三物從來的是無。", "若向無中拈得出，不須見佛問何如。"]'),
('5300a004-fa83-4aeb-bec1-bf885eabc128','頌馬祖因僧問離四句絕百非','釋文禮','宋','宋诗','song-poetry','','[]','喚起窗全曙，催歸日未西。',24,'全唐诗/poet.song.183000.json','["喚起窗全曙，催歸日未西。", "無心花裏鳥，更與盡情啼。"]'),
('aa29cacb-4ca2-4b9a-9c4d-e608d3eaf9dd','六代祖師贊  其一','釋文禮','宋','宋诗','song-poetry','','[]','咄咄胡僧，齒缺面黑。',36,'全唐诗/poet.song.183000.json','["咄咄胡僧，齒缺面黑。", "滿口鄉談，無人譯得。", "只知結果自然成，不知滿地花狼藉。"]'),
('1d2e3d79-55ad-4f83-9424-2f66ddf7108d','六代祖師贊  其二','釋文禮','宋','宋诗','song-poetry','','[]','哀哉斷臂，甘受欺瞞。',36,'全唐诗/poet.song.183000.json','["哀哉斷臂，甘受欺瞞。", "心既不有，何處求安。", "寂寂少林人不見，一庭風雪夜漫漫。"]'),
('d1c3e34f-81e4-41ca-943e-052892d7e128','六代祖師贊  其三','釋文禮','宋','宋诗','song-poetry','','[]','內外中間，覓罪不得。',36,'全唐诗/poet.song.183000.json','["內外中間，覓罪不得。", "瞌睡醒來，眼睛突出。", "一從歸去皖公山，直至如今沒蹤蹟。"]'),
('323ab473-4864-42ee-9e91-e743aa3d78fd','六代祖師贊  其四','釋文禮','宋','宋诗','song-poetry','','[]','破頭山前，三辭詔旨。',36,'全唐诗/poet.song.183000.json','["破頭山前，三辭詔旨。", "教壞小兒，賣弄唇嘴。", "無端又上牛頭山，更與懶融說道理。"]'),
('0c87d04f-5f21-4c85-a689-83a696e2e565','六代祖師贊  其五','釋文禮','宋','宋诗','song-poetry','','[]','黄梅再來，青松依舊。',36,'全唐诗/poet.song.183000.json','["黄梅再來，青松依舊。", "前身後身，一場逗漏。", "七百高僧總作家，唯有南能不唧𠺕。"]'),
('4f2522b8-e675-4b53-aa9a-902a54160bb9','六代祖師贊  其六','釋文禮','宋','宋诗','song-poetry','','[]','倩人書偈，巧說脫空。',36,'全唐诗/poet.song.183000.json','["倩人書偈，巧說脫空。", "傳衣宵遁，喪盡英雄。", "非風旛動惟心動，依舊埋身草莽中。"]'),
('df33d7dc-c174-49c5-9559-7003fbaccf7a','松源和尚贊','釋文禮','宋','宋诗','song-poetry','','[]','耳根聵兀如鴟，項頸縮拗如馿，有問東却答西。',71,'全唐诗/poet.song.183000.json','["耳根聵兀如鴟，項頸縮拗如馿，有問東却答西。", "未嘗許可，說甚傳持。", "臨行三轉語，自起一團疑。", "幾多吞不下，背後亂鍼錐。", "咬定牙關供死款，鐵牛耕破舌頭皮。"]'),
('6ee162f9-8899-4af0-967f-a7f0df95f838','示圓證知客','釋文禮','宋','宋诗','song-poetry','','[]','莫年結屋傍山椒，門外荆蕪沒半腰。',32,'全唐诗/poet.song.183000.json','["莫年結屋傍山椒，門外荆蕪沒半腰。", "幾度賺君來扣擊，老無氣力舉藤條。"]'),
('40b7353e-e718-49a4-a949-bf0c0ad973f7','寄真寂深居圓鑑浄和尚','釋文禮','宋','宋诗','song-poetry','','[]','墾土耕烟四十年，了無禪教與人傳。',32,'全唐诗/poet.song.183000.json','["墾土耕烟四十年，了無禪教與人傳。", "钁頭邊事誰相委，八月深居有筍鞭。"]'),
('def02804-7eca-41b4-8dfa-6d41435b3646','天台石橋','釋文禮','宋','宋诗','song-poetry','','[]','橋橫飛澗上崔嵬，澗瀑千尋吼怒雷。',32,'全唐诗/poet.song.183000.json','["橋橫飛澗上崔嵬，澗瀑千尋吼怒雷。", "五百聲聞看不破，至今活葬在巖隈。"]'),
('2bd197f2-f40f-460b-9ed4-027d721fa410','送僧歸雁山','釋文禮','宋','宋诗','song-poetry','','[]','秋來歸去雁山阿，爲問龍湫諾詎那。',32,'全唐诗/poet.song.183000.json','["秋來歸去雁山阿，爲問龍湫諾詎那。", "貪看高崖千丈雪，伽梨打濕竟如何。"]'),
('429b2bea-6efa-451e-bf12-794df02bbdde','送晦巖佛光法師歸天竺  其一','釋文禮','宋','宋诗','song-poetry','','[]','颺下天台故紙堆，爲搜言外蔣山來。',32,'全唐诗/poet.song.183000.json','["颺下天台故紙堆，爲搜言外蔣山來。", "浙翁拶到無棲泊，謂實情忘撒手回。"]'),
('31a12d48-4021-4dfb-88cc-bd08880e5f8f','送晦巖佛光法師歸天竺  其二','釋文禮','宋','宋诗','song-poetry','','[]','歸去相依有鷲山，渠家一向斥前三。',32,'全唐诗/poet.song.183000.json','["歸去相依有鷲山，渠家一向斥前三。", "誰知開異來同了，圓旨如今亦厭談。"]'),
('af718fa8-5b5c-4ca4-8124-13e164ff4744','佛光炤公首依於梁渚今往下竺參北峰印禪師二首  其一','釋文禮','宋','宋诗','song-poetry','','[]','送子參尋靈鷲山，諸方多是落前三。',32,'全唐诗/poet.song.183000.json','["送子參尋靈鷲山，諸方多是落前三。", "自從開異歸同後，玄旨於今亦倦談。"]'),
('b05d0354-b1d1-4c43-ad88-00fa0d6ae804','佛光炤公首依於梁渚今往下竺參北峰印禪師二首  其二','釋文禮','宋','宋诗','song-poetry','','[]','揀境分明妙藥方，餘之分別更須忘。',32,'全唐诗/poet.song.183000.json','["揀境分明妙藥方，餘之分別更須忘。", "晚風吹落殘紅片，休向枝頭覓舊香。"]'),
('aef35120-31f3-45d3-978a-9f43df40c1ee','贊應菴華','釋文禮','宋','宋诗','song-poetry','','[]','亭亭相對兩蒼松，不覺當門觸祖翁。',32,'全唐诗/poet.song.183000.json','["亭亭相對兩蒼松，不覺當門觸祖翁。", "後代兒孫無著莫，忍聽蕭瑟起凄風。"]'),
('a4c92b46-134c-4bd1-8301-00e552afc837','句','釋文禮','宋','宋诗','song-poetry','','[]','施爲動靜憑誰力。',8,'全唐诗/poet.song.183000.json','["施爲動靜憑誰力。"]'),
('92d6884b-29ec-45d2-994c-bc4e8994aa5b','戒事魔十詩  其一','李兼','宋','宋诗','song-poetry','','[]','勸爾編氓莫事魔，魔成剗地禍殃多。',32,'全唐诗/poet.song.183000.json','["勸爾編氓莫事魔，魔成剗地禍殃多。", "家財破蕩身狼籍，看取胡忠季子和。"]'),
('b0c26bc7-2e21-42e4-9d9f-b207d3e84d63','戒事魔十詩  其二','李兼','宋','宋诗','song-poetry','','[]','白衣夜會說無根，到曉奔逃各出門。',32,'全唐诗/poet.song.183000.json','["白衣夜會說無根，到曉奔逃各出門。", "此是邪魔名外道，自投刑辟害兒孫。"]'),
('cc741991-cf0e-4192-84d2-20e277ac7f06','戒事魔十詩  其三','李兼','宋','宋诗','song-poetry','','[]','金鍼引透白蓮池，此語欺人亦自欺。',32,'全唐诗/poet.song.183000.json','["金鍼引透白蓮池，此語欺人亦自欺。", "何似田桑家五畝，雞豚狗彘勿違時。"]'),
('45c2fab3-fe02-44cd-ba05-87d93f7890f0','戒事魔十詩  其四','李兼','宋','宋诗','song-poetry','','[]','莫念雙宗二會經，官中條令至分明。',32,'全唐诗/poet.song.183000.json','["莫念雙宗二會經，官中條令至分明。", "罪流更溢三千里，白佛安能救爾生。"]'),
('1a44303b-d61f-443d-af6a-1319129116a1','戒事魔十詩  其五','李兼','宋','宋诗','song-poetry','','[]','生兒只遣事犁鉏，有智宜令早讀書。',32,'全唐诗/poet.song.183000.json','["生兒只遣事犁鉏，有智宜令早讀書。", "莫被胡輝相引誘，此人决脊尚囚拘。"]'),
('b7d30527-210c-4a02-90ca-7c47e753f370','戒事魔十詩  其六','李兼','宋','宋诗','song-poetry','','[]','蚩蚩女婦太無知，喫菜何須自苦爲。',32,'全唐诗/poet.song.183000.json','["蚩蚩女婦太無知，喫菜何須自苦爲。", "料想阿童鞭背後，心中雖悔可能追。"]'),
('e073d81b-5389-4ccc-915d-6768a81fda42','戒事魔十詩  其七','李兼','宋','宋诗','song-poetry','','[]','仙居舊有祖師堂，坐落當初白塔鄉。',32,'全唐诗/poet.song.183000.json','["仙居舊有祖師堂，坐落當初白塔鄉。", "眼見菜頭頭落地，今人諱說呂師囊。"]'),
('4b23beb1-2e26-472c-b7dd-ee7a0a4482ae','戒事魔十詩  其八','李兼','宋','宋诗','song-poetry','','[]','貴賤家家必有尊，如何舍祖事魔神。',32,'全唐诗/poet.song.183000.json','["貴賤家家必有尊，如何舍祖事魔神。", "細思父母恩難報，早轉頭來孝爾親。"]'),
('b9d4b7c7-ee5f-41ba-bb7a-eaf1cff3b43e','戒事魔十詩  其九','李兼','宋','宋诗','song-poetry','','[]','肉味魚腥喫不妨，隨宜茶飯守家常。',32,'全唐诗/poet.song.183000.json','["肉味魚腥喫不妨，隨宜茶飯守家常。", "朝昏但莫爲諸惡，底用金罏爇乳香。"]'),
('86f3b37d-b9ef-40df-9f7e-8a0a32349baa','戒事魔十詩  其一○','李兼','宋','宋诗','song-poetry','','[]','官家爲是愛斯民，臨遣知州誨爾諄。',32,'全唐诗/poet.song.183000.json','["官家爲是愛斯民，臨遣知州誨爾諄。", "願爾進知庠序教，怕嫌爾做事魔人。"]'),
('74549018-1f64-4774-9f22-9ddec1dd6ef7','寄白雲軒周道正','李兼','宋','宋诗','song-poetry','','[]','自往丹丘去，因循過一年。',48,'全唐诗/poet.song.183000.json','["自往丹丘去，因循過一年。", "孤雲無定止，明月又重圓。", "書尾間相問，琴聲淡悄然。", "何時當會面，吟醉海濤邊。"]'),
('aaafc971-ba95-4da1-a27e-86fa5d9a0f3b','送桑澤卿歸天台','李兼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','野鶴昂然不可羈，伴行雙屐一筇枝。',64,'全唐诗/poet.song.183000.json','["野鶴昂然不可羈，伴行雙屐一筇枝。", "屈公蕭寺三旬客，益我空囊幾卷詩。", "亂帙檢殘燒燭夜，淺杯流向落花時。", "春光只戀西湖好，不念台山老桂枝。"]'),
('7b963335-edf6-41ba-8df9-69238c4fd752','蘭亭題詠  其一','李兼','宋','宋诗','song-poetry','','[]','書法光芒晉永和，後來摹寫不勝多。',32,'全唐诗/poet.song.183000.json','["書法光芒晉永和，後來摹寫不勝多。", "考論又得桑夫子，蘭渚風流轉不磨。"]'),
('44c62e5d-080f-4bd1-a6c0-38828cb6558f','蘭亭題詠  其二','李兼','宋','宋诗','song-poetry','','[]','自從繭紙殉昭陵，定武流傳賸得名。',32,'全唐诗/poet.song.183000.json','["自從繭紙殉昭陵，定武流傳賸得名。", "總輯舊聞爲博議，即今真贋不難憑。"]'),
('37f3b6d6-d9ea-4da3-9443-11f99c55c1d3','寄題愚齋','李兼','宋','宋诗','song-poetry','','[]','巧鬻非善賈，利穫非良農。',72,'全唐诗/poet.song.183000.json','["巧鬻非善賈，利穫非良農。", "君子不自智，甘與庸人同。", "天君見獨者，進退有新功。", "忽斂藝文手，反著懷袖中。", "客問以臆對，此說非易窮。", "吾非甯武子，今學北山翁。"]'),
('216ddfa1-f0f4-43cb-9c56-123c3f77a66a','奉陪攖寧侍郎遊柏山寺謁梅公墓小憩行軒勉酌','李兼','宋','宋诗','song-poetry','','[]','蕭寺倚巖郭，昔遊幾何年。',216,'全唐诗/poet.song.183000.json','["蕭寺倚巖郭，昔遊幾何年。", "茲辰愜幽賞，杖屨從儒先。", "稍穿蒼蘚徑，旋入青蘿烟。", "山色若倒屣，松風自鳴絃。", "目力眩奇觀，步屧信所便。", "俄登旃檀林，金碧耀脩緣。", "道旁老木拱，詩翁久飛仙。", "蟬蛻萬物表，蝶夢三生前。", "至今二百載，相望箕斗懸。", "緬懷文忠公，豐碑泯遺鎸。", "樂善如緇衣，後世兩稱賢。", "山僧矜好事，華表新題璇。", "向來委榛棘，時情任渠遷。", "先生笑撫掌，此事從古然。", "相逢一樽酒，勸君小流連。", "江梅欲浮動，春光向妖妍。", "同遊二三子，舂容有佳篇。", "歸歟不知夜，霜雪凈寒天。"]'),
('2ffa6b79-bb8a-44a3-980b-b8d81a7c9f07','秋扇行','李兼','宋','宋诗','song-poetry','','[]','憶當九夏初，恒御君王手。',56,'全唐诗/poet.song.183000.json','["憶當九夏初，恒御君王手。", "西風颯然至，持用焉能久。", "人情易變如三秋，君恩覆水不可收。", "藉使凉飈奪炎熱，感隕此身終不絕。"]'),
('2b9eedb6-9455-4c2c-9805-951070c545c0','題冀缺圖','李兼','宋','宋诗','song-poetry','','[]','耕夫自立苗且耘，饟婦相敬禮如賓。',130,'全唐诗/poet.song.183000.json','["耕夫自立苗且耘，饟婦相敬禮如賓。", "畫工貌出態閒暇，不是如今愚野人。", "古之農者蓋如此，饁彼公田同婦子。", "山林自信有真樂，隠逸傳中無姓字。", "吾不能走馬章臺街，畫眉狼籍貽譏諧。", "又不能賣酒臨邛市，奔妻萬古不滅恥。", "遺風後世豈無存，半在東阡烟雨村。", "不見杵臼梁家婦，猶能親舉案前餐。"]'),
('e800c4ca-6020-4f2a-818f-b094c80c7128','田里','李兼','宋','宋诗','song-poetry','','[]','百穀盈成後，三秋假樂時。',48,'全唐诗/poet.song.183000.json','["百穀盈成後，三秋假樂時。", "雞豚開社甕，簫鼓賽神祠。", "野茹青盈筥，香炊雪滿匙。", "欲知田里趣，細誦老翁詩。"]'),
('2341ab73-6b64-4a08-9a03-72071839e46b','次韵周與能','李兼','宋','宋诗','song-poetry','','[]','墜緒今如綫，遺書尚滿床。',48,'全唐诗/poet.song.183000.json','["墜緒今如綫，遺書尚滿床。", "功名兩蝸角，世路幾羊腸。", "癖有登山屐，貧無在笥裳。", "故人應見念，莫遣字稀行。"]'),
('c8f27e5e-edfa-4c53-89e6-1ecc532dccd4','莎雞','李兼','宋','宋诗','song-poetry','','[]','悲思亦何苦，繁聲咽未休。',48,'全唐诗/poet.song.183000.json','["悲思亦何苦，繁聲咽未休。", "家庭殘月曙，衰草故園秋。", "物化終歸盡，年華迅若流。", "要當期子夜，相與和商謳。"]'),
('51f29709-6564-45d4-ad2d-3b5bb18696cc','曉出','李兼','宋','宋诗','song-poetry','','[]','凌晨躬蕆事，未曉出城關。',48,'全唐诗/poet.song.183000.json','["凌晨躬蕆事，未曉出城關。", "路暗雞三唱，天青月一彎。", "華香衣笥外，嵐翠竹輿間。", "欲盡清游興，官程索遽還。"]'),
('aa3fbcd6-2876-4251-953d-b7820e82903e','食兔詩','李兼','宋','宋诗','song-poetry','','[]','弱質司明視，虛名直望舒。',48,'全唐诗/poet.song.183000.json','["弱質司明視，虛名直望舒。", "軼迂辭上蔡，能事到中書。", "狡計空多窟，珍盤竟付厨。", "獨將毫末效，曾紀汗青餘。"]'),
('db03e5d8-18eb-420d-abe2-4d0295f00ed8','謝張世顯詩卷','李兼','宋','宋诗','song-poetry','','[]','珍重張公子，交情不我遺。',48,'全唐诗/poet.song.183000.json','["珍重張公子，交情不我遺。", "肯迂林下步，來贄袖中詩。", "江樹煙中色，叢梅雪外枝。", "吟哦清絕句，一一可同時。"]'),
('b3549ff2-b97f-483e-b944-ac661cdf591d','鍾山','李兼','宋','宋诗','song-poetry','','[]','白鳥江天闊，青山佛閣重。',48,'全唐诗/poet.song.183000.json','["白鳥江天闊，青山佛閣重。", "影孤寒日塔，聲殷暮煙鐘。", "異世文中選，當時鏡裏容。", "猶傳遺蛻骨，只在此高峰。"]'),
('904816f9-34d0-4701-9590-e58e7d7de4c2','發于湖','李兼','宋','宋诗','song-poetry','','[]','斷岸收潢潦，蒼烟出翠微。',48,'全唐诗/poet.song.183000.json','["斷岸收潢潦，蒼烟出翠微。", "衆帆爭鵓港，孤塔認梟磯。", "萬事皆前定，重來悟昨非。", "此身縻薄爵，何處避危機。"]'),
('ad08967f-8740-4d5d-955c-3bd4b63b10bb','回次采石','李兼','宋','宋诗','song-poetry','','[]','千帆東下勢連檣，控带河山自一方。',64,'全唐诗/poet.song.183000.json','["千帆東下勢連檣，控带河山自一方。", "塞角凄風營戍遠，野花濕雨墓田荒。", "落霞孤鶩江干闊，去馬來牛歲月長。", "老我聲名無一遂，征衫藍縷鬢蒼蒼。"]'),
('1b6faa9a-4928-4aee-baa5-232b3cd5150e','謝當塗陳舍人饋姑孰春','李兼','宋','宋诗','song-poetry','','[]','門巷春風翳草萊，筆耕無藝甑生埃。',64,'全唐诗/poet.song.183000.json','["門巷春風翳草萊，筆耕無藝甑生埃。", "空成洛下書生詠，敢望青州從事來。", "洗盞首供堂上壽，留尊更待月中開。", "陶然竟墮難名境，疑是凌歊百尺臺。"]'),
('e634f031-1062-4872-9cbd-d58fe7b1f01a','晚春','李兼','宋','宋诗','song-poetry','','[]','筠窗幽獨靜亡鄰，坐睡從吾一欠伸。',64,'全唐诗/poet.song.183000.json','["筠窗幽獨靜亡鄰，坐睡從吾一欠伸。", "綠樹清圓宜靜晝，孤花寂寞照餘春。", "時拈柏子燒銅鼎，旋碾茶團瀹玉塵。", "在昔芻蕘猶足採，獨慙無用養閒身。"]'),
('4088ca13-88af-4432-ab98-1d63bb337922','送交代高丞','李兼','宋','宋诗','song-poetry','','[]','天涯客裏送人歸，恨絕青青楊柳枝。',64,'全唐诗/poet.song.183000.json','["天涯客裏送人歸，恨絕青青楊柳枝。", "細雨杏園摩詰畫，春風花岸少陵詩。", "九天掄擢堪先卜，萬里功名莫後時。", "江上豈無西到鴈，平安數遣故人知。"]'),
('ac62dcba-3bbe-495c-92cf-99d9668169dd','簡丘倅即次韵','李兼','宋','宋诗','song-poetry','','[]','先生志尚直明廬，庀職毋嫌外且疎。',64,'全唐诗/poet.song.183000.json','["先生志尚直明廬，庀職毋嫌外且疎。", "聊向江城紆驥足，行趨禁闥侍鸞輿。", "河陽花樹曾親植，魯相葵根欲盡鋤。", "從此把君詩過目，絕勝厚祿故人書。"]'),
('d9c1dcf5-a9a6-42f4-9a3c-a8962368a689','依韵和吳起季見寄','李兼','宋','宋诗','song-poetry','','[]','騏驥瘦，駑駘肥，不如占我白石磯。',256,'全唐诗/poet.song.183000.json','["騏驥瘦，駑駘肥，不如占我白石磯。", "出無車，食無肉，寧復羨渠黄金屋。", "叔孫禮樂何紛綸，兩生不行豈徒云。", "丈夫結交半天下，幾人沮溺同耕雲。", "捷徑趨榮速如鬼，齷齪豈堪豪右齒。", "虞卿著書託窮愁，仲蔚繞宅蓬蒿秋。", "朅來話舊重携手，往事紛紛集樽酒。", "胸中奇氣耿獨在，匣劍時作蛟龍吼。", "窮亦樂，貧非痡，且復安步行坦途。", "從人嘲笑我非夫，乘流則逝寧須扶。", "亦知落落固難合，焉能鬰鬰屈此乎。", "朝驅車於閬風之顛，夕濟舟於丹水之淵。", "放身物外豈不好，局蹐人間真可憐。", "追若亡，汗漫遊，笑甯子，商聲謳。", "豈曰無衣，與子同裘。", "天地一馬，日月雙輈。", "噫，流光胡可以淹留。"]'),
('d6d0d906-af6b-4435-a739-b20f77a02779','蒹葭','李兼','宋','宋诗','song-poetry','','[]','蒹葭漫漫秋風多，陂池水落枯葦柯。',64,'全唐诗/poet.song.183000.json','["蒹葭漫漫秋風多，陂池水落枯葦柯。", "青山斷處落日下，欵乃一聲漁子歌。", "高秋鱸肥賤如土，換酒村場醉迷路。", "夜深艇子艤前灣，依稀月照蘆花浦。"]'),
('2b25d928-0649-4874-8261-e68ff7e7ee7d','舟中','李兼','宋','宋诗','song-poetry','','[]','昔向畫圖見，今行莽蒼間。',48,'全唐诗/poet.song.183000.json','["昔向畫圖見，今行莽蒼間。", "天連疑有路，湖闊更無山。", "地入番君國，星潛左蠡灣。", "江神相行客，未覺畏途艱。"]'),
('db513239-0322-41c6-b3cb-e4ea747cd8e0','游道宮','李兼','宋','宋诗','song-poetry','','[]','路去叢祠修竹林，插天松檜卧龍吟。',64,'全唐诗/poet.song.183000.json','["路去叢祠修竹林，插天松檜卧龍吟。", "翬飛朱閣闌干外，人在白雲巖竇深。", "落花半逐流水逝，黄鶴一去莫烟沉。", "安得金丹蛻凡骨，一視往昔與來今。"]'),
('03fd2980-4ce1-4259-acae-c1771b443b17','水陽道中','李兼','宋','宋诗','song-poetry','','[]','落日河西岸，春風水北橋。',48,'全唐诗/poet.song.183000.json','["落日河西岸，春風水北橋。", "地迂帆影轉，石出漲痕銷。", "濁釀淋茅滓，頳鱗貫柳條。", "幾年安穩處，纔幸適今朝。"]'),
('53f69043-3106-417f-91f3-c2f4a59fbc60','芳洲','李兼','宋','宋诗','song-poetry','','[]','芳洲日云夕，薄言擷蘭荃。',72,'全唐诗/poet.song.183000.json','["芳洲日云夕，薄言擷蘭荃。", "悠悠無與贈，脈脈空自憐。", "美人洵且都，爲加一笑嫣。", "知己古所重，欲報甘縻捐。", "未省晼晚姿，可復成春妍。", "彼哉爨下桐，猶爲朱絲弦。"]'),
('0d3d3810-641d-43d1-b6c4-981087cf78d4','江上','李兼','宋','宋诗','song-poetry','','[]','晚來艤櫂瀕江側，汀草蘋花間紅碧。',64,'全唐诗/poet.song.183000.json','["晚來艤櫂瀕江側，汀草蘋花間紅碧。", "無聲畫裏更斜陽，匹練光中正秋色。", "雲間落帆繫高樹，烟外牧牛橫短策。", "黄昏漁火亂前村，猶有孤吟未歸客。"]'),
('0c325cca-3f33-47b0-93ec-8979f07b93fa','石子澗','李兼','宋','宋诗','song-poetry','','[]','去郭無多地，肩輿又獨來。',48,'全唐诗/poet.song.183000.json','["去郭無多地，肩輿又獨來。", "青山隨路轉，老樹挾溪迴。", "映水深宜竹，皚林早見梅。", "頗思傾白酒，適意卧青苔。"]'),
('0ec28680-c5d6-4e66-9ad5-6bad25ef06f6','山居苦','李兼','宋','宋诗','song-poetry','','[]','地僻塵心遠，臺高縱目賒。',48,'全唐诗/poet.song.183000.json','["地僻塵心遠，臺高縱目賒。", "鷺明烟際渚，鳥篆雨餘沙。", "橡栗駢秋實，雞冠媚晚花。", "斷無車馬客，來問野人家。"]'),
('d2100011-d045-4961-ac87-44f1452516df','離家','李兼','宋','宋诗','song-poetry','','[]','送者臨門廡，征人暮路歧。',48,'全唐诗/poet.song.183000.json','["送者臨門廡，征人暮路歧。", "翻思津遣後，可奈獨歸時。", "歲旱田疇薄，家貧母子離。", "能忘手中綿，密密綴衣濕。"]'),
('6dc6fc0b-f0a6-4e27-bafc-c7c4e8da8ec8','句','嚴大猷','宋','宋诗','song-poetry','','[]','笏未到身難擊泚，兵如入手易擒吳。',16,'全唐诗/poet.song.183000.json','["笏未到身難擊泚，兵如入手易擒吳。"]'),
('d9c2a410-be48-4426-862c-2534085547a3','縣學秋試','呂祖平','宋','宋诗','song-poetry','','[]','細雨輕寒弄曉晴，紛紛鵠立擁書黌。',64,'全唐诗/poet.song.183000.json','["細雨輕寒弄曉晴，紛紛鵠立擁書黌。", "廣庭賸欲先耆艾，小試聊煩喚弟兄。", "韞櫝此時增玉價，傳家有子勝金籝。", "鷄蟲得失能多少，也聽春蠶葉上聲。"]'),
('10c1c1ea-9f13-4835-8272-1c83492dfabc','句','石東震','宋','宋诗','song-poetry','','[]','門前碧蘸一溪斜，髣髴逃秦處士家。',16,'全唐诗/poet.song.183000.json','["門前碧蘸一溪斜，髣髴逃秦處士家。"]'),
('23f0f76a-dc43-451a-939d-a5a945bc95b3','爛柯山','汪忱','宋','宋诗','song-poetry','','[]','山作危梁千尺橫，一天金泛月波清。',64,'全唐诗/poet.song.183000.json','["山作危梁千尺橫，一天金泛月波清。", "幽禽不復驚棋響，深谷猶能答斧聲。", "塔壞尚餘鴻雁意，井荒誰放轆轤鳴。", "試將比較天台景，只欠璁瓏琪樹英。"]'),
('bc8010df-708b-4c77-b704-df285eec7653','蛻龍洞','陳玨','宋','宋诗','song-poetry','','[]','潛虬成穴古危岑，曾爲編氓霈旱霖。',64,'全唐诗/poet.song.183000.json','["潛虬成穴古危岑，曾爲編氓霈旱霖。", "石怪自留千載跡，泥蟠難駐九天心。", "老松猶學拏雲勢，群籟渾驚動地吟。", "瀟灑禪關連勝概，追遊誰不快煩襟。"]'),
('e3931377-6574-4d14-9508-6f4c449a13c5','垂虹亭','陳玨','宋','宋诗','song-poetry','','[]','高壓玉龍腰，參差雁勢朝。',48,'全唐诗/poet.song.183000.json','["高壓玉龍腰，參差雁勢朝。", "雄吞五湖闊，平揖兩山嶢。", "闌檻中流出，炎蒸白晝消。", "暫來塵慮息，那復日逍遥。"]'),
('b3fefe85-1647-455d-85b4-60cd53db861a','句','陳玨','宋','宋诗','song-poetry','','[]','石洞雲歸春雨足，海門月上夜潮生。',16,'全唐诗/poet.song.183000.json','["石洞雲歸春雨足，海門月上夜潮生。"]'),
('70bb186e-03bf-4c25-9aac-0209e1b35f9c','和劉後村梅花絕句  其一','黄珩','宋','宋诗','song-poetry','','[]','豐鐘逐散曉雲遮，我欲伸冤玉帝家。',32,'全唐诗/poet.song.183000.json','["豐鐘逐散曉雲遮，我欲伸冤玉帝家。", "青女一身都是膽，年年隨下月偷花。"]'),
('4a59c3a7-30f6-4c04-896c-9229a74b4e58','和劉後村梅花絕句  其二','黄珩','宋','宋诗','song-poetry','','[]','一雙白鶴騎焉往，十萬青蚨散即休。',32,'全唐诗/poet.song.183000.json','["一雙白鶴騎焉往，十萬青蚨散即休。", "吟透何郎早春句，輸他占射得揚州。"]'),
('17a4998d-904a-4476-a173-0e76c965f7a5','句','黄珩','宋','宋诗','song-poetry','','[]','真色果無描寫法，漢人枉自殺毛公。',16,'全唐诗/poet.song.183000.json','["真色果無描寫法，漢人枉自殺毛公。"]'),
('b03bb8c6-4f81-4a66-922e-8f97d7050173','伯時番王禮佛圖卷','李簡','宋','宋诗','song-poetry','','[]','佛身充滿大千界，蓮座玄談海水翻。',32,'全唐诗/poet.song.183000.json','["佛身充滿大千界，蓮座玄談海水翻。", "融攝群修證圓覺，靈通虛徹卓然存。"]'),
('f00535e3-dfd2-4ba1-95b5-686da34ba7c5','句  其一','李簡','宋','宋诗','song-poetry','','[]','挹香不盈懷，餐英淡無味。',12,'全唐诗/poet.song.183000.json','["挹香不盈懷，餐英淡無味。"]'),
('2a3c1b47-ec8d-4a6e-827a-33aca1817d5b','句  其二','李簡','宋','宋诗','song-poetry','','[]','向來紅與紫，隨流去如雲。',24,'全唐诗/poet.song.183000.json','["向來紅與紫，隨流去如雲。", "雖有故枝在，花落何紛紛。"]'),
('4b22acb2-ffb0-4bd6-8484-4adcd00f5dfb','譜樂歌','趙由濟','宋','宋诗','song-poetry','','[]','悠悠我祖，始於軒轅。',240,'全唐诗/poet.song.183000.json','["悠悠我祖，始於軒轅。", "既歷高陽，秩秩大猷。", "爰自伯益，舜賜皂斿。", "中衍仕商，造父御周。", "征彼徐方，營營有功。", "邑於趙城，大河之東。", "建仕晉國，耿光其封。", "成宣諭日，畏夏愛冬。", "岸賈作難，嬰臼立孤。", "襄子始大，常山得符。", "於赫烈侯，懋建丕圖。", "肅侯武靈，兆配有虞。", "西漢子都，生長河間。", "暨於唐末，今族居燕。", "卜遷大梁，世系綿綿。", "厚德豐功，宜永其傳。", "中罹多難，西歷江沱。", "眷焉吾族，豐水居多。", "百川有源，衆條有柯。", "庸修家牒，克俾無訛。", "顧及伯仲，憂患更多。", "瞻歎古烈，自憐其生。", "厥生豈偶，三辰垂精。", "德業未進，敢不戰兢。"]'),
('854501ca-db52-4bc6-a0da-fbf4cd5d1820','清明  其一','史達祖','宋','宋诗','song-poetry','','[]','一百六朝花雨過，柳梢猶爾病春寒。',32,'全唐诗/poet.song.183000.json','["一百六朝花雨過，柳梢猶爾病春寒。", "晉官今日炊烟斷，併著新晴看牡丹。"]'),
('5b56da46-920b-4114-a103-fdb726fc9da7','清明  其二','史達祖','宋','宋诗','song-poetry','','[]','宮燭分烟眩曉霞，驚心知又度年華。',32,'全唐诗/poet.song.183000.json','["宮燭分烟眩曉霞，驚心知又度年華。", "榆羹杏粥誰能辦，自採庭前薺菜花。"]'),
('bc44cfd4-0ef5-4f4e-af39-e0c564bc864d','句','史達祖','宋','宋诗','song-poetry','','[]','遺像人猶思後主。',8,'全唐诗/poet.song.183000.json','["遺像人猶思後主。"]'),
('969cb0bb-1d8b-4ef6-a67c-de6c419b627b','皋橋','周文璞','宋','宋诗','song-poetry','','[]','伯鸞出京師，慷慨歌五噫。',144,'全唐诗/poet.song.183000.json','["伯鸞出京師，慷慨歌五噫。", "豈無濟時心，升降與我違。", "有來適吳中，舂粱救寒饑。", "吳人皋伯通，舎之慰窮棲。", "方志雖或除，此橋猶可稽。", "伯鸞號逸民，佳傳照綠綈。", "伯通頼有此，庶幾與之齊。", "至今閶門外，兩冢陪要離。", "累累各高大，冥冥春草萋。", "古者賢哲人，不計鳳與鷄。", "焜耀亦偶爾，埋沒何淒兮。", "出語賀兩公，亦以昌吾詩。"]'),
('5904ac63-8664-48c4-8642-dd73695a4178','堯章金銅佛塔歌','周文璞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','白石招我入書齋，使我速禮金塗塔。',236,'全唐诗/poet.song.183000.json','["白石招我入書齋，使我速禮金塗塔。", "我疑此塔非世有，白石云是錢王禁中物。", "上作如來捨身相，饑鷹餓虎紛相向。", "拈起靈山受記時，龍天帝釋應惆悵。", "形模遠自流沙至，鑄出今回更精緻。", "錢王納土歸京師，流落多在西湖寺。", "錢王本是英雄人，白蓮花現國主身。", "蛇鄉虎落狗脚朕，何如紅袍玉带稱功臣。", "天封坼開即退聽，兩浙不聞笳鼓競。", "歸來佛子作護持，太師尚父尚書令。", "一枚傳到白石生，生今但有能詩聲。", "同袍秦外銛師兄，哦詩禮塔作佛事，同喫地爐山芋羹。", "何曾薰陸綺床供，但見相輪銅綠明。", "哦詩禮塔猶未畢，蘆葉低飛山雨濕。"]'),
('6e66b350-9262-4adf-baa1-2bc2a4d71b18','初至長干寺','周文璞','宋','宋诗','song-poetry','','[]','雲杪熒熒一塔燈，覺皇舎利寶煙凝。',32,'全唐诗/poet.song.183000.json','["雲杪熒熒一塔燈，覺皇舎利寶煙凝。", "山門推上三更月，似照前朝禮拜僧。"]'),
('d7014873-b9a5-420d-942a-639595262548','回次秣陵','周文璞','宋','宋诗','song-poetry','','[]','我行古井邑，北風吹倒人。',72,'全唐诗/poet.song.183000.json','["我行古井邑，北風吹倒人。", "旗店語簇簇，石路聲轔轔。", "下車得少憩，亭午聽司晨。", "豈但田秔香，更覺村醪醇。", "懷哉厭王氣，契闊毋重陳。", "舊爲秣陵尉，今爲鍾山神。"]'),
('67a81650-7da0-40f3-878d-7d3ddeca5e6a','哦松夏夜','周文璞','宋','宋诗','song-poetry','','[]','雅頌聲流到楚詞，更無人見獨看時。',32,'全唐诗/poet.song.183000.json','["雅頌聲流到楚詞，更無人見獨看時。", "池頭五粒初摇動，却替幽人說舊詩。"]'),
('568a899d-0b06-4359-b523-ad157801b5cd','鷓鴣','周文璞','宋','宋诗','song-poetry','','[]','夜聞春雨來，濃綠凈於洗。',156,'全唐诗/poet.song.183000.json','["夜聞春雨來，濃綠凈於洗。", "有禽自南翥，自呼不能已。", "豈非湘川下，或自江左起。", "黄陵見哀妃，白下感遊子。", "仍多憂其兄，宛轉深樹裏。", "汝兄今何在，荆棘日靡靡。", "豈非囚空山，或已投逝水。", "年深桎梏化，波冷皮肉死。", "鷓鴣謹勿痛，此係造物理。", "吾若破析言，汝恨入骨髓。", "風吹慈竹林，苔暈上深紫。", "吾亦念故鄉，日夜夢鄰里。", "不如各歸休，闕月照西鄙。"]'),
('91e0438f-3682-4000-84da-38510e4402b5','懷何月湖','周文璞','宋','宋诗','song-poetry','','[]','星星鬢髮卧林丘，詔使東川作郡侯。',64,'全唐诗/poet.song.183000.json','["星星鬢髮卧林丘，詔使東川作郡侯。", "髯叟望公來海嶠，癭兵迎守去夔州。", "珍圖想掛茅齋壁，巧石應隨竹釘舟。", "教得巴童歌舞好，侍郎千萬却歸休。"]'),
('5619edb7-4b19-4512-bce3-05b5c6f87ec7','瀨上懷古','周文璞','宋','宋诗','song-poetry','','[]','古寺閟岑鬰，空梁懸齋魚。',96,'全唐诗/poet.song.183000.json','["古寺閟岑鬰，空梁懸齋魚。", "神坐既欹仄，德容亦饑虛。", "先生貧有命，山僧樂無餘。", "長安滿市花，匹馬吟九衢。", "寥寥北邙山，而誰噫荒墟。", "豈有先生者，不如山僧歟。", "盲風振苕華，重露落芙蕖。", "何當醉尉歸，方坐釣水隅。"]'),
('2260a73a-8ce9-4d00-a2f6-9f95da8e668a','瀨上貞女祠','周文璞','宋','宋诗','song-poetry','','[]','估客征夫上野橋，錦縭玉瑱亦蕭條。',32,'全唐诗/poet.song.183000.json','["估客征夫上野橋，錦縭玉瑱亦蕭條。", "人間多少乘除事，到了英雄恨不消。"]'),
('73630bd0-3f26-49cf-a028-0db8c0d9568e','銅雀研','周文璞','宋','宋诗','song-poetry','','[]','君王有遺令，婢子守空臺。',132,'全唐诗/poet.song.183000.json','["君王有遺令，婢子守空臺。", "遥望西陵下，漆燈照鴆杯。", "玉顔闕釵澤，松柏生悲哀。", "低吟短歌行，想像姦雄才。", "清泉沈金彩，古煙凝紫灰。", "零落故瓦在，雕鎸若陶坯。", "爲人作書研，詞章出詼諧。", "上下千載間，流轉何悠哉。", "那知墟中人，天命不復來。", "齊昏亦披猖，增三築崔嵬。", "年年漳河頭，野棠如雪開。"]'),
('2c461fe9-815c-4723-9b8d-e448b7e58048','丘慶餘畫兔','周文璞','宋','宋诗','song-poetry','','[]','家住棲賢雲，泉石恣幽討。',84,'全唐诗/poet.song.183000.json','["家住棲賢雲，泉石恣幽討。", "寫出明視孫，眉目增媚好。", "卯日行踆踆，衣褐坐芳草。", "脫身文字禍，見機恨不早。", "仰候月盈縮，脩眉幾回掃。", "迷離望靈藥，青松爲三倒。", "山人書姓名，欲使好事考。"]'),
('be62a7d2-1a3d-4018-9185-acdd221fc9ce','夜坐讀書','周文璞','宋','宋诗','song-poetry','','[]','此生無耽嗜，獨具愛書癖。',108,'全唐诗/poet.song.183000.json','["此生無耽嗜，獨具愛書癖。", "旁搜固未暇，乍見亦畧識。", "塵土苦見汙，更苦官事逼。", "紙燈既自剪，竹牖仍僕織。", "山邑少文獻，有亦何自覓。", "隨行五升瓻，一歲無滴瀝。", "向來長安市，閲之常竟夕。", "悵然夢裏去，莽莽雲雨側。", "哦此謂寒螿，夜漏三十刻。"]'),
('166fd8c6-ed58-4119-a921-ec2adbb35fb6','春雪','周文璞','宋','宋诗','song-poetry','','[]','崇禧仙舘似官居，二月寒風峭有餘。',64,'全唐诗/poet.song.183000.json','["崇禧仙舘似官居，二月寒風峭有餘。", "傲吏吟哦空峭下，野童放散夜堂初。", "熒熒宿火煨村酒，煜煜殘燈鏡道書。", "忽聽打窗聲更急，快移銀礫上枯株。"]'),
('363657e4-1ed9-43b2-aa84-70c38d300c58','鶴廟','周文璞','宋','宋诗','song-poetry','','[]','櫻桃花覆地，古廟自青春。',48,'全唐诗/poet.song.183000.json','["櫻桃花覆地，古廟自青春。", "帳裏還丹使，山中采藥人。", "風林嗥黑虎，雲路列斑麟。", "欲見神君面，連朝禮北辰。"]'),
('c1a7bf11-75ac-44bd-a789-a49a3f4cb9a0','玉晨口占','周文璞','宋','宋诗','song-poetry','','[]','風鳴長史昇天柏，草護仙翁瘞劍塋。',32,'全唐诗/poet.song.183000.json','["風鳴長史昇天柏，草護仙翁瘞劍塋。", "瑞像殿前亡馬跡，養龍池上有鼉鳴。"]'),
('8caf3945-83f8-4ce4-a778-c1ec044f6a73','華道士白胭脂','周文璞','宋','宋诗','song-poetry','','[]','蕭史水銀粉，番女紅藍花。',48,'全唐诗/poet.song.183000.json','["蕭史水銀粉，番女紅藍花。", "狂奴愛風調，脂澤遂成家。", "鏡開青峽月，衣近赤城霞。", "欲下人間世，槲林栖晚鴉。"]'),
('6fbce1b6-d010-41c6-bb78-25bfc7f47dd2','杜鵑花','周文璞','宋','宋诗','song-poetry','','[]','雲樹重重和淚吟，故宮遺廟有知音。',32,'全唐诗/poet.song.183000.json','["雲樹重重和淚吟，故宮遺廟有知音。", "秦吳萬里皆芳草，染到山花恨最深。"]'),
('9c62fef5-3fcb-4d54-bd32-9b1c35408da6','新柳','周文璞','宋','宋诗','song-poetry','','[]','長條導幽情，浄色穿戶牖。',36,'全唐诗/poet.song.183000.json','["長條導幽情，浄色穿戶牖。", "酸風釅如醋，少待濃似酒。", "颭颭金絲垂，滿眼遮老醜。"]'),
('38349e81-1f32-4930-a056-fc499ec1630c','王道士庵','周文璞','宋','宋诗','song-poetry','','[]','出家纔二十，小築契初心。',48,'全唐诗/poet.song.183000.json','["出家纔二十，小築契初心。", "水浸籬根冷，苔封井臼深。", "狖啼天慘慘，犬吠月陰陰。", "又踞藜牀座，焚香鼓內琴。"]'),
('013cf040-a653-466f-a355-27e22eac5b15','南華陽洞','周文璞','宋','宋诗','song-poetry','','[]','稽首遊名山，駕言入華陽。',137,'全唐诗/poet.song.183000.json','["稽首遊名山，駕言入華陽。", "南洞極秘怪，松草泉水香。", "曲几妙隸畫，殘碣刊靈章。", "俛首試一闚，冷風襲綃裳。", "守菴敬愛客，暖我紫朮湯。", "遺我鵝眼錢，云是洞所藏。", "往有尋幽徒，入見黄金牆。", "侈心或已起，幾受奇鬼戕。", "身儻獲會遇，敢恨飛蓬霜。", "更丐一片土，小築安閑房。", "朝披神芝圖，暮試{扟扌=飠}飯方。"]'),
('ce4e80c4-8922-425c-9aee-4953afb4774c','金牛洞','周文璞','宋','宋诗','song-poetry','','[]','凌兢下危梯，俯傴生深穴。',84,'全唐诗/poet.song.183000.json','["凌兢下危梯，俯傴生深穴。", "回身避雲霧，偃面視日月。", "藥苗護谽谺，竹節截㠔嶭。", "安知幽蹊下，有此大奇絕。", "金牛鏟光景，仙牒尚可閲。", "崗頭春已半，枸杞如點血。", "便恐顛風興，橫吹石崖裂。"]'),
('6a1b7280-c883-420e-877f-9f12197052e4','山行行歌十首  其一','周文璞','宋','宋诗','song-poetry','','[]','受籙壇前雲更長，春風漠漠杏花香。',32,'全唐诗/poet.song.183000.json','["受籙壇前雲更長，春風漠漠杏花香。", "峰回路轉無人處，恰見天書字數行。"]'),
('e88a6b4d-37dd-445f-92e5-c8043595f032','山行行歌十首  其二','周文璞','宋','宋诗','song-poetry','','[]','竦楶雕珉萬萬層，雲頭晃晃現觚稜。',32,'全唐诗/poet.song.183000.json','["竦楶雕珉萬萬層，雲頭晃晃現觚稜。", "野人自愛幽深景，只是尋常不見僧。"]'),
('2b89907c-1775-4054-b6bb-62974a475290','山行行歌十首  其三','周文璞','宋','宋诗','song-poetry','','[]','道院中間沐髮容，施來元自贊皇公。',32,'全唐诗/poet.song.183000.json','["道院中間沐髮容，施來元自贊皇公。", "君能百拜香煙下，不怕丹瓊路不通。"]'),
('60c6fe40-6f69-442c-9474-47037db68c39','山行行歌十首  其四','周文璞','宋','宋诗','song-poetry','','[]','蟲蛀黄連徹夜焚，秦謠楚誦少人聞。',32,'全唐诗/poet.song.183000.json','["蟲蛀黄連徹夜焚，秦謠楚誦少人聞。", "近前欲問新宮信，鶴带靈芝入暮雲。"]'),
('b01fa5e8-a400-4b2d-9beb-00efc638766c','山行行歌十首  其五','周文璞','宋','宋诗','song-poetry','','[]','带淺人家隠樹深，嫩晴天色弄雲陰。',32,'全唐诗/poet.song.183000.json','["带淺人家隠樹深，嫩晴天色弄雲陰。", "好風嫋嫋穿林去，吹散松黄似鬰金。"]'),
('54fda7e0-6bc4-4ec1-9667-baab8af5e59c','山行行歌十首  其六','周文璞','宋','宋诗','song-poetry','','[]','遨遊自是不思歸，花氣蒸衣氣力微。',32,'全唐诗/poet.song.183000.json','["遨遊自是不思歸，花氣蒸衣氣力微。", "拋棄文書亡俗累，嶺猿吟後閉山扉。"]'),
('c5de9ddc-d2af-4440-a618-ece37ed05c58','山行行歌十首  其七','周文璞','宋','宋诗','song-poetry','','[]','天風穩送步虛聲，雜和漫山檜柏鳴。',32,'全唐诗/poet.song.183000.json','["天風穩送步虛聲，雜和漫山檜柏鳴。", "遠望山腰多白石，細看知是野人行。"]'),
('425cd3ab-84cc-40b5-8f1d-ead90c940a71','山行行歌十首  其八','周文璞','宋','宋诗','song-poetry','','[]','中峰道士蕊珠丹，曾與神仙玉煉顔。',32,'全唐诗/poet.song.183000.json','["中峰道士蕊珠丹，曾與神仙玉煉顔。", "見說醉來燒隠訣，藥爐蕭瑟卧空山。"]'),
('789a0631-7fd4-4b32-bc6c-9127fc6c968b','山行行歌十首  其九','周文璞','宋','宋诗','song-poetry','','[]','紫陽道院古丹青，恨渠猶畫化胡經。',32,'全唐诗/poet.song.183000.json','["紫陽道院古丹青，恨渠猶畫化胡經。", "晚香滅沒人歸後，自有天風撼玉鈴。"]'),
('18494c29-2c6b-4599-94f8-57a0d4a8e2ec','山行行歌十首  其一○','周文璞','宋','宋诗','song-poetry','','[]','砌穴蕭森隔土橋，項梁城頌最蕭條。',32,'全唐诗/poet.song.183000.json','["砌穴蕭森隔土橋，項梁城頌最蕭條。", "羽衣歌此招魂魄，直送旛旗上九霄。"]'),
('d8eb405f-cd66-4287-a29f-93a939f23483','壬戌春日','周文璞','宋','宋诗','song-poetry','','[]','自從憂患長精神，兀坐齋房過了春。',64,'全唐诗/poet.song.183000.json','["自從憂患長精神，兀坐齋房過了春。", "鑿落盞乾官燭暗，樗蒲齒齔旅囊貧。", "皇天老眼非塵世，白日閑愁自替身。", "一段風光好如畫，未須全與路行人。"]'),
('c0e5f936-3e34-4eb4-b3e7-674254c1bdfb','至荆公墓  其一','周文璞','宋','宋诗','song-poetry','','[]','一丈荒墳上，悠悠落日斜。',24,'全唐诗/poet.song.183000.json','["一丈荒墳上，悠悠落日斜。", "子孫來祭後，守墓掃松花。"]'),
('abd662f3-106b-4509-ab49-41b35be84342','至荆公墓  其二','周文璞','宋','宋诗','song-poetry','','[]','野老從余話，文公在半山。',24,'全唐诗/poet.song.183000.json','["野老從余話，文公在半山。", "蹇馿追不及，落日寺深關。"]'),
('4b24c42b-0ce1-48f2-a13e-28024fec4f1b','至荆公墓  其三','周文璞','宋','宋诗','song-poetry','','[]','年少坐談玄，鍾山直北邊。',24,'全唐诗/poet.song.183000.json','["年少坐談玄，鍾山直北邊。", "春風吹夢過，淚浥舊貂蟬。"]'),
('305d7c69-7408-477f-b64a-8e0f303bd7ca','至荆公墓  其四','周文璞','宋','宋诗','song-poetry','','[]','守法曾丞相，能文陸左丞。',24,'全唐诗/poet.song.183000.json','["守法曾丞相，能文陸左丞。", "風流如未泯，應作寺中僧。"]'),
('96783ed0-3197-42d6-bf0e-8700755c4557','出白下','周文璞','宋','宋诗','song-poetry','','[]','南朝禁籞夕陽明，猶與遊人作隊行。',32,'全唐诗/poet.song.183000.json','["南朝禁籞夕陽明，猶與遊人作隊行。", "煙滿天淵池上路，菜花黄盡綠陰成。"]'),
('b110c5c9-4c73-4c78-a295-abcf0034e5f0','遊栖霞四首  其一','周文璞','宋','宋诗','song-poetry','','[]','破曉逗苦霧，客鼻何酸辛。',132,'全唐诗/poet.song.183000.json','["破曉逗苦霧，客鼻何酸辛。", "山中氣候異，初日如燭銀。", "田間石獸多，知是肉角麟。", "古苔半皴腹，化作蒼龜鱗。", "兩柱既岌嶪，衆碑亦嶙峋。", "幽涂得奇觀，未敢辭埃塵。", "連年抱離憂，百嗟亡一呻。", "花委鬢毛晚，草奪袍色春。", "愁中書櫝失，夢裏歌鍾陳。", "窮愁著文字，屢被同行嗔。", "同行不相知，而况悠悠人。"]'),
('fbebce8b-109a-496c-a46a-f60f6d85b2de','遊栖霞四首  其二','周文璞','宋','宋诗','song-poetry','','[]','吾與空門友，相扶歷芳甸。',84,'全唐诗/poet.song.183000.json','["吾與空門友，相扶歷芳甸。", "天機久深妙，梵本亦貫穿。", "徐馳得幽欣，濟勝愜孤願。", "宿芽發輕苞，寒卉抱短艷。", "鹿走風生林，僧歸雲入殿。", "寺從齊梁來，諸彥題品遍。", "安知千歲後，未歎陵谷變。"]'),
('5828398e-c427-4696-baca-03f49f466455','遊栖霞四首  其三','周文璞','宋','宋诗','song-poetry','','[]','優尼製銅覺，欲住女主齡。',72,'全唐诗/poet.song.183000.json','["優尼製銅覺，欲住女主齡。", "主稱金輪王，錄在華嚴經。", "而捨覺富貴，愛慕塗椒馨。", "月黯回心院，妖魂啼窈冥。", "僧人弗知此，獨受一峰青。", "分減儻及我，終歲棲林坰。"]'),
('9d1035c7-cdfa-4f5f-a66c-cd46e0f3645d','遊栖霞四首  其四','周文璞','宋','宋诗','song-poetry','','[]','府帖昨夕下，許奉半月急。',84,'全唐诗/poet.song.183000.json','["府帖昨夕下，許奉半月急。", "遂作茲山遊，惘怳憂思失。", "古跡墮榛莽，久久失修葺。", "南唐石塔好，巋然對人立。", "高碣纏蛟龍，奇畫耐風日。", "明旦丹陽路，萬感當畢集。", "說似石翁婆，皆須爲余泣。"]'),
('cba0cc15-3b86-42be-a153-887e7dac3663','再如金陵','周文璞','宋','宋诗','song-poetry','','[]','再踏江東路，詞窮不復論。',48,'全唐诗/poet.song.183000.json','["再踏江東路，詞窮不復論。", "江泥沾苦淚，津鼓聚歸魂。", "庾信因愁老，陶潜爲酒存。", "孤蹤雖落魄，不敢望明恩。"]'),
('c3d23f35-613f-4f78-a10f-ddc8f7a96ecd','道中望茅山有感','周文璞','宋','宋诗','song-poetry','','[]','危亭對名岳，畢景扶鈎欄。',216,'全唐诗/poet.song.183000.json','["危亭對名岳，畢景扶鈎欄。", "白鷺伺察過，低昂若弓彎。", "去歲負笈遊，最住元符間。", "櫟林带脩竹，清派流珊珊。", "離留叫晝靜，洞天生春寒。", "偉哉老宗師，作屋雲雨端。", "竟爲殺蟲蟻，不活升龍鸞。", "遺體但解蛻，故宮亦燒殘。", "今創已半舊，萬柱扶玄壇。", "遂以兩不借，一筇履巑岏。", "入宅問玉斧，採芝投金環。", "墨沼篆結字，丹臺氣成盤。", "將謂便隠遁，遽爾罹間關。", "夷甫麈尾墮，荀令香爐閑。", "再獲望奇秀，恍然神觀還。", "如見大仙伯，被髮綠映山。", "兩君控鵠從，俱著漢小冠。", "俗累當復馳，煮藥鼎欲翻。"]'),
('43991197-06c7-4795-9107-5c4fde275586','病起寫懷','周文璞','宋','宋诗','song-poetry','','[]','夕陽蔽天涯，望望不見家。',36,'全唐诗/poet.song.183000.json','["夕陽蔽天涯，望望不見家。", "牛斗象緯微，咄咄空嗟咨。", "此時將細碎，說與枝上花。"]'),
('54a16938-f4f3-4835-a811-9c3efd17c119','送友人入浙','周文璞','宋','宋诗','song-poetry','','[]','小縣登樓上，依稀是去年。',48,'全唐诗/poet.song.183000.json','["小縣登樓上，依稀是去年。", "更闌吹短笛，飲散覓歸韉。", "丹葉標寒渡，黄花羃野田。", "重來吊古地，爲拊石羊肩。"]'),
('61aeff77-3890-470b-bb81-1d053ec3d8a7','轆轤體','周文璞','宋','宋诗','song-poetry','','[]','野人無事時，常誦極玄詩。',48,'全唐诗/poet.song.183000.json','["野人無事時，常誦極玄詩。", "寫遍千山寺，吟行九曲溪。", "誰爲補天手，同是决雲兒。", "欲去無人問，今霄醉似泥。"]'),
('411cc88b-b2eb-4ddd-8437-065be09b1260','金陵懷古六首  其一','周文璞','宋','宋诗','song-poetry','','[]','孫伯陵頭水最悲，蔣侯廟下月來遲。',32,'全唐诗/poet.song.183000.json','["孫伯陵頭水最悲，蔣侯廟下月來遲。", "夜深行客心驚恐，猿掛晉朝楓樹枝。"]'),
('b3f02b45-d6fa-413f-883e-8934943bdf15','金陵懷古六首  其二','周文璞','宋','宋诗','song-poetry','','[]','司馬家兒持酒杯，天星亦下澆崔嵬。',32,'全唐诗/poet.song.183000.json','["司馬家兒持酒杯，天星亦下澆崔嵬。", "當時若便效牛飲，定有孟津師旅來。"]'),
('fc5e34db-1914-4d82-8395-67c2535c59e6','金陵懷古六首  其三','周文璞','宋','宋诗','song-poetry','','[]','愁看幕府夕陽邊，那更雞籠在目前。',32,'全唐诗/poet.song.183000.json','["愁看幕府夕陽邊，那更雞籠在目前。", "跋扈飛揚只如此，登臨那得不酸然。"]'),
('02dad3db-75c4-43bd-9d82-6e99dbeeaa22','金陵懷古六首  其四','周文璞','宋','宋诗','song-poetry','','[]','杳杳舊蹤尋不得，茫茫遺恨有誰窮。',32,'全唐诗/poet.song.183000.json','["杳杳舊蹤尋不得，茫茫遺恨有誰窮。", "長安敗績誰憐汝，灞上收聲未到公。"]'),
('6992fee7-e89d-40c5-aa05-67f58e8198c9','金陵懷古六首  其五','周文璞','宋','宋诗','song-poetry','','[]','琵琶未盡使人嗟，淚洒華林御苑花。',32,'全唐诗/poet.song.183000.json','["琵琶未盡使人嗟，淚洒華林御苑花。", "今日聞韶無處所，雁煙蛩雨屬他家。"]'),
('d09df2c5-0623-4544-a925-d13b1ec47923','金陵懷古六首  其六','周文璞','宋','宋诗','song-poetry','','[]','江水無情碧草春，北朝留住老詞臣。',32,'全唐诗/poet.song.183000.json','["江水無情碧草春，北朝留住老詞臣。", "子規啼向青楓樹，爲爾離鄉去園人。"]'),
('ac6fe198-f33c-4b97-9857-8f76a02e1f28','江南曲四首  其一','周文璞','宋','宋诗','song-poetry','','[]','露下五願秋，雨打三楊愁。',24,'全唐诗/poet.song.183000.json','["露下五願秋，雨打三楊愁。", "齊梁才子多，埋在青山頭。"]'),
('27cbb5aa-bc9b-43ec-bd76-6916a0020634','江南曲四首  其二','周文璞','宋','宋诗','song-poetry','','[]','郎與新歡濃，儂與舊歡熟。',24,'全唐诗/poet.song.183000.json','["郎與新歡濃，儂與舊歡熟。", "懊惱對行人，當爲歌艷曲。"]'),
('e20b9c73-fe63-4647-b1ca-f4851a233c65','江南曲四首  其三','周文璞','宋','宋诗','song-poetry','','[]','孤舘聞啼鶑，日暮脂粉薄。',24,'全唐诗/poet.song.183000.json','["孤舘聞啼鶑，日暮脂粉薄。", "芳醪似泥賤，那得不行樂。"]'),
('e68e7e60-6aaa-4bcf-8a5d-2a50c1747738','江南曲四首  其四','周文璞','宋','宋诗','song-poetry','','[]','雨認巫山氣，江通淫預情。',24,'全唐诗/poet.song.183000.json','["雨認巫山氣，江通淫預情。", "相逢未多時，秋花開古城。"]'),
('baa41250-c72c-479d-aa8b-65c22b882d28','吳中秋日','周文璞','宋','宋诗','song-poetry','','[]','郊原落葉已離離，尚有孤花闖短籬。',64,'全唐诗/poet.song.183000.json','["郊原落葉已離離，尚有孤花闖短籬。", "小醉不成憐病後，苦吟未了說愁時。", "鬭雞走狗爰絲喜，臨水登山宋玉悲。", "豆角已收無別事，待同野老赴襟期。"]'),
('8024e169-c6f8-42e1-9c20-4b3b8820dac3','野薔薇','周文璞','宋','宋诗','song-poetry','','[]','娟娟籬頭花，白白間綠葉。',120,'全唐诗/poet.song.183000.json','["娟娟籬頭花，白白間綠葉。", "明光裁販袴，不掩遊子屧。", "餘春背人去，乞與弄芳蝶。", "感我萬古心，離離不相接。", "我行田野間，落魄何所挾。", "猶能自撐拄，使氣學漢俠。", "悠然芳草畔，見此衣逐妾。", "羅帷未生夢，粉面反成怯。", "幽香薰倒人，山麝火初熁。", "長亭或相思，如見玉蹀躞。"]'),
('3eea7b01-cb0a-410d-a810-8397bc682835','狼山','周文璞','宋','宋诗','song-poetry','','[]','吾母禱於山，生我偃蹇身。',48,'全唐诗/poet.song.183000.json','["吾母禱於山，生我偃蹇身。", "卅八始入寺，所天俱不晨。", "歸人復何之，所願清戰塵。", "勿復論銜鈎，去作瑞世珍。"]'),
('fa225868-10a4-4035-b9a8-36a67a3072ca','烏夜啼','周文璞','宋','宋诗','song-poetry','','[]','何人彈阮咸，故故輕手摘。',288,'全唐诗/poet.song.183000.json','["何人彈阮咸，故故輕手摘。", "彈作烏夜啼，此意我所惻。", "南朝有帝子，作牧號侯伯。", "著身疑嫌間，生意日偪仄。", "愛妾聞啼聲，改鎮頒竹冊。", "或云長安吏，性命在頃刻。", "小婦聞啼聲，赦令敷大澤。", "身雖不肖甚，幼小著蒼幘。", "再轉作縣佐，欲塞父祖責。", "濡墨决疑訟，行朱慰冤魄。", "羣凶見之怒，極意便刳磔。", "首沮隸陽橋，公議亦已格。", "痛掠及庫胥，指作盜錢賊。", "胥既窘椎鑿，手墮面愈黑。", "書款自誣伏，身竟遭刻畫。", "酷毒一如斯，誰謂彼無策。", "謗書入外臺，遂坐使者劾。", "牽連入冶城，五載窮慘礉。", "陳詞叫穹旻，哀慟人叵測。", "若無磊落者，誰肯爲昭白。", "翻思受禍時，何但鎩羽翮。", "愁冤傳里巷，泣涕到臧獲。", "嫠母偕妻孥，惘惘望秋色。", "豈料今日下，置酒設豚拍。"]'),
('35bbfd4a-4c8f-4c15-869b-49ffdbc73db2','贈趙子野歌','周文璞','宋','宋诗','song-poetry','','[]','與君雖爲外兄弟，語話尋常見肝肺。',160,'全唐诗/poet.song.183000.json','["與君雖爲外兄弟，語話尋常見肝肺。", "自從不見半年餘，每望吳雲輒流涕。", "蘋溪松江同一波，半年不見當奈何。", "長安市上相就處，弟能起舞兄能歌。", "兄今賜第南薰殿，滿戴宮花上林宴。", "弟歸便著墮遊冠，他時山中儻相見。", "吳王臺畔楊柳黄，吳姬對坐調絲簧。", "阿兄自對吳雲坐，呼弟不來應斷腸。", "書來不應寄他物，只要秋林一雙笛。", "當使蠻奴月下吹，此時此夜須相憶。"]'),
('6f67f42d-0144-402b-bc56-1fa05f8886c5','古琴歌','周文璞','宋','宋诗','song-poetry','','[]','山人袖携古琴來，形模拙醜腹破穿。',160,'全唐诗/poet.song.183000.json','["山人袖携古琴來，形模拙醜腹破穿。", "上兩金字亦殘漫，自云得自十年前。", "十年前宿野店間，野店岑寂無炊煙。", "只將百錢乞翁媼，回買濕薪煨澗泉。", "老翁持出一木段，刀痕鑿痕斧痕滿。", "秀才望見三嘆羨，學琴以後何曾見。", "此是成都雷氏爲，揩摩雷字分明現。", "持歸修治調曲成，曲成他人不肯聞。", "初彈羑里可釋憾，再鼓廣陵如雪冤。", "將歸古操次第傳，龍入我舟何可憐。"]'),
('ef5a0741-944d-41c2-b5fa-6212674d4b88','憶昔','周文璞','宋','宋诗','song-poetry','','[]','憶昔在童初，身輕俗累無。',144,'全唐诗/poet.song.183000.json','["憶昔在童初，身輕俗累無。", "雲霞明道服，日月綴僊都。", "屑玉三危露，泥金一丈符。", "遨遊即閶闔，佩带或昆吾。", "學語闚真誥，談玄校易圖。", "竹間時搏拊，松下亦樗蒲。", "謫墮歸巖壑，庸凡近僕奴。", "極知方匿景，何敢遽摶扶。", "請命書盈紙，祈真淚迸珠。", "但能覘帝座，不恨守天厨。", "譴巨知難逭，心安敢自誣。", "相隨有芒屨，還欲化雙鳬。"]'),
('b4c3eb01-38a6-4787-96a6-c0fb6e1f6212','吊堯章','周文璞','宋','宋诗','song-poetry','','[]','相逢蕭寺已纍然，自詠離騷講太玄。',64,'全唐诗/poet.song.183000.json','["相逢蕭寺已纍然，自詠離騷講太玄。", "極目舊遊猶白石，傷心孤塚只蒼煙。", "兒從外舍收殘稿，客向空山泣斷絃。", "帝所修文與張樂，魂兮應是到鈞天。"]'),
('7f5c9de4-ff68-4314-ada9-0a496b4f0674','遣興','周文璞','宋','宋诗','song-poetry','','[]','望見山櫻媚短岑，翻然便悔出家林。',64,'全唐诗/poet.song.183000.json','["望見山櫻媚短岑，翻然便悔出家林。", "壞車殺馬空嗟晚，裂芰焚荷直到今。", "筍蕨久爲歸去計，雲煙無復舊來心。", "平生最愛花濃淡，看了斜陽看暝陰。"]'),
('5946d759-55e5-4c75-a877-7b7036e4d1ac','夜歸','周文璞','宋','宋诗','song-poetry','','[]','還山迫暮夜，枕石吟下眠。',48,'全唐诗/poet.song.183000.json','["還山迫暮夜，枕石吟下眠。", "夢作童子日，采花弄寒泉。", "回身在人世，欲去塵網纏。", "永謝歡樂情，把袂入紫煙。"]'),
('ed2bf738-41d1-4721-96e2-0f6ebd8299c7','送道友歸','周文璞','宋','宋诗','song-poetry','','[]','浮雲起足下，是子欲歸家。',48,'全唐诗/poet.song.183000.json','["浮雲起足下，是子欲歸家。", "藏室收芸蠹，丹房掃箭砂。", "時聞搗藥鳥，啼向款冬花。", "莫使山童去，驚飛逐亂鴉。"]'),
('1c465419-446c-4512-8cb1-56f949433115','黄龍洞','周文璞','宋','宋诗','song-poetry','','[]','一從負圖與負舟，天公閟之居靈湫。',64,'全唐诗/poet.song.183000.json','["一從負圖與負舟，天公閟之居靈湫。", "重瞳胼手久不作，蒼苔古木兩漠漠。", "朝來石磴鱗鱗濕，如覺蜿蜒爲人出。", "甘霖未甦焦卷多，相候吳雲莫相失。"]'),
('bfca4f53-abb8-41ba-98c2-e4de4f8a901b','歸憩仁王寺','周文璞','宋','宋诗','song-poetry','','[]','重到招提未覺遲，鉢單初副袷衣時。',64,'全唐诗/poet.song.183000.json','["重到招提未覺遲，鉢單初副袷衣時。", "僧房齋院門門閉，梅子枇杷樹樹垂。", "蟻蔭經幢求託化，龍纏佛座學慈悲。", "長年無事閑來此，坐對空山諷小詩。"]'),
('1ce1c8a8-ba9c-416e-8464-32e24356458d','下竺','周文璞','宋','宋诗','song-poetry','','[]','靜看唐人刻，相連坐石陰。',48,'全唐诗/poet.song.183000.json','["靜看唐人刻，相連坐石陰。", "鳥啼留客意，果熟住山心。", "野水流詩葉，天香襲道林。", "雲根有桂子，應待月中尋。"]'),
('c0ef4cde-9991-4798-b50c-508e7a6b0b02','七言','周文璞','宋','宋诗','song-poetry','','[]','雲竺前頭即御園，小風斜雨入梅天。',64,'全唐诗/poet.song.183000.json','["雲竺前頭即御園，小風斜雨入梅天。", "放歌偃蹇如圓澤，古貌昂藏若稚川。", "尋得數行天寶字，破他一夜草堂眠。", "此生更要窮經論，惆悵高人舊石筵。"]'),
('da6e966b-60ea-4d6c-bffd-b95395005fe3','過葛天民新居','周文璞','宋','宋诗','song-poetry','','[]','爲憶空山雨，因嗟短鬢霜。',144,'全唐诗/poet.song.183000.json','["爲憶空山雨，因嗟短鬢霜。", "幅巾終日仄，侍女古時妝。", "烏臼殘林外，丹砂舊井旁。", "不留禪月畫，只踞凈名床。", "湖鏡秋容淡，雲莊曉露香。", "汲泉須透脈，種果便成行。", "使鶴過村店，携孥上野航。", "極知秦外叟，全似賀知章。", "對佛稱居士，翻經悟法王。", "自將詩檢校，猶與竹商量。", "嗟我渾無頼，非公不作狂。", "莫移松下石，老子要乘凉。"]'),
('9e3ccc69-69b2-4945-b91b-6b878de3da6d','十月過鳳山舟回入項王祠用前韵','周文璞','宋','宋诗','song-poetry','','[]','墜葉濃於染，孤花凈似霜。',144,'全唐诗/poet.song.183000.json','["墜葉濃於染，孤花凈似霜。", "溪山如有待，朱粉玄施妝。", "勝境如天上，雄鳴自帝旁。", "工陳白玉琯，人坐紫金床。", "古兕稱春酒，靈虬換夕香。", "風箏猶有韵，星弁忽分行。", "念此鋤榛壟，頻來渡葦航。", "欲揮終極淚，只廢苦吟章。", "慨慷辭歡伯，英雄憶憤王。", "逝騅嗟弗及，撞斗恨難量。", "起舞何勞短，行歌未要狂。", "斷雲將落日，千古助哀凉。"]'),
('ab1b7409-8f39-46d5-85e6-fa259090e492','送蜀客','周文璞','宋','宋诗','song-poetry','','[]','都市今重到，文園更倦遊。',288,'全唐诗/poet.song.183000.json','["都市今重到，文園更倦遊。", "依依返窮峽，得得上歸舟。", "往事深能憶，沈痾久合瘳。", "行經古祠廟，應酹舊山丘。", "梁甫遺馨在，降牋殺氣浮。", "白衣猶肯出，黄裏不包羞。", "一聽巴人曲，多貽漢璽憂。", "花蒙塵漠漠，苑抱水悠悠。", "蠢爾狂童輩，俱爲滅族囚。", "坤維元自正，棧閣未應修。", "管樂誰能並，卿雲亦可儔。", "時哉著檮杌，聊以畔牢愁。", "硉矹重開險，銷沉萬壘秋。", "堂留石室畫，歌尚竹枝謳。", "寒蚻催逋客，啼鵑識故侯。", "屈沱嘗角黍，岷嶺看牽牛。", "從此多談讌，逢誰共勸酬。", "近前持硯削，成列抱箜篌。", "近歲安樞相，宣威在益州。", "君歸如訪謁，朝論必咨諏。", "列聖方垂統，羣公亦好脩。", "焚燒已郿塢，誅殛到讙兜。", "虎豹參差束，魑魖次第投。", "衣冠通海嶠，干羽格蠻陬。"]'),
('eb3b0942-9086-4408-91f6-6409d1934a2c','戊辰感事二首  其一','周文璞','宋','宋诗','song-poetry','','[]','久要和平福，須寬次第刑。',72,'全唐诗/poet.song.183000.json','["久要和平福，須寬次第刑。", "諸公善調壹，熙祚必清寧。", "夾道焚香拜，今知病酒醒。", "謾勞雙鬢白，何止故山青。", "妖緯朝沉彩，非煙夜透扃。", "願同臧獲列，齊壽八千齡。"]'),
('8857841a-cd15-4953-a63c-6b266fe69008','戊辰感事二首  其二','周文璞','宋','宋诗','song-poetry','','[]','幕府才方盛，軍師意最高。',72,'全唐诗/poet.song.183000.json','["幕府才方盛，軍師意最高。", "何年燕巢木，幾處馬騰槽。", "馳騁心方壯，指麾身更勞。", "周詩歌勞徠，費誓說逋逃。", "行闕占風角，穹廬拜羽旄。", "飛騰真有種，淡泊正相遭。"]'),
('27f0565c-84c6-4172-977c-694230ef3ce7','山居書事','周文璞','宋','宋诗','song-poetry','','[]','荼䕷架倒無人架，全似老夫狂醉時。',32,'全唐诗/poet.song.183000.json','["荼䕷架倒無人架，全似老夫狂醉時。", "昨夜一場溪雨橫，又漂苔蘚到花枝。"]'),
('19689ee5-0564-40ae-b4d2-cb1ae5e202b5','遊洞霄','周文璞','宋','宋诗','song-poetry','','[]','天柱青峩峩，石筍危不墮。',132,'全唐诗/poet.song.183000.json','["天柱青峩峩，石筍危不墮。", "晃晃銀雲收，誰子開玉鎖。", "崩騰放閘水，煜爚入洞火。", "神境偕靈休，乃欲搜碎瑣。", "媿彼朽濁顔，一得在無我。", "致彼老鑄凝，披褐迎路左。", "願留護銀鐺，被葉盤礴裸。", "玉𥫽付九虎，遊宴升嶪峨。", "爲言子速去，勤苦悔坎軻。", "反樸招太和，當免運劫禍。", "慟哭出青松，殘齡其或可。"]'),
('d359df21-1726-48e1-b741-9ad8e0f8d72f','題喻玉泉家亦可樂亭','周文璞','宋','宋诗','song-poetry','','[]','先生亭非伯夷築，亭柱亦用秋山竹。',128,'全唐诗/poet.song.183000.json','["先生亭非伯夷築，亭柱亦用秋山竹。", "但令家有滿架書，何慮妻兒少饘粥。", "朝來相對亭上賓，洙泗尺度羲皇人。", "先生已死名不泯，常與此亭作標準。", "後來鄰觸閼伯怒，僕夫預起池魚慮。", "拆亭拆亭先拆柱，有孫抱柱出煙去。", "三十年餘復改觀，有孫如此不待贊。", "似魯靈光偶不全，令人見此空三嘆。"]'),
('c52df74f-c684-4cd7-86b1-94c00195c0ff','病後','周文璞','宋','宋诗','song-poetry','','[]','風燈露水兩茫然，莫爲歡華少壯年。',64,'全唐诗/poet.song.183000.json','["風燈露水兩茫然，莫爲歡華少壯年。", "無病更須求藥物，愛閑猶要覓緡錢。", "此生身世揶揄裏，末路光陰泣涕前。", "快出囊中餐玉法，白雲深處日高眠。"]'),
('354cbfd4-88fc-4417-a284-ef3d3d26baa3','上冢','周文璞','宋','宋诗','song-poetry','','[]','蒸魚燔肉當好羞，北面百拜如有求。',64,'全唐诗/poet.song.183000.json','["蒸魚燔肉當好羞，北面百拜如有求。", "願身長健兒孫好，歲歲此日燒松楸。", "紙錢灰盡淚不盡，孤也雖在猶拘幽。", "沄沄金蓋山下水，相送直過龍灣頭。"]'),
('6dd30305-f722-420d-9819-5bf06af36184','送人歸苕溪','周文璞','宋','宋诗','song-poetry','','[]','憤王祠廟桃花下，愁苦看春又隔年。',32,'全唐诗/poet.song.183000.json','["憤王祠廟桃花下，愁苦看春又隔年。", "今夜白蘋風更惡，去時須傍采菱船。"]'),
('ef8ff913-e4ab-4358-9e33-c81b8b5e0afa','歐陽琴歌','周文璞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','嗚呼箇是文忠琴，嗚呼此琴今尚存。',224,'全唐诗/poet.song.183000.json','["嗚呼箇是文忠琴，嗚呼此琴今尚存。", "堂中圖書散失盡，留得七絃傳子孫。", "六言自書書在腹，古錦梅花留不得。", "嗣孫賢者能忍貧，不向豪家博珠玉。", "初鼓如撼昭陵松，鞏原流水青溶溶。", "三宗龍衮在帝左，曾把鈞天賜與公。", "再鼓似播清潁水，只將漱流肯洗耳。", "曾蘇兩生招不來，自寫新聲付兒子。", "堯囚山，舜放野，自茲以下不平苦。", "與君所得婦女謗，此日一洗清萬古。", "小儒昔誦五季傳，頗訝春秋體微變。", "今來再聽七絃琴，南薰遺製喜復見。", "浮雲流盡白日逃，何用廣陵與離騷。", "譜成只度歐家曲，秋聲賦共廬山高。"]'),
('05d312be-39ec-44a3-adf2-93ac91697bf7','歸姑蘇','周文璞','宋','宋诗','song-poetry','','[]','舊巢已是別人門，梅自蕭疏柳自昏。',64,'全唐诗/poet.song.183000.json','["舊巢已是別人門，梅自蕭疏柳自昏。", "河北謗來須混俗，江東讞就欲招魂。", "故王未納耶溪女，越相先尋澤國村。", "懷古感今吟不盡，一雙清淚落醨樽。"]'),
('139025c1-a8ef-49c0-8c52-8e88ef32c588','晨起','周文璞','宋','宋诗','song-poetry','','[]','閉門不與俗人交，玄晏春秋日日抄。',32,'全唐诗/poet.song.183000.json','["閉門不與俗人交，玄晏春秋日日抄。", "清曉偶然隨鶴出，野風吹折白櫻桃。"]'),
('be658d55-8384-4d2f-a163-d2eef7905570','磵上小飲','周文璞','宋','宋诗','song-poetry','','[]','方坐愛蠲潔，俯窺爲回縈。',48,'全唐诗/poet.song.183000.json','["方坐愛蠲潔，俯窺爲回縈。", "汲汲雨露澤，悠悠江海情。", "引之灌蔬圃，亦足發光晶。", "陶然未須去，於焉潜我名。"]'),
('12f34018-cb16-4319-af66-21ac7f7e46f9','送道人歸華陽','周文璞','宋','宋诗','song-poetry','','[]','山中無酒禁，戶戶有松醪。',48,'全唐诗/poet.song.183000.json','["山中無酒禁，戶戶有松醪。", "旋汲泉炊飯，多挑筍助庖。", "天燈將出現，野月未能高。", "憶我初遊日，先將石洞敲。"]'),
('9f6c70da-2ce7-49ad-af2e-0d8ba1b4968c','寄茅山道友三絕  其一','周文璞','宋','宋诗','song-poetry','','[]','伏事三茅過一生，癡心不望羽車迎。',32,'全唐诗/poet.song.183000.json','["伏事三茅過一生，癡心不望羽車迎。", "舊時手種黄龍子，今解升雲入太清。"]'),
('96178ed0-d493-442d-8dc7-5fcc5c9f65d6','寄茅山道友三絕  其二','周文璞','宋','宋诗','song-poetry','','[]','九錫碑亭日欲曛，有人趺坐對爐薰。',32,'全唐诗/poet.song.183000.json','["九錫碑亭日欲曛，有人趺坐對爐薰。", "憑誰傳語桓司馬，句曲山中只白雲。"]'),
('b80b3112-f19f-44fb-9d54-1fc254ab4464','寄茅山道友三絕  其三','周文璞','宋','宋诗','song-poetry','','[]','蕊珠宮女傍瑶屏，自把韋編問姓名。',32,'全唐诗/poet.song.183000.json','["蕊珠宮女傍瑶屏，自把韋編問姓名。", "回到人間無一事，紫陽花下白鷄鳴。"]'),
('a0f515ff-5ddf-4194-bb6b-d914c97c6046','秋日孤山道院','周文璞','宋','宋诗','song-poetry','','[]','孤山有何好，脩竹隠樓居。',48,'全唐诗/poet.song.183000.json','["孤山有何好，脩竹隠樓居。", "人在秋雲杪，香凝午醮餘。", "芳林多落果，靈沼少驚魚。", "歸棹聞歌詠，猶如學步虛。"]'),
('323b89e5-6069-4760-9934-67fa0696806e','寄韓澗泉','周文璞','宋','宋诗','song-poetry','','[]','窮冬孤陋只書癡，肯爲凶荒强忍饑。',64,'全唐诗/poet.song.183000.json','["窮冬孤陋只書癡，肯爲凶荒强忍饑。", "師友淵源似公者，輿臺貧賤亦安之。", "人來山縣猶須債，雨映茅簷但要詩。", "欲詣樓居無逸步，要從老手化神奇。"]'),
('37204860-366a-4343-89ab-ace19538f2a1','訪梅二首  其一','周文璞','宋','宋诗','song-poetry','','[]','起看重霧白漫漫，畧見春風在樹間。',32,'全唐诗/poet.song.183000.json','["起看重霧白漫漫，畧見春風在樹間。", "傍水出籬猶未快，淡煙微雨又青山。"]'),
('234a8a26-3dfe-4026-a76f-3e7b54e99d97','訪梅二首  其二','周文璞','宋','宋诗','song-poetry','','[]','幽花墮在石根傍，幾欲移將近草堂。',32,'全唐诗/poet.song.183000.json','["幽花墮在石根傍，幾欲移將近草堂。", "草草一尊聊爾爾，跨馿歸去月荒凉。"]'),
('2debfa73-b6b2-4c6b-a829-6b239fcc2758','呈鞏睡翁','周文璞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','家本汶陽縣，累世事耕蠶。',120,'全唐诗/poet.song.183000.json','["家本汶陽縣，累世事耕蠶。", "室廬既焚蕩，飄零住江潭。", "幼及識故老，頗聞鄉里談。", "最盛陽和時，梨杏春酣酣。", "岱宗富栝柏，孔林存欃檀。", "鄉閭鼎其中，實號玉檐檐。", "去年拜睡翁，知是山堂孫。", "淵流京洛舊，尺度歐梅間。", "昨夢返故里，有翁作司南。", "俚語馳寄之，何以鎸冥頑。"]'),
('a6ebc9b9-77d0-41dc-bc5a-d382cc974c6a','石林','周文璞','宋','宋诗','song-poetry','','[]','蒼蒼一林石，零散少存者。',84,'全唐诗/poet.song.183000.json','["蒼蒼一林石，零散少存者。", "分携多子孫，不勝落田野。", "虛堂有天就，乃在絕壁下。", "存者寧非真，散者亦已假。", "相君久藏山，遠客初繫馬。", "幽玩埋莓苔，孤嘀坐梧檟。", "方咏茲游清，未敢泥風雅。"]'),
('edf989bc-4880-4a79-8151-caeb882b44df','絕句四首  其一','周文璞','宋','宋诗','song-poetry','','[]','巾車初扣槿花籬，物物來前總要詩。',32,'全唐诗/poet.song.183000.json','["巾車初扣槿花籬，物物來前總要詩。", "一句坐來模寫了，雨鳩飛下老梅枝。"]'),
('d05d0696-7d45-4584-a947-f44f950c1290','絕句四首  其二','周文璞','宋','宋诗','song-poetry','','[]','紗籠解散坐門畿，生怕逢人索接籬。',32,'全唐诗/poet.song.183000.json','["紗籠解散坐門畿，生怕逢人索接籬。", "朝雨灑來山更凈，舂鋤恰好到方池。"]'),
('4d1d6ef5-b541-478f-a606-f2dceb955568','絕句四首  其三','周文璞','宋','宋诗','song-poetry','','[]','解呼威羽歸丹穴，可縛單于獻漢宮。',32,'全唐诗/poet.song.183000.json','["解呼威羽歸丹穴，可縛單于獻漢宮。", "四面八方籠不住，許來分坐此山中。"]'),
('c1b04c6e-efb4-4ca7-b3b7-c54d0c520d5a','絕句四首  其四','周文璞','宋','宋诗','song-poetry','','[]','隔林八十厖眉叟，理竹疏泉過一生。',32,'全唐诗/poet.song.183000.json','["隔林八十厖眉叟，理竹疏泉過一生。", "見說石林身健日，把書只在石中行。"]'),
('724c6758-c5d8-4e6d-9672-d83c6c13687e','客中','周文璞','宋','宋诗','song-poetry','','[]','客中時序又怱怱，孤坐初春小雨中。',32,'全唐诗/poet.song.183000.json','["客中時序又怱怱，孤坐初春小雨中。", "弄水攀松去年事，令人憶殺洞霄宮。"]'),
('3c02c988-8351-4adb-b297-810fcbfe14f9','山樂官','周文璞','宋','宋诗','song-poetry','','[]','山樂官，爾誰魂，逃河入海俱奔奔，伶倫梨園何可論。',45,'全唐诗/poet.song.183000.json','["山樂官，爾誰魂，逃河入海俱奔奔，伶倫梨園何可論。", "山樂官，予欲爾兮無言。", "如有言，爲余歌雲門。"]'),
('26d4a378-a37d-469b-9e07-f59ad7940229','鳥媒','周文璞','宋','宋诗','song-poetry','','[]','一自弋者篡，冥飛亦云多。',36,'全唐诗/poet.song.183000.json','["一自弋者篡，冥飛亦云多。", "庖犧網未收，同類如予何。", "已噤伐斧篇，去去依女蘿。"]'),
('f4522034-92c8-4d2f-bfef-ed1a30e24c16','和澗泉賦山楹','周文璞','宋','宋诗','song-poetry','','[]','共惟古至人，用意事物表。',84,'全唐诗/poet.song.183000.json','["共惟古至人，用意事物表。", "一丘謾摧殘，八極自圍繞。", "不勞日月運，坐見歲時了。", "魯夢久不作，楚賦那遽曉。", "既煩匠氏來，誰謂此山小。", "雲衣方紛敷，雪幹復夭矯。", "沐浴抱歸藏，樂甚憂悄悄。"]'),
('b2a45fe7-4b75-4534-94b4-40954329b775','重經洞霄','周文璞','宋','宋诗','song-poetry','','[]','曩既負幽討，今敢萌遐心。',96,'全唐诗/poet.song.183000.json','["曩既負幽討，今敢萌遐心。", "扶桑下陽馭，砮磬浮空林。", "瓊臺渺詄蕩，蕊珮棲高深。", "屢見仙驥舞，遥聆玄女吟。", "如遂覩開闢，那復憂崎嶔。", "抱關職貴重，啟閉非所任。", "靈飈掣虬戶，同此琅琅音。", "願併翠綃水，寫之朱絲琴。"]'),
('e6e2da0b-d00f-4fe1-b5c6-8ecfdf25c3ef','大滌洞','周文璞','宋','宋诗','song-poetry','','[]','嵌空纔入泉潏潏，隔凡倒懸若錐立。',32,'全唐诗/poet.song.183000.json','["嵌空纔入泉潏潏，隔凡倒懸若錐立。", "道士云是閭丘公，入向華陽便門出。"]'),
('d2db5392-4a8a-482f-bf1f-9564cf05987b','岸幘','周文璞','宋','宋诗','song-poetry','','[]','岸幘坐亭皋，休嗟命不遭。',48,'全唐诗/poet.song.183000.json','["岸幘坐亭皋，休嗟命不遭。", "通幽文似呪，招隠句如騷。", "日下桃花熱，風低鶴背高。", "真遊窮不盡，只是酌芳醪。"]'),
('a656221f-8905-40fe-8a09-eab1c0ca2c49','翠蛟亭','周文璞','宋','宋诗','song-poetry','','[]','禹驅龍蛇不驅蛟，依然跧此山之坳。',48,'全唐诗/poet.song.183000.json','["禹驅龍蛇不驅蛟，依然跧此山之坳。", "有時淵停忽奔放，如負山走如玉跑。", "昔時莘渭正如此，咨爾來者無空嘲。"]'),
('933a21a0-2f76-4a1b-85bf-763de3d93dd6','寄題館娃即靈巖寺','周文璞','宋','宋诗','song-poetry','','[]','突兀僧藍是舘娃，屧廊猶自隠晴霞。',64,'全唐诗/poet.song.183000.json','["突兀僧藍是舘娃，屧廊猶自隠晴霞。", "清明但長離宮草，精魄應棲野寺花。", "白苧黄蕉迷鶴市，紫蘭綠芷屬漁家。", "思量種蠡成何事，空使君王式怒蛙。"]'),
('c369e1fb-2e43-485c-93af-c5cc5848e448','小寒食','周文璞','宋','宋诗','song-poetry','','[]','從來寒食多風雨，不料窮鄉亦管弦。',64,'全唐诗/poet.song.183000.json','["從來寒食多風雨，不料窮鄉亦管弦。", "壯歲心情悲昨夢，異鄉時序感流年。", "偶隨遊子來溪上，因與棠梨立路邊。", "從此堪悲轉憔悴，隨羣同上釣魚船。"]'),
('0db80515-51af-4e94-9791-3f929696956f','五月五日至京口','周文璞','宋','宋诗','song-poetry','','[]','回回望秦淮，出語重煩喋。',156,'全唐诗/poet.song.183000.json','["回回望秦淮，出語重煩喋。", "凱風初酸辛，靈雨更淒切。", "疇昔之所經，望見心已折。", "粵從世態換，轉見凡事別。", "緡錢換仍艱，旅飯雜砂屑。", "坊市半頹毀，物貨僅羅列。", "鳴鳳斯不聞，遺沴猶慘烈。", "凌晨轉時序，涂路已入浙。", "京清雖快人，忍作昌歜節。", "身本無瑕疵，反被讒口諜。", "低翔就師友，庶幾免磨滅。", "清曠雖未能，玄暢差可悅。", "如其守微言，予將俟來哲。"]'),
('90a5e342-83a7-4e48-9f18-a14118a956ae','贈蘇召叟','周文璞','宋','宋诗','song-poetry','','[]','句容縣古寺，壁有道玄筆。',168,'全唐诗/poet.song.183000.json','["句容縣古寺，壁有道玄筆。", "晃晃纓絡軀，渺渺煙霧質。", "一堵最光怪，朱泥久堙鬰。", "泥去墨亦盡，慘淡意都失。", "恨不還其人，加巾急鞭抶。", "毀棄加弗敬，請論如漢律。", "羅漢院塔影，顛倒難致詰。", "稗書誌海翻，此理殊未必。", "今君所歸路，正向此中出。", "况有吊古才，仰天痛呼屈。", "勿稱荒唐言，析理資按述。", "其餘傳播詠，淋漓滿箱帙。", "棲霞者悲壯，茅洞者清逸。", "珍題倘相命，當第爲甲乙。"]'),
('53d60762-919f-4bc1-a014-de1f7d5890e5','半山寺','周文璞','宋','宋诗','song-poetry','','[]','野芳汀芷互幽妍，相國風流亦未傳。',32,'全唐诗/poet.song.183000.json','["野芳汀芷互幽妍，相國風流亦未傳。", "衮冕塵埃半山寺，自相撐拄過年年。"]'),
('4e941bf9-9c0b-4223-9485-c73f418f4c64','跋鍾山賦二首  其一','周文璞','宋','宋诗','song-poetry','','[]','丁年寫了鍾山賦，舉向禪宮入定僧。',32,'全唐诗/poet.song.183000.json','["丁年寫了鍾山賦，舉向禪宮入定僧。", "僧却爲余言未好，扶行同謁晉諸陵。"]'),
('c378dad9-b7e1-48ed-9c51-32d1937f2405','跋鍾山賦二首  其二','周文璞','宋','宋诗','song-poetry','','[]','往在秦淮問六朝，江樓祇有女吹簫。',32,'全唐诗/poet.song.183000.json','["往在秦淮問六朝，江樓祇有女吹簫。", "昭陽太極無行路，歲歲鵝黄上柳條。"]'),
('8053a6b0-d0dc-450d-a4fc-77532d3e26a9','過鳳山有感二首  其一','周文璞','宋','宋诗','song-poetry','','[]','當年準擬作家林，溪墅樓居意已深。',64,'全唐诗/poet.song.183000.json','["當年準擬作家林，溪墅樓居意已深。", "隠者自應尋別業，鳳兮何肯負初心。", "參差一段囊中玉，激烈三更月下吟。", "若不速來相就飲，定應從此失知音。"]'),
('6973e6da-caaf-48ce-827d-d91b477e9186','過鳳山有感二首  其二','周文璞','宋','宋诗','song-poetry','','[]','秋蕪闕是草堂基，惟有南鄰盡得知。',64,'全唐诗/poet.song.183000.json','["秋蕪闕是草堂基，惟有南鄰盡得知。", "辛苦置家將守冢，告求廣地要穿池。", "浄蓮已付鄉僧掘，慈竹從教墓客移。", "雖向龍灣作耆舊，此生寧沒暫來時。"]'),
('6d03ac5d-e81e-4ad4-aa1c-f68f14af22de','絕句二首  其一','周文璞','宋','宋诗','song-poetry','','[]','皋伯通家瑣夕暉，八年寒食數歸期。',32,'全唐诗/poet.song.183000.json','["皋伯通家瑣夕暉，八年寒食數歸期。", "江鄉橘柚花如雪，不許離人戴一枝。"]'),
('13d28e4e-7226-4738-97e7-050519f47c82','絕句二首  其二','周文璞','宋','宋诗','song-poetry','','[]','入春便與僧爲友，紫萼黄英見坐禪。',32,'全唐诗/poet.song.183000.json','["入春便與僧爲友，紫萼黄英見坐禪。", "昨日鄰翁催入社，謝他只是說無錢。"]'),
('5d3ede00-bf08-447a-adda-4bd71257cc58','辛未九月晦日','周文璞','宋','宋诗','song-poetry','','[]','遺體即母身，哀哀勿重陳。',84,'全唐诗/poet.song.183000.json','["遺體即母身，哀哀勿重陳。", "一貽泉壤憂，兩見霜露晨。", "繁霜與重露，塗抹隨荆榛。", "身即未殞滅，强與松柏春。", "遂於摇落中，見此天地仁。", "玄鳥已辭社，蓐收方降莘。", "拭淚聲秋旻，何由酬艱辛。"]'),
('370d2512-82b7-4ca6-84d6-6dbd74ee6716','閑居日有幽事戲作','周文璞','宋','宋诗','song-poetry','','[]','竹暗僧窺戶，莎寒鶴上廳。',120,'全唐诗/poet.song.183000.json','["竹暗僧窺戶，莎寒鶴上廳。", "壁懸陳處士，屏貼少微星。", "壘甓爲蔬圃，埋盆學蓼汀。", "自知癡得計，常用醉爲醒。", "野客兼稱僕，幽禽代作伶。", "浴鳬翻落磵，鬭雀墮空庭。", "算數推三甲，防身召一丁。", "案頭松葉響，牆角柚花馨。", "梵庋堆書笈，醪罌隠粟缾。", "茅茨隠煙雨，鷄犬也忘形。"]'),
('b889f6c8-2f59-494d-b48b-85fdd06cb5c7','苦錐歌寄澗泉','周文璞','宋','宋诗','song-poetry','','[]','我園秋果枝累累，縹青紺黄使相持，役夫牧人記註之。',112,'全唐诗/poet.song.183000.json','["我園秋果枝累累，縹青紺黄使相持，役夫牧人記註之。", "所佳尚者惟苦錐，苦錐兩株結蒙密。", "追惟丈人語天出，遂欲供之作籩實。", "他往返舍百無一，乃被猿狙打都畢。", "摧藏睢盱以自佚，季冬初旬日協吉。", "寒風急霰俱冽栗，自慙曩者信已失，作歌獻焉效詼譎。"]'),
('96a9ba20-fc6d-4ed7-91c7-12454d8d499c','臘月八夜雨','周文璞','宋','宋诗','song-poetry','','[]','愁雲欲雪未成雪，忽聞寒雨夜淋浪。',64,'全唐诗/poet.song.183000.json','["愁雲欲雪未成雪，忽聞寒雨夜淋浪。", "但知歲月墮寂寞，不悟乾坤發艷陽。", "天黑鬼車聲更大，夜闌客枕夢初長。", "明朝起視籬砌下，草芽浥浥又回黄。"]'),
('c81af733-caca-497a-b636-696bb12ba67e','送澗泉','周文璞','宋','宋诗','song-poetry','','[]','一自接道誼，形容生輝光。',120,'全唐诗/poet.song.183000.json','["一自接道誼，形容生輝光。", "束情謝流宕，捧詠增慚惶。", "矯足時切闚，雲海何頹唐。", "長安賣藥市，堇堇十載强。", "復綴守藏史，得近中書堂。", "心計常自珍，孰云失其防。", "稽首謝衆去，酹酒相扶將。", "融風促綠蔭，代對日夜忙。", "石澗流自湧，玉山禾欲長。", "安得便奮飛，相從决高翔。"]'),
('0e5586a8-3225-4a63-b715-f0e74b09992c','送薛子舒','周文璞','宋','宋诗','song-poetry','','[]','龍泉餞語餘，便使借船居。',48,'全唐诗/poet.song.183000.json','["龍泉餞語餘，便使借船居。", "津吏方抽木，官人但載書。", "潮通白矴石，身近碧京魚。", "一卷新文就，皋禽亦自如。"]'),
('6abbacb5-b98c-4481-943e-1679f708b867','晚菊','周文璞','宋','宋诗','song-poetry','','[]','亭亭砌下黄金花，霜後顔色如矜誇。',65,'全唐诗/poet.song.183000.json','["亭亭砌下黄金花，霜後顔色如矜誇。", "玄英摧挫百卉盡，獨自照耀山人家。", "湘累晨餐不論數，千歲高丘恐無女。", "君不見天寶杜陵翁，晚節嘗爲少年侮。"]'),
('e51b278f-1c14-40a1-8e39-53c7af8d8f6b','誦哀江南賦','周文璞','宋','宋诗','song-poetry','','[]','高橋沙水涸，臺城蔓草纏。',96,'全唐诗/poet.song.183000.json','["高橋沙水涸，臺城蔓草纏。", "下有煩冤人，誦此危苦篇。", "我生楚臣後，身在江楓前。", "但見去魂遠，不見歸魂還。", "惟昔愛好詞，細碎窮註箋。", "中間多佚事，他書亦不傳。", "極欲補闕漏，今方長棄捐。", "重效嘈囋聲，庶幾與周旋。"]'),
('2a608c83-f91d-4499-a295-bcba1e5227a8','簡正字南仲','周文璞','宋','宋诗','song-poetry','','[]','白髮梁鴻隨暮猿，不辭引領望兄門。',64,'全唐诗/poet.song.183000.json','["白髮梁鴻隨暮猿，不辭引領望兄門。", "久無清夢相追逐，今喜遺經爲討論。", "數葉赤楓鳴客路，一畦黄薤憶家園。", "著書不就身何用，每見飛塵恨滿軒。"]'),
('d0b25c56-945a-4f41-986c-ddde25ff57cf','重遊栖霞','周文璞','宋','宋诗','song-poetry','','[]','林麓已盡虎不見，邇來流民所蹂踐。',96,'全唐诗/poet.song.183000.json','["林麓已盡虎不見，邇來流民所蹂踐。", "殘僧自言昔遭變，藏經埋像猶可唁。", "流泉鳴悲雨摧殿，滿巖慈相沙汰難。", "白盛綴粘或壞面，慧命弗絕如斷綫。", "况我憂患經歷遍，見此悲酸尚兢戰。", "千聲萬聲走出門，門外秋花泣餘泫。"]'),
('b36b6ae0-69fa-4ad2-a877-d032caf08683','出溪','周文璞','宋','宋诗','song-poetry','','[]','二月天景佳，波清見佳蝦。',48,'全唐诗/poet.song.183000.json','["二月天景佳，波清見佳蝦。", "望中何所好，溪女摘蘋花。", "淺淺猶可涉，素手花似雪。", "隔港聞謳聲，風來正相接。"]'),
('e85a98e6-1694-4bad-8ea0-74e3fe451f85','過舊居遇鄰家子述懷','周文璞','宋','宋诗','song-poetry','','[]','憶昔玉雪時，最感鄰媼嫂。',144,'全唐诗/poet.song.183000.json','["憶昔玉雪時，最感鄰媼嫂。", "翦羅作髮鬌，添璣綴紋褓。", "今回遇孫枝，面墨體枯槁。", "念彼舊宅凶，災釁失依保。", "此生未還役，况復念家道。", "冷節返鄉閭，江路見芳草。", "奪恃罹荒饑，連歲愁浩浩。", "流離在山縣，只有泉水好。", "野櫻聚紫玫，衒弄晴日杲。", "半爲鳥雀盜，半被奴婢討。", "佰弜必盡護，盤飣如拱寶。", "坐薦一盞春，便足舒遠抱。"]'),
('2b4d7702-41cc-4213-bed1-fd076bdacdc7','正字南仲祭詩','周文璞','宋','宋诗','song-poetry','','[]','昭陽作噩冬，愁雲凝上蒼。',288,'全唐诗/poet.song.183000.json','["昭陽作噩冬，愁雲凝上蒼。", "我墮谿谷底，鹵莽聞公喪。", "哲人困中壽，頗謂告者狂。", "繼執邸吏符，躑蹢抽肝腸。", "又聞歛魂魄，玉色貌愈强。", "環泣甚危苦，精氣都不揚。", "一朝委垕地，千歲還天常。", "峩冠謝成均，射策何巍昂。", "連踐中秘書，檢校四庫藏。", "象緯識校尉，篇編嘉議郎。", "麟遊夜閣黑，鳳去旻霄黄。", "惟初典郡學，吐血謗可傷。", "積疊高於山，黨讞空銷亡。", "故老解噓枯，新人工絕吭。", "灼灼藻火衣，可使綻作裳。", "竟罷奉面對，射策裨君王。", "愧負臨軒恩，穹林摧棟梁。", "往者流傳誣，聖賢失隄防。", "頹裂在眼前，悽愴遥相望。", "二紀獲敬事，實亞衿珮行。", "嘗竊季弟稱，朽穢敢自將。", "束教濡雨露，采擷參差香。", "雖罹顛沛憂，夢寐敢自忘。", "翻思說待對，按述何微茫。"]'),
('52c05143-6a1b-4eed-bf1a-3f339dde16da','吊友人朱子大','周文璞','宋','宋诗','song-poetry','','[]','與君昔並丹陽船，形容惘愴俱可憐。',144,'全唐诗/poet.song.183000.json','["與君昔並丹陽船，形容惘愴俱可憐。", "自說宅囿及百年，藏三小山出雲煙。", "土伯小廟自題扁，持照清池分醜妍。", "吁嗟先君方下世，姪子賣半相炒煎。", "出尋方伯待救護，與我密者纔萬錢。", "是身災疢恐凋謝，語未脫口吁皇天。", "那知君今亦逝川，洪崖白石夢杳然，竟從他姓改受廛。", "嗚呼，朱君無歸，歸來但見空屋椽，入抱山骨於黄泉。"]'),
('cb4c69b4-9d43-4240-9939-c647e1379b90','挽正字南仲四首  其一','周文璞','宋','宋诗','song-poetry','','[]','千古應無恨，諸公竟不能。',48,'全唐诗/poet.song.183000.json','["千古應無恨，諸公竟不能。", "要令參溟涬，端合罷飛騰。", "白草傷麟野，蒼山下馬陵。", "有兒持手澤，淚落照書燈。"]'),
('8afb18fb-372b-4100-aadd-8013552a6eb6','挽正字南仲四首  其二','周文璞','宋','宋诗','song-poetry','','[]','卷舌空沉彩，芸香亦蠹賢。',48,'全唐诗/poet.song.183000.json','["卷舌空沉彩，芸香亦蠹賢。", "幾時噫鳳沼，一旦感龍泉。", "遠播雕題外，高垂若木邊。", "煎膠嗟不及，遺碣暝臺懸。"]'),
('afe2370b-7b2a-4138-9194-8967a5943e50','挽正字南仲四首  其三','周文璞','宋','宋诗','song-poetry','','[]','珠璧方輝耀，菁華未寂寥。',48,'全唐诗/poet.song.183000.json','["珠璧方輝耀，菁華未寂寥。", "極知身作祟，何用食爲妖。", "犧象收儒廟，簫笳咽市橋。", "傷心紗帽冷，三徑雨瀟瀟。"]'),
('1d9d1aee-7ac3-4014-8963-b634ccbc21cd','挽正字南仲四首  其四','周文璞','宋','宋诗','song-poetry','','[]','一自初聞報，哀號向草堂。',48,'全唐诗/poet.song.183000.json','["一自初聞報，哀號向草堂。", "相隨只兒子，遠和有山獐。", "土沃幽宮掩，灰凝奠酒香。", "孤身揮泣盡，松柏便萎黄。"]'),
('2057aa83-4f81-4b18-a9f6-90be21a473cb','行歌四首  其一','周文璞','宋','宋诗','song-poetry','','[]','雪壓門外土骨堆，一番兩番春始回。',64,'全唐诗/poet.song.183000.json','["雪壓門外土骨堆，一番兩番春始回。", "歸來但見鄰舍換，老樹紅花如死灰。", "商量千古有何事，經營八紘非汝才。", "乘除幻變既如此，何不快呼鸚鵡杯。"]'),
('559cbcbf-6370-47f2-843f-cbb6b78f3c6f','行歌四首  其二','周文璞','宋','宋诗','song-poetry','','[]','天讒天讒光照戶，反舌轉枝啼更怒。',64,'全唐诗/poet.song.183000.json','["天讒天讒光照戶，反舌轉枝啼更怒。", "九霄詄蕩帝座高，老我此身無告訴。", "舍傍種園翁作鄰，一方泉兮在中庭。", "齊民書在泉有銘，誓將團結爲林坰。"]'),
('f138cfdf-29b9-4451-bf6a-84dd31fde2e8','行歌四首  其三','周文璞','宋','宋诗','song-poetry','','[]','春霏霏兮秋靡靡，嘆息賞音人已死。',64,'全唐诗/poet.song.183000.json','["春霏霏兮秋靡靡，嘆息賞音人已死。", "堪嗟玉雪綴空條，可奈芳蕤逐流水。", "融怡艷冶恨欲銷，世間風雨何寂寥。", "有誰肯爲吹葬簫，往和蟋蟀諧鴟鴞。"]'),
('2881bf98-152b-44d9-83b2-a968f5bb19bf','行歌四首  其四','周文璞','宋','宋诗','song-poetry','','[]','先秦古書世已稀，國風雅頌聲又微。',64,'全唐诗/poet.song.183000.json','["先秦古書世已稀，國風雅頌聲又微。", "彼美人兮在天路，馬蜷局兮將安歸。", "古人所懷已汩汩，今人所懷又忽忽。", "我亦東西南北人，相逢且盡杯中物。"]'),
('a625b0d4-78af-4573-96e3-d1577f25f977','遣興','周文璞','宋','宋诗','song-poetry','','[]','山中雨更愁，不是棄吾州。',48,'全唐诗/poet.song.183000.json','["山中雨更愁，不是棄吾州。", "懷母未能去，訴鄰誰肯留。", "茶人窮似虱，藥戶狹於舟。", "一磵多深碧，嘲吟尚自由。"]'),
('4a140f09-f5b1-46f9-93e0-d14c489f3963','孤山桃花二首  其一','周文璞','宋','宋诗','song-poetry','','[]','天上仙人休擲火，塵中道士莫燒香。',32,'全唐诗/poet.song.183000.json','["天上仙人休擲火，塵中道士莫燒香。", "可憐絳雪渾無頼，一簇千枝對草堂。"]'),
('48f5ac36-4757-45c2-a010-57f511f2b6b6','孤山桃花二首  其二','周文璞','宋','宋诗','song-poetry','','[]','莫向蓬蒿恨不遭，夢魂曾釣海山鼇。',32,'全唐诗/poet.song.183000.json','["莫向蓬蒿恨不遭，夢魂曾釣海山鼇。", "當時不合輕仙事，惆悵靈風滿碧桃。"]'),
('90fc8ae3-ed3f-4df0-8890-8e63ca281920','送人之武夷二首  其一','周文璞','宋','宋诗','song-poetry','','[]','精舍人歸入內臺，遺基處處有芳埃。',32,'全唐诗/poet.song.183000.json','["精舍人歸入內臺，遺基處處有芳埃。", "小儒更合修壺史，刊落乾魚說水苔。"]'),
('135ec8eb-f0fb-46a7-bc90-6637a824ddbc','送人之武夷二首  其二','周文璞','宋','宋诗','song-poetry','','[]','終向名山度此生，此生吟骨要猿擎。',32,'全唐诗/poet.song.183000.json','["終向名山度此生，此生吟骨要猿擎。", "洞宮終與人間別，六六峰高削紫瓊。"]'),
('7b2d748e-4dbb-47ad-bf61-be01353dd871','秋晦有懷南仲正字','周文璞','宋','宋诗','song-poetry','','[]','懷人幾日惡，况復值秋陰。',48,'全唐诗/poet.song.183000.json','["懷人幾日惡，况復值秋陰。", "天亦容清調，人難識素心。", "他鄉誰饋肉，永夜只聽琴。", "高詠龍泉碣，相從發至音。"]'),
('63617e61-e669-4cc0-b573-73a060396a9d','贈孤山道士二首  其一','周文璞','宋','宋诗','song-poetry','','[]','九霄象簡手中擎，豈是閑人愛列卿。',32,'全唐诗/poet.song.183000.json','["九霄象簡手中擎，豈是閑人愛列卿。", "洞裏石田春漠漠，有田多與種黄精。"]'),
('461eaffa-e390-4c44-9773-b04f880ed270','贈孤山道士二首  其二','周文璞','宋','宋诗','song-poetry','','[]','清秋古洞無猿嘯，自覺尋行幽意微。',32,'全唐诗/poet.song.183000.json','["清秋古洞無猿嘯，自覺尋行幽意微。", "處士橋邊增悵望，幾回沽酒對斜暉。"]'),
('44a73f24-e4bc-4b36-95fe-4903bfd311be','送人之桐柏','周文璞','宋','宋诗','song-poetry','','[]','半溪松黄堆碧波，狂夫於此欲如何。',32,'全唐诗/poet.song.183000.json','["半溪松黄堆碧波，狂夫於此欲如何。", "洞天春晚歸不得，司馬悔橋芳草多。"]'),
('ef4791c9-e44d-467f-ad61-69c0b5f466f4','送髯高謁方巖','周文璞','宋','宋诗','song-poetry','','[]','客舍窘積雨，出門今始晴。',48,'全唐诗/poet.song.183000.json','["客舍窘積雨，出門今始晴。", "藥苗隨野飯，燕子看山行。", "大道白日晚，閑汀綠芷生。", "方巖相見了，爲謝草堂兄。"]'),
('06c55588-2535-42c8-8da3-d2a3c1bb15e6','瞿塘神君歌','周文璞','宋','宋诗','song-poetry','','[]','黄衫紗帽佳少年，炯然餓虎窮山淵。',176,'全唐诗/poet.song.183000.json','["黄衫紗帽佳少年，炯然餓虎窮山淵。", "不居秦鹿祖龍畔，却走碧鷄金馬邊。", "左手斜執巨靈鑿，右手敬抱禹貢篇。", "離堆順流已受命，一下不打天吳鞭。", "有時挾彈暮雲表，有時蹴遊春風前。", "有時却自著絳帕，走入藥市尋神仙。", "爲人定似李太白，學道定似葛稚川。", "孫翁走避乖崖叟，遣僕送畫不取錢。", "神君廟食與畫像，千古萬古當流傳。", "我昔夢上神君殿，偶值蓬萊衆真宴。", "洛陽開盡姚黄花，銅駝陌上難相見。"]'),
('71f764ee-557f-4560-8bad-a2fcc38b374c','清明日書事','周文璞','宋','宋诗','song-poetry','','[]','蒼弁一如楚執珪，思想越吟身自低。',160,'全唐诗/poet.song.183000.json','["蒼弁一如楚執珪，思想越吟身自低。", "澗水又如古智士，縱橫流轉多滑稽。", "雜花半開已倏落，如怨曠女離深閨。", "幽禽自呼復相命，如譴逐魄傷窮棲。", "而我自是不羈者，行行踏破青萋萋。", "今回蕩槳苕霅溪，與野老輩相扶携。", "園池亭墅游歷遍，自對蜀錦傾偏提。", "興闌徑走歸弟舍，同沃浮蟻烹村鷄。", "百五之後最寥闃，獨過趙灣西更西。", "野夫不知時節換，但要熟醉如春泥。"]'),
('130fac1b-19b2-4adc-806b-f122971a1058','雲根','周文璞','宋','宋诗','song-poetry','','[]','雲從會稽生，旦旦見伯禹。',144,'全唐诗/poet.song.183000.json','["雲從會稽生，旦旦見伯禹。", "聽讀山海經，成龍不成虎。", "禹命雲歸歟，可向蕺山去。", "昂昂王內史，眉宇照今古。", "常在此盤旋，深藏無處所。", "王孫江海人，雲根自栖翥。", "招邀玉葉來，以石爲伴侶。", "既從衣上浮，只就茶裏煮。", "不入晉家池，肯作秦望雨。", "兩儒一支郎，不學世間語。", "吳傖哦五字，坎壈酸澀苦。", "併送山中人，約束雲下取。"]'),
('423e27a8-6357-4a3e-9d20-8fe605f30f48','聽琴','周文璞','宋','宋诗','song-poetry','','[]','向人猶抱舜文絃，可煞書生不值錢。',32,'全唐诗/poet.song.183000.json','["向人猶抱舜文絃，可煞書生不值錢。", "彈出履霜空作惡，一林風露已鳴蟬。"]'),
('98d5002a-aac4-4cef-b9d6-35b63197ad44','寄友人','周文璞','宋','宋诗','song-poetry','','[]','流落他鄉鎩羽翰，半年寧復記悲歡。',64,'全唐诗/poet.song.183000.json','["流落他鄉鎩羽翰，半年寧復記悲歡。", "夜傳樓鼓思城角，朝見江船念客鞍。", "不恨形骸老閭里，遂令唇舌滿長安。", "寄聲好在文章友，目送春雲自倚欄。"]'),
('84fe2edb-fc5f-40ed-b172-d8b792eb53dd','雨','周文璞','宋','宋诗','song-poetry','','[]','雨意遽如許，雲容亦可憐。',48,'全唐诗/poet.song.183000.json','["雨意遽如許，雲容亦可憐。", "聲聲總斷續，滴滴更勻圓。", "道院燒香地，山房焙畫天。", "故園無恙否，潤色到瓜田。"]'),
('669967ce-e388-4711-bfcf-d9c8108d2312','陰山','周文璞','宋','宋诗','song-poetry','','[]','陰山祠下月如霜，不爲吟猿斷殺腸。',32,'全唐诗/poet.song.183000.json','["陰山祠下月如霜，不爲吟猿斷殺腸。", "折得橙花無處賞，带枝分與棹船郎。"]'),
('c617ba6e-0ed3-42be-bbec-4b1dd6440eb5','新亭','周文璞','宋','宋诗','song-poetry','','[]','諸君收淚已無言，煙外中原草色昏。',32,'全唐诗/poet.song.183000.json','["諸君收淚已無言，煙外中原草色昏。", "老子歸來坐廊廟，短轅車上欲消魂。"]'),
('0ae16d9f-d358-465d-9ae4-01838a8ff4a2','法寶寺','周文璞','宋','宋诗','song-poetry','','[]','細竹千竿殿影斜，龍顔曾此著袈裟。',32,'全唐诗/poet.song.183000.json','["細竹千竿殿影斜，龍顔曾此著袈裟。", "寺樓杳杳鍾聲度，疑有宮娥出晚花。"]'),
('7c26a8e3-c08c-4414-8843-a6141bdc2667','戒壇','周文璞','宋','宋诗','song-poetry','','[]','相君孫女小乘僧，身入祇園佛律行。',32,'全唐诗/poet.song.183000.json','["相君孫女小乘僧，身入祇園佛律行。", "三級戒壇秋色冷，箇中螻蟻亦長生。"]'),
('0fc11334-d593-41ee-94b7-efbbfd174c3d','桓野王畫像','周文璞','宋','宋诗','song-poetry','','[]','胡床三弄清溪笛，嘆息欷歔太極箏。',32,'全唐诗/poet.song.183000.json','["胡床三弄清溪笛，嘆息欷歔太極箏。", "怊悵斯人風味減，江花江草不勝情。"]'),
('5c250058-20bd-4d92-bd11-cd884dbfb3f6','玉晨觀二首  其一','周文璞','宋','宋诗','song-poetry','','[]','野筍衝泉出，山花避石開。',24,'全唐诗/poet.song.183000.json','["野筍衝泉出，山花避石開。", "余方有公事，不爲等閑來。"]'),
('54e22c5f-f5fc-4465-9a38-9efadaf8d623','玉晨觀二首  其二','周文璞','宋','宋诗','song-poetry','','[]','羽扇臨玄寺，霓衣上醮壇。',24,'全唐诗/poet.song.183000.json','["羽扇臨玄寺，霓衣上醮壇。", "九枝松葉冷，千葉杏花殘。"]'),
('73cbf8e6-6afe-47ca-9f4f-7320a80041bc','寒食有感三首  其一','周文璞','宋','宋诗','song-poetry','','[]','生平參道術，師事大茅翁。',48,'全唐诗/poet.song.183000.json','["生平參道術，師事大茅翁。", "持鑰開金匱，焚香立玉童。", "黄麟來地上，朱鯉出江中。", "今在桁楊畔，依依睡晚風。"]'),
('115851c5-e023-48f8-b021-c32349dff763','寒食有感三首  其二','周文璞','宋','宋诗','song-poetry','','[]','清明好時節，傲吏小詩家。',48,'全唐诗/poet.song.183000.json','["清明好時節，傲吏小詩家。", "失意因流水，傷心爲落花。", "人歸知市靜，日落見山斜。", "明日三叉路，村醪亦自佳。"]'),
('927a6b97-fa1d-46f2-bae6-a119511cb9e2','寒食有感三首  其三','周文璞','宋','宋诗','song-poetry','','[]','亭午步江皋，誰云命不遭。',48,'全唐诗/poet.song.183000.json','["亭午步江皋，誰云命不遭。", "愛風吹蛺蝶，怕雨爛櫻桃。", "鑽火烹新乳，槌門覓小槽。", "今年奇事少，塵滿舊征袍。"]'),
('8512263e-f908-4e7e-98ea-f0009a813ed3','桂','周文璞','宋','宋诗','song-poetry','','[]','偶向花邊立，懸知病已瘳。',48,'全唐诗/poet.song.183000.json','["偶向花邊立，懸知病已瘳。", "小山今夜月，團樹滿庭秋。", "清露霑叢底，斜河在上頭。", "須臾香更好，還與碧雲浮。"]'),
('828e862f-e65e-4804-99d6-f651a9c34cd3','自笑','周文璞','宋','宋诗','song-poetry','','[]','自笑蕭條甚，微吟坐到昏。',48,'全唐诗/poet.song.183000.json','["自笑蕭條甚，微吟坐到昏。", "江風來掃地，山鳥見開門。", "茶面龍頭縮，花梢犢鼻溫。", "一從杯酒少，不復過深村。"]'),
('90fd8b20-67ea-4943-9e17-34881b04dfed','槜李道中二首  其一','周文璞','宋','宋诗','song-poetry','','[]','吹徹鵝笙醉碧桃，古城斜日泛輕舠。',32,'全唐诗/poet.song.183000.json','["吹徹鵝笙醉碧桃，古城斜日泛輕舠。", "此行憶著經行處，綠樹黄桑一樣高。"]'),
('bd7b414c-fc5a-488f-bf11-96f24c04d877','槜李道中二首  其二','周文璞','宋','宋诗','song-poetry','','[]','卧龍山下聽吟松，細雨清明似夢中。',32,'全唐诗/poet.song.183000.json','["卧龍山下聽吟松，細雨清明似夢中。", "柳蔭朱欄三百尺，渴烏猶自泣春風。"]'),
('5986015a-7d29-48d2-af9a-10902994bb01','梅梁歌','周文璞','宋','宋诗','song-poetry','','[]','文命殿角東北左，上有梅梁鐵交鎖。',179,'全唐诗/poet.song.183000.json','["文命殿角東北左，上有梅梁鐵交鎖。", "傳聞舊時枝葉生，木質鱗身無不可。", "有時匹練離朱栱，歸带濕萍光欲動。", "低頭下吸菲嶺泉，奮髯直入陽明洞。", "旁觀但怪香火濃，頃刻即令風雨送。", "爾不見饑烏啄鼓來饋食，走入嵩高化爲石。", "禨祥禍福儻或是，陰陽幻變誰能測。", "玉笥觀掛白玉梁，含元追下流血柱。", "異事苟逢博物問，後來那得詳其故。", "卷丹雲，凝素霧，玉簫九成奠雕俎。", "登歌升降只仰俯，嗚呼梅梁怱飛去。"]'),
('e6e0a165-70eb-4fc7-a38a-c81b1612e408','題胡女騎','周文璞','宋','宋诗','song-poetry','','[]','燕山雪花一尺飛，胡人胡女夜打圍。',67,'全唐诗/poet.song.183000.json','["燕山雪花一尺飛，胡人胡女夜打圍。", "海東青過流沙西，黄頭郎主獨自歸。", "創殘狐兔懸氈車，疲憊鷹犬聞笳悲。", "君不見自從石晉納書款，白溝河漘作邊面。"]'),
('57171620-15b4-46fc-be78-5ba6392b8407','東陽道中','周文璞','宋','宋诗','song-poetry','','[]','野店梢頭起竈煙，江雲弄色半晴天。',64,'全唐诗/poet.song.183000.json','["野店梢頭起竈煙，江雲弄色半晴天。", "暗泉遶砌喧人語，遠燒侵林照客韉。", "晚日未收鷄上樹，春風欲度鳥耘田。", "布帆無恙歸心穩，纔到家山又迫年。"]'),
('02329008-7047-41a5-b97b-5a5ef24cdb97','鳳門泉','周文璞','宋','宋诗','song-poetry','','[]','石根兩眼北流泉，乳竇潜通御井邊。',32,'全唐诗/poet.song.183000.json','["石根兩眼北流泉，乳竇潜通御井邊。", "飄出宮花人不識，又沿衰草下山前。"]'),
('b202d032-55e2-46aa-bbfc-4e4c0cabe1f8','寒食曲','周文璞','宋','宋诗','song-poetry','','[]','今年寒食好天色，遊人踏青行不極。',115,'全唐诗/poet.song.183000.json','["今年寒食好天色，遊人踏青行不極。", "尋山不憚千里遠，往往啼號濕松柏。", "一杯纔酹墳上土，祗就墳前便歌舞。", "故鄉自有懊惱聲，插腰羊皮小番鼓。", "吁嗟悲歡一餉間，但恨死人不能語。", "君不見北客紛紛俱落南，先冢盡被胡塵漫。", "影堂逢節具飲食，魂魄夜行溪谷山。"]'),
('5ab39682-c04f-4256-8cac-969f44935495','賞春二首  其一','周文璞','宋','宋诗','song-poetry','','[]','滿酌黄封都市酒，斜簪縹蔕御園花。',32,'全唐诗/poet.song.183000.json','["滿酌黄封都市酒，斜簪縹蔕御園花。", "半酣更乞跳珠水，獨對風爐自煮茶。"]'),
('6d1e9a84-f7f9-4adc-b6ed-9b478cde6833','賞春二首  其二','周文璞','宋','宋诗','song-poetry','','[]','賞春社裏鼓逢逢，尚恨聲同調不同。',32,'全唐诗/poet.song.183000.json','["賞春社裏鼓逢逢，尚恨聲同調不同。", "我亦明朝苦無事，更來吹笛亂山中。"]'),
('93af449d-64c8-4b51-8f9e-f70f8d26cebd','春懷','周文璞','宋','宋诗','song-poetry','','[]','棠梨未落柳絲長，料望幽人作斷腸。',64,'全唐诗/poet.song.183000.json','["棠梨未落柳絲長，料望幽人作斷腸。", "已自不堪田父飲，更能重入少年場。", "山連莽莽荒陂白，門掩蕭蕭野日黄。", "想得故園疏雨外，樽前催拍杜韋娘。"]'),
('c9352565-df14-41dc-910a-cb955de3d006','暮雨','周文璞','宋','宋诗','song-poetry','','[]','暮雨瀟瀟郎不歸，尊前誰憶舊歌詞。',32,'全唐诗/poet.song.183000.json','["暮雨瀟瀟郎不歸，尊前誰憶舊歌詞。", "望夫烏臼濃於染，葉葉驚秋恨欲飛。"]'),
('bfc792c3-68ae-4f64-8ea6-2af05140977d','即事二首  其一','周文璞','宋','宋诗','song-poetry','','[]','樂使金花鼓，蠻衣紫錦鞍。',24,'全唐诗/poet.song.183000.json','["樂使金花鼓，蠻衣紫錦鞍。", "蕃官船過界，驛吏報平安。"]'),
('259599f6-5a73-4e29-8370-9db0cc3cf131','即事二首  其二','周文璞','宋','宋诗','song-poetry','','[]','龍護朝元閣，鶴棲封禪臺。',24,'全唐诗/poet.song.183000.json','["龍護朝元閣，鶴棲封禪臺。", "中原垂白叟，只望羽書來。"]'),
('8e39e14e-5516-4767-ad1a-a98263d8b498','題堯章新成山堂','周文璞','宋','宋诗','song-poetry','','[]','早將心事付漁樵，若被幽人苦見招。',64,'全唐诗/poet.song.183000.json','["早將心事付漁樵，若被幽人苦見招。", "多種竹將挑筍喫，旋栽松待斫柴燒。", "壁間古畫身都碎，架上枯琴尾半焦。", "猶有住山窮活計，仙經盈卷一村瓢。"]'),
('a1648bbb-94f8-4f84-bc04-7c14677529ab','題盧申之騾綱圖','周文璞','宋','宋诗','song-poetry','','[]','昔日三郎騎爾祖，廟食太山可辛苦。',64,'全唐诗/poet.song.183000.json','["昔日三郎騎爾祖，廟食太山可辛苦。", "後來崎嶇蜀棧間，棄置龍媒復親汝。", "深山古木雪漫漫，險途十步九步艱。", "綱頭呪囑勿損折，要爾助軍身補官。"]'),
('89a02883-1553-4754-919d-aa3e84ae8b83','贈相士丁日宣','周文璞','宋','宋诗','song-poetry','','[]','張公謂余可神仙，薛顛謂余可英傑。',96,'全唐诗/poet.song.183000.json','["張公謂余可神仙，薛顛謂余可英傑。", "丁生謂二皆無成，世間安有此奇絕。", "麒麟閣上冠貂蟬，龍虎鼎內治大丹。", "興來一笑掃燕□，回首已自升雲端。", "何如只向松江渡，楊柳影邊茅屋住。", "卧看蒼虬挾白雲，卷取秋濤過江去。"]'),
('029c7059-62b4-4ac4-814f-ea4fa6abc217','弔黥卒','周文璞','宋','宋诗','song-poetry','','[]','吾作窮奇白下囚，汝披短褐從吾遊。',64,'全唐诗/poet.song.183000.json','["吾作窮奇白下囚，汝披短褐從吾遊。", "蔣侯廟畔沽春酒，周處臺邊送客舟。", "械欲破時應日慘，命將絕處亦天愁。", "江陵柳大如知此，對著官軍輒淚流。"]'),
('cc6e40c4-8dd8-44a3-aa56-326d9cf726fd','楊孟博挽詞','周文璞','宋','宋诗','song-poetry','','[]','向來洛下老書生，今見諸孫更老成。',64,'全唐诗/poet.song.183000.json','["向來洛下老書生，今見諸孫更老成。", "不復秀才趨試院，已題文學上銘旌。", "泛觀今古人亡恨，只有英雄命莫爭。", "來弔乍聞妻子哭，依然認作讀書聲。"]'),
('2f198fcf-0e3f-4328-8488-e295a544727a','贈隠者','周文璞','宋','宋诗','song-poetry','','[]','袁三柳大劉廿八，長到先生卜肆邊。',64,'全唐诗/poet.song.183000.json','["袁三柳大劉廿八，長到先生卜肆邊。", "便拜逸妻爲嫂氏，更沽村酒作家筵。", "山公馬在何須爾，林屋丹成亦偶然。", "獨此老身無藉頼，爲他人擲卦爻錢。"]'),
('499206f2-17f4-463d-bbe8-4e3f45e4b5d7','劍客行','周文璞','宋','宋诗','song-poetry','','[]','燕雲逆胡著柘黄，仁人烈士集太行。',128,'全唐诗/poet.song.183000.json','["燕雲逆胡著柘黄，仁人烈士集太行。", "已聞泣涕拜明詔，共挾金輿歸大梁。", "安得山人一雙劍，走入雲中看不見。", "人間夜半風雨時，逆胡首奏延和殿。", "我生四十無所成，荆淮好漢爲知音。", "丈夫志在仁義耳，麟閣貂冠非本心。", "功成劍化兩龍去，我亦變名入煙霧。", "此時再拜康山人，九霄客星在何處。"]'),
('13236fcc-f6b6-406d-a77e-9fa5ca12e73a','書事','周文璞','宋','宋诗','song-poetry','','[]','說戰猶能聽，聞屍不忍過。',48,'全唐诗/poet.song.183000.json','["說戰猶能聽，聞屍不忍過。", "役人愁似鬼，病馬瘦於駝。", "甚欲參經緯，其誰出揣摩。", "中原有遺老，亡柰檄書何。"]'),
('6a54bd13-5d27-49a1-86f2-dd7a4605f581','見泗州降者','周文璞','宋','宋诗','song-poetry','','[]','纔自降胡便守邊，大家齊數中興年。',32,'全唐诗/poet.song.183000.json','["纔自降胡便守邊，大家齊數中興年。", "姑蘇寺裏相逢處，爲爾呻吟一悵然。"]'),
('fecd13df-b604-4f16-9a1e-0b8c79f8fe4f','感興七言三首  其一','周文璞','宋','宋诗','song-poetry','','[]','寥寥古意少人傳，莫爲薰琴只五絃。',64,'全唐诗/poet.song.183000.json','["寥寥古意少人傳，莫爲薰琴只五絃。", "夫子縱心方學易，我曹何意便談玄。", "神馳洙泗身將老，望斷沅湘眼欲穿。", "月白風清如此夜，阿郎不肯上鈞天。"]'),
('ca84e940-d5dd-4d2c-acad-4dc7eb2e0052','感興七言三首  其二','周文璞','宋','宋诗','song-poetry','','[]','在家莫羨出家僧，擾擾營營竟未曾。',64,'全唐诗/poet.song.183000.json','["在家莫羨出家僧，擾擾營營竟未曾。", "相國舟中龍奪劍，山人琴畔鬼吹燈。", "從來不肯尋真訣，更自無心學大乘。", "漢室諸公鳴玉佩，也須還我一枝藤。"]'),
('3cc6dd5e-9691-4cd9-a84b-4c279087880e','感興七言三首  其三','周文璞','宋','宋诗','song-poetry','','[]','夜夜推敲學苦吟，一如鍛鍊假黄金。',64,'全唐诗/poet.song.183000.json','["夜夜推敲學苦吟，一如鍛鍊假黄金。", "石間真隠何時出，地下狂魂無處尋。", "獨鶴尚知長袖舞，哀猿空作斷腸音。", "故墟杞菊今何似，桂落小山春水深。"]'),
('baeebf60-e87c-46af-9da3-4f365d13153b','題天童全老','周文璞','宋','宋诗','song-poetry','','[]','天童寶樓閣，銅釘敞朱扉。',48,'全唐诗/poet.song.183000.json','["天童寶樓閣，銅釘敞朱扉。", "一老燒香後，諸禪乞食歸。", "天聽塗毒鼓，神捧苾芻衣。", "說了村夫偈，依然入翠微。"]'),
('983ea78f-3ad3-432e-bc12-9aa5a5ee3b92','送人之金陵','周文璞','宋','宋诗','song-poetry','','[]','江山不逐寒潮晚，陵墓猶含古木春。',32,'全唐诗/poet.song.183000.json','["江山不逐寒潮晚，陵墓猶含古木春。", "君入臺城須訪問，箇中定有六朝人。"]'),
('c8e3df5a-edec-4143-858d-20dcdc5ba893','送逸人歸茅洞','周文璞','宋','宋诗','song-poetry','','[]','三君乘白鵠，各在一山椒。',48,'全唐诗/poet.song.183000.json','["三君乘白鵠，各在一山椒。", "子去穿茅洞，人方采藥苗。", "花連雲氣近，松轉水程遥。", "想得尋幽侶，空歌散午朝。"]'),
('4251acaf-9bfe-40c5-a20d-8afbe3bbb29e','中秋日遊能仁北寺兩剎','周文璞','宋','宋诗','song-poetry','','[]','輕雲漠漠煙漫漫，杖藜扶行不作難。',64,'全唐诗/poet.song.183000.json','["輕雲漠漠煙漫漫，杖藜扶行不作難。", "無量壽佛像最古，未曾有經碑亦殘。", "秋花泫露顔色好，客子著雨衣裳單。", "題詩寫寄莓苔壁，勿使俗人相對看。"]'),
('391a78ee-be90-4ef8-b05a-e84d9b7ec9f3','贈虎丘僧道輝遊天台二首  其一','周文璞','宋','宋诗','song-poetry','','[]','世讚碑文換，穹龜上綠苔。',48,'全唐诗/poet.song.183000.json','["世讚碑文換，穹龜上綠苔。", "琵琶不可聽，樓閣更堪哀。", "竹動禪僧入，梅香凍雀回。", "開函翻內典，日晚未歸來。"]'),
('fa4fa3e6-dcb8-4345-a214-f0fdac604819','贈虎丘僧道輝遊天台二首  其二','周文璞','宋','宋诗','song-poetry','','[]','少小即精勤，參禪復著文。',48,'全唐诗/poet.song.183000.json','["少小即精勤，參禪復著文。", "香薰滬瀆像，茶酹武丘墳。", "入定山猿見，吟詩海鶴聞。", "幽情正迢遞，又拜石橋雲。"]'),
('4a2d7ff5-03b5-4569-b807-61b12d140ae7','西湖即事','周文璞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閑看浮鳩棲曲渚，倦隨奔鹿上荒陵。',32,'全唐诗/poet.song.183000.json','["閑看浮鳩棲曲渚，倦隨奔鹿上荒陵。", "松門雨過長廊靜，一架藤花供病僧。"]'),
('b9aedd2d-30fd-4955-8ce5-a6412b3460c3','宮人斜','周文璞','宋','宋诗','song-poetry','','[]','魂魄凄凉掩暮塵，野花山葉自精神。',32,'全唐诗/poet.song.183000.json','["魂魄凄凉掩暮塵，野花山葉自精神。", "年年中使頭邊過，暗裏相看似路人。"]'),
('ff360245-55d2-433e-b3c7-6ae3ff0781b9','上强寺','周文璞','宋','宋诗','song-poetry','','[]','方池流水碧溶溶，怊悵靈蛇不易逢。',32,'全唐诗/poet.song.183000.json','["方池流水碧溶溶，怊悵靈蛇不易逢。", "門外行人常立看，一株唐末半枯松。"]'),
('8050cf5a-cadf-485e-8e57-e8cf5e73467e','太湖','周文璞','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖我污池，茂苑我林莽。',48,'全唐诗/poet.song.183000.json','["太湖我污池，茂苑我林莽。", "橘柚我堆盤，鱸魚我登俎。", "區區爲蘋花，移去溪上住。", "終當賦歸歟，來此卧煙雨。"]'),
('406095e0-0b3f-48a8-b08c-68f4837e8e44','寫懷二首  其一','周文璞','宋','宋诗','song-poetry','','[]','吾聞唐諸僧，往往多人傑。',48,'全唐诗/poet.song.183000.json','["吾聞唐諸僧，往往多人傑。", "有携至巖廊，可並夔稷契。", "偉哉寒山子，拾菜衣百結。", "其文似離騷，但自寫木葉。"]'),
('993ceb99-6c7a-4abe-8e81-53ddda156fa5','寫懷二首  其二','周文璞','宋','宋诗','song-poetry','','[]','往時陸荆門，自是天下雄。',48,'全唐诗/poet.song.183000.json','["往時陸荆門，自是天下雄。", "徒隸解散盡，何處尋樊翁。", "遂令一世士，默默逃虛空。", "至今大堤上，葉葉皆春風。"]'),
('bbada7bd-e4de-433d-858f-8077e49c47d0','九溪十八磵','周文璞','宋','宋诗','song-poetry','','[]','九溪十八磵，冷見帝青苔。',48,'全唐诗/poet.song.183000.json','["九溪十八磵，冷見帝青苔。", "洗足僧書石，臨流客放杯。", "案頭松葉響，身畔野花開。", "百六辭歌吹，清遊始一回。"]'),
('1dfa7199-d7dd-4644-b168-f9bd1a8a71da','吊辨才二首  其一','周文璞','宋','宋诗','song-poetry','','[]','讀了碑文讀祭詩，冷看遺像立多時。',32,'全唐诗/poet.song.183000.json','["讀了碑文讀祭詩，冷看遺像立多時。", "郎當嶺上生雲處，山鳥山花憶老師。"]'),
('8cf19f3b-0998-4984-897e-41c8e9c05b37','吊辨才二首  其二','周文璞','宋','宋诗','song-poetry','','[]','坡使參寥滴奠茶，定將老淚濕煙霞。',32,'全唐诗/poet.song.183000.json','["坡使參寥滴奠茶，定將老淚濕煙霞。", "誰知走入靈山隊，又對閑人說法華。"]'),
('c2f90db4-d7fc-46e7-828b-0e47908c680e','西湖小隠','周文璞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','先帝何曾寵倖臣，家園籍沒幾經春。',32,'全唐诗/poet.song.183000.json','["先帝何曾寵倖臣，家園籍沒幾經春。", "一丘賜與嬋娟魄，教主西湖似洛神。"]'),
('14b1f835-fd7b-4f5b-840a-f74a512037b3','麯坊','周文璞','宋','宋诗','song-poetry','','[]','麯坊纔盡上湖船，笑問雲山欠酒錢。',32,'全唐诗/poet.song.183000.json','["麯坊纔盡上湖船，笑問雲山欠酒錢。", "兩行柳絲黄不斷，不知身在御園邊。"]'),
('c72f0205-589c-46cf-8177-a0e3bff69e78','壽星寺聞子規二首  其一','周文璞','宋','宋诗','song-poetry','','[]','子規欲歸歸未得，啼向錢王壽星石。',32,'全唐诗/poet.song.183000.json','["子規欲歸歸未得，啼向錢王壽星石。", "月明血盡人不知，只怪曉山深似碧。"]'),
('4a153d1f-ff67-4323-9e74-3cc43cadbe2d','壽星寺聞子規二首  其二','周文璞','宋','宋诗','song-poetry','','[]','莫向空山惱病僧，暮雲臺殿異鄉人。',32,'全唐诗/poet.song.183000.json','["莫向空山惱病僧，暮雲臺殿異鄉人。", "多時不識巴江路，守著濃花哭過春。"]'),
('8cd78243-59b7-42f6-9493-b546668fe883','分夢泉','周文璞','宋','宋诗','song-poetry','','[]','偷得兩泓清，同他猿鳥喫。',36,'全唐诗/poet.song.183000.json','["偷得兩泓清，同他猿鳥喫。", "上下泉邊身，上下床上客。", "相對各相忘，山中小花白。"]'),
('48ec641a-f601-4fd8-8cc9-402f78fb9118','隠者居','周文璞','宋','宋诗','song-poetry','','[]','密竹緣坡便當籬，野泉入戶自成池。',32,'全唐诗/poet.song.183000.json','["密竹緣坡便當籬，野泉入戶自成池。", "床頭一卷麻衣易，更有寒山拾得詩。"]'),
('a2323117-45b5-4da8-a971-a890e8d70d44','逸士墳','周文璞','宋','宋诗','song-poetry','','[]','魂歸魄散兩逍遥，小小丘亭慰寂寥。',32,'全唐诗/poet.song.183000.json','["魂歸魄散兩逍遥，小小丘亭慰寂寥。", "守墓未須耘宿草，白蟾方護紫芝苗。"]'),
('4b49b32f-3913-49b1-b9ab-5f98fc833461','夏日偶題','周文璞','宋','宋诗','song-poetry','','[]','溪友相呼上釣舟，藕花菱葉思悠悠。',32,'全唐诗/poet.song.183000.json','["溪友相呼上釣舟，藕花菱葉思悠悠。", "好詩已在前山寺，寫放參寥石井頭。"]'),
('55442750-19c4-442d-95e9-d02275e11d79','謝頤師見過','周文璞','宋','宋诗','song-poetry','','[]','雲卷道者方晝睡，有僧奚爲入桑杞。',104,'全唐诗/poet.song.183000.json','["雲卷道者方晝睡，有僧奚爲入桑杞。", "惠然相過窮壑底，共談儒流佛宗旨。", "二家之風亦頹靡，吹而颺之誰爲起。", "寒灰煨芋香透紙，呼童就鄰一賒米。", "作糜煮菜相料理，吾窮於世無比擬。", "殷勤相覓有吾子，謾書七字聊送似，往供天嬪泣山鬼。"]'),
('472d9293-a4e8-44d6-bd3b-b3aafd2e3fc8','望茅山六言三首  其一','周文璞','宋','宋诗','song-poetry','','[]','羽衣藥叟歡迎，手執蘭花共行。',28,'全唐诗/poet.song.183000.json','["羽衣藥叟歡迎，手執蘭花共行。", "從此十年不調，可能久視長生。"]'),
('79b470eb-c950-4753-8ace-f23f3a3ff921','望茅山六言三首  其二','周文璞','宋','宋诗','song-poetry','','[]','昔年唱采芝歌，已老頭顱柰何。',28,'全唐诗/poet.song.183000.json','["昔年唱采芝歌，已老頭顱柰何。", "不見飈輪碾處，白雲出沒常多。"]'),
('f81cf83a-1518-469f-91a9-a54c27358a94','望茅山六言三首  其三','周文璞','宋','宋诗','song-poetry','','[]','蔣家兄弟清古，著書互相推宗。',28,'全唐诗/poet.song.183000.json','["蔣家兄弟清古，著書互相推宗。", "摶土劃沙戲劇，穿崗度嶺從容。"]'),
('0d842498-2fc6-45f1-a068-94d51d573c54','寄山中道友三首  其一','周文璞','宋','宋诗','song-poetry','','[]','玉函捧上五雲堆，著意通幽此一回。',32,'全唐诗/poet.song.183000.json','["玉函捧上五雲堆，著意通幽此一回。", "三十年來增悵望，更無人上望僊臺。"]'),
('d6c11de6-0e41-4c79-aab2-270f70f68e70','寄山中道友三首  其二','周文璞','宋','宋诗','song-poetry','','[]','怱怱山信寄來時，中有黄庭七字詩。',32,'全唐诗/poet.song.183000.json','["怱怱山信寄來時，中有黄庭七字詩。", "已死華顛無覓處，幾回吹斷玉參差。"]'),
('73429d51-2129-440e-a5a9-01fe52c025bd','寄山中道友三首  其三','周文璞','宋','宋诗','song-poetry','','[]','憶得尋山復出山，綠楊時候暮春間。',32,'全唐诗/poet.song.183000.json','["憶得尋山復出山，綠楊時候暮春間。", "至今只有游仙夢，長與松風自往還。"]'),
('ce2fac49-4e9a-4442-a28b-72db0c9609de','初營鳳山','周文璞','宋','宋诗','song-poetry','','[]','香草參差種，幽花逐旋移。',48,'全唐诗/poet.song.183000.json','["香草參差種，幽花逐旋移。", "既添醒酒石，須著放生池。", "春在年年好，山來處處奇。", "吹簫吾不解，長嘯却相宜。"]'),
('f6cf1b9c-67eb-4003-b710-ad5cb822ba01','梅谷','周文璞','宋','宋诗','song-poetry','','[]','香焰雲頭玉雪身，緩行微詠岸烏巾。',64,'全唐诗/poet.song.183000.json','["香焰雲頭玉雪身，緩行微詠岸烏巾。", "始從谷裏看脩竹，却向水濱逢麗人。", "客子去時方得月，嶺猿啼後便無春。", "鳳凰欲下簫聲緊，狼籍瀛洲萬斛塵。"]'),
('cd69c0e2-645b-459f-b849-6d4dfc487827','法華小隠','周文璞','宋','宋诗','song-poetry','','[]','偃蓋著地卧，清瑶傍渠走。',120,'全唐诗/poet.song.183000.json','["偃蓋著地卧，清瑶傍渠走。", "散入流觴臺，轉若珠曲九。", "淙淙不知休，還赴石鯨口。", "灣澴合巨澗，橫橋傍蒲柳。", "來看暮春餘，衆綠濃似酒。", "摩挲蘇陳刻，愈覺歲月久。", "寺僧愛光焰，捧送貴侯有。", "至今星散居，各自開戶牖。", "自棄眠雲身，誰縛釣月手。", "夕陽令我歸，爲爾重搔首。"]'),
('fba155ac-9762-4b2d-aae9-85de12e5e378','既離洞霄遇雨却寄道友','周文璞','宋','宋诗','song-poetry','','[]','凡骨何堪得再行，渴心猶要謁通明。',64,'全唐诗/poet.song.183000.json','["凡骨何堪得再行，渴心猶要謁通明。", "驚聞竹樹連山雨，疑有風雷㩧地聲。", "鹿啖黄精知歲久，人逢青箬便神清。", "重來只要齋盂飯，副以常堂枸杞羹。"]'),
('0d874268-6a87-47fc-aaa9-65b8b6107c13','題曹武帝削瓜圖','周文璞','宋','宋诗','song-poetry','','[]','阿瞞瓜分姿，見之垂髫中。',120,'全唐诗/poet.song.183000.json','["阿瞞瓜分姿，見之垂髫中。", "此心既弗乂，此道安可洪。", "漢祚既墜地，餘子方困窮。", "仁義儻自唱，曆數豈不同。", "挾令及宮閫，殺士延奴童。", "至今弔古徒，哀痛殊未終。", "實以己偪仄，遂令彼長雄。", "畫圖出後世，畧見經營工。", "想其鼎峙勢，亦天誘其衷。", "此章弗徒歌，聊以裨國風。"]'),
('ea50cd9d-7859-446e-b8c5-8ea71065bb2c','題蔡武伯所藏荆公硯','周文璞','宋','宋诗','song-poetry','','[]','獸面鼎足奔回互，中有潤澤比雨露。',187,'全唐诗/poet.song.183000.json','["獸面鼎足奔回互，中有潤澤比雨露。", "當年曾出富國疏，老子平生用心處。", "帝謨商頌周六典，刻畫聲形勞解詁。", "至今文字與風騷，一一相輝炫緗素。", "如聞四海失枝梧，可憾諸公欠調護。", "誰令天乎遽如許，可是石也能無預。", "陳玄同歸蔣山路，亦使高人野僧覷。", "若爲持入定林中，應有明雲入天柱。", "吾鄉風流蔡夫子，匣而藏之美無度。", "君不見公鄉後進陸象山，作祠堂記餘千言，直欲百世俟聖賢。", "惜哉不得銘此硯，使我失意心惘然。"]'),
('89b6324a-4861-46b6-8661-0c6200567d9f','歸別墅','周文璞','宋','宋诗','song-poetry','','[]','幽棲久不到，猿鶴擅藤蘿。',48,'全唐诗/poet.song.183000.json','["幽棲久不到，猿鶴擅藤蘿。", "叢篠生將遍，流泉咽更多。", "鄰翁新釀熟，野寺暮鐘和。", "亦有經行者，來觀倚杖歌。"]'),
('30bc7651-c3ed-449b-aceb-44484e6ea358','早起','周文璞','宋','宋诗','song-poetry','','[]','佛香纔了換儒巾，身是人間自在身。',32,'全唐诗/poet.song.183000.json','["佛香纔了換儒巾，身是人間自在身。", "一路野花清養目，半溝流水靜怡神。"]'),
('8e93fde6-be0f-471e-aafa-1a90d040f71f','雨宿山中','周文璞','宋','宋诗','song-poetry','','[]','留連如有情，蕙帳極空明。',48,'全唐诗/poet.song.183000.json','["留連如有情，蕙帳極空明。", "晚粥知泉味，昏鍾度雨聲。", "稍容林叟睡，莫放曉猿驚。", "剩欲剜苔蘚，應當寫姓名。"]'),
('8f619d28-d1c7-4562-9dca-559ea41a0f64','再遊九溪','周文璞','宋','宋诗','song-poetry','','[]','昔年九溪十八澗，今度見之逾清真。',64,'全唐诗/poet.song.183000.json','["昔年九溪十八澗，今度見之逾清真。", "靜依落落石路晚，閑繞寂寂山家春。", "可憐潺湲似留客，更覺曲折能隨人。", "得得杖藜來盡目，野棠山杏亦精神。"]'),
('101364d0-6e99-46f1-8b36-f8546de01812','偶題','周文璞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','海氣江聲相與浮，今時帝里舊杭州。',32,'全唐诗/poet.song.183000.json','["海氣江聲相與浮，今時帝里舊杭州。", "西湖寺裏多金碧，自厭穠華不肯遊。"]'),
('b972d887-5c58-474e-8454-2ca94b5a9e31','送人之官嚴陵','周文璞','宋','宋诗','song-poetry','','[]','如君風貌又精神，自合拖紳近紫宸。',64,'全唐诗/poet.song.183000.json','["如君風貌又精神，自合拖紳近紫宸。", "平地有心開洞穴，十年無俸著閑身。", "已看青舫垂垂去，須憶緋桃灧灧春。", "若向玄英臺下過，爲言亦是學詩人。"]'),
('b9623208-2655-49a2-88de-13bd0c33ee0b','與弁山道士飲','周文璞','宋','宋诗','song-poetry','','[]','采茗歸來日未斜，更携苦菜入仙家。',32,'全唐诗/poet.song.183000.json','["采茗歸來日未斜，更携苦菜入仙家。", "後園同坐枯桐樹，仰看紅桃落澗花。"]'),
('31f2761f-2985-409c-9702-83fd4fdbf2ab','不欺齋','周文璞','宋','宋诗','song-poetry','','[]','陳兄榜名不欺齋，不欺本自誠中來。',91,'全唐诗/poet.song.183000.json','["陳兄榜名不欺齋，不欺本自誠中來。", "晚周洙泗漢伊雒，中間此道寒如灰。", "不欺齋中一尊酒，兄乎此意差耐久。", "真情往往到僮僕，何况親知與朋友。", "君不見湯脫胡桃一語失，此是迂翁年少日，陳兄再拜吾事畢。"]'),
('19608c16-ecd4-47ca-b248-2199a28bc1a3','望雲亭','周文璞','宋','宋诗','song-poetry','','[]','淑氣槃槃接九原，須臾鱗合更瀰漫。',64,'全唐诗/poet.song.183000.json','["淑氣槃槃接九原，須臾鱗合更瀰漫。", "自從蒿里無顔色，來到鍾山有淚痕。", "往者英雄俱雨絕，後來哀痛欲河翻。", "夜深月照長松下，誰見孤飛出墓門。"]'),
('f53e6905-9ae5-48fb-a798-093a160f319c','敬思堂四言','周文璞','宋','宋诗','song-poetry','','[]','有亭央央，高丘之傍。',100,'全唐诗/poet.song.183000.json','["有亭央央，高丘之傍。", "父兮母兮，堅深埋藏。", "厦屋淒涼，宰木成行。", "春秋蒸嘗，酒漿牛羊。", "身體俯傴，雖勞弗彰。", "心志瞀亂，雖煩弗揚。", "欲求幽陰，茫茫洋洋。", "兩間四方，實繫我腸。", "何以照之，明神后皇。", "凡今之人，誰同慨傷。"]'),
('d9399bb4-bfb2-405e-b0a8-8920ac77829c','陳將軍哀詞','周文璞','宋','宋诗','song-poetry','','[]','扞環城兮保赤子，歸王所兮執弓矢。',133,'全唐诗/poet.song.183000.json','["扞環城兮保赤子，歸王所兮執弓矢。", "雖有妻子兮不如兄弟，嗟全家兮南向而死。", "護行殿兮卧旗鼓，統伍符兮莫余侮。", "故宮蕪兮胡作主，哀將軍兮鬢垂素。", "氣力絕兮委塵土，後來孤童兮不勝測楚。", "天陰陰兮春寂寂，曰余兄兮有廟食。", "偕友于兮往作配，駕鐵駟兮載雲旆。", "山中人兮望余歸，江鼯翔兮花亂飛。"]'),
('8c5fb8ab-6f8a-4854-9a7f-e4863bbb2b64','弔青溪姑詞','周文璞','宋','宋诗','song-poetry','','[]','投余兮綠波，彼土偶兮柰何。',52,'全唐诗/poet.song.183000.json','["投余兮綠波，彼土偶兮柰何。", "余魂兮無依，依余兄兮山阿。", "兄姿兮甚雄，青骨兮朱弓。", "稱天兮訴余冤，令讒夫兮不終。"]'),
('a214a22e-69e7-4748-adc5-bad501bdbf8a','水仙廟鼓吹曲四首  其一','周文璞','宋','宋诗','song-poetry','','[]','水奫淪兮不揚，山嶔岑兮多巨石。',37,'全唐诗/poet.song.183000.json','["水奫淪兮不揚，山嶔岑兮多巨石。", "神來下獨舂，仰昂神遠適。", "王孫的咳，神無亟兮。"]'),
('0f663a86-2fdf-4086-94a9-9f647f03ecd1','水仙廟鼓吹曲四首  其二','周文璞','宋','宋诗','song-poetry','','[]','倚碧櫨，款銅鋪，德星在南烏尾逋。',57,'全唐诗/poet.song.183000.json','["倚碧櫨，款銅鋪，德星在南烏尾逋。", "兩峰隠天，花深草蕍。", "錢唐十餘萬戶，皆看史君歡娛。", "雖涉流沙歷炎都，入醫無閭不如東吳。"]'),
('bdc9d68b-2bda-40ba-8218-84d81b4bde6b','水仙廟鼓吹曲四首  其三','周文璞','宋','宋诗','song-poetry','','[]','龍飛天門，鷄鳴日觀。',54,'全唐诗/poet.song.183000.json','["龍飛天門，鷄鳴日觀。", "湖州有鶴知夜半。", "端冕結纓，鋒車施幰。", "瞻彼孤山，男呼女怨。", "欲裂冕毀車，春榮秋枯，無翁愁予。"]'),
('013d7c37-f730-4774-81d3-56ef4c8d4ca5','水仙廟鼓吹曲四首  其四','周文璞','宋','宋诗','song-poetry','','[]','雲冥冥，雷闐闐。',43,'全唐诗/poet.song.183000.json','["雲冥冥，雷闐闐。", "橫玉轉，流珠乾。", "靈龜入我夢，謂君當旋。", "既窮海壖之炎天，當飲山中之流泉。"]'),
('58da29f6-98c9-4f0f-b96b-b571129c2717','招魂','周文璞','宋','宋诗','song-poetry','','[]','天孫召魂，鬼伯催促，千歲之淵不爲谷。',66,'全唐诗/poet.song.183000.json','["天孫召魂，鬼伯催促，千歲之淵不爲谷。", "巉巖既刊，松柏桓桓。", "曰惟君之魂，于茲考槃。", "其永安君窆初成，余以歸藏筮之，其兆蓋如此也。", "嗚呼休哉。"]'),
('35bdee47-d72a-4556-902b-256bfa9ef721','金陵雜詠  其一','周文璞','宋','宋诗','song-poetry','','[]','灩灩江波綠更肥，蒼煙中有鴨鷗飛。',32,'全唐诗/poet.song.183000.json','["灩灩江波綠更肥，蒼煙中有鴨鷗飛。", "當年神武今何在，老却遺民更不歸。"]'),
('29b124e7-c069-4480-8411-4a0457903c38','金陵雜詠  其二','周文璞','宋','宋诗','song-poetry','','[]','長干小婦學吹簫，樓外閒風弄翠條。',32,'全唐诗/poet.song.183000.json','["長干小婦學吹簫，樓外閒風弄翠條。", "近得廣陵消息未，暮潮已過赤欄橋。"]'),
('a9ad38fa-bc9c-4fe0-bd25-5b790442c638','贈陳宗之','周文璞','宋','宋诗','song-poetry','','[]','伊吾聲裏過年年，收拾旁行亦可憐。',64,'全唐诗/poet.song.183000.json','["伊吾聲裏過年年，收拾旁行亦可憐。", "頻嗅芸香心欲醉，爲尋脈望眼應穿。", "哦詩苦似悲秋客，收價清於賣卜錢。", "吳下異書渾未就，每逢佳處輒留連。"]'),
('28257e92-a5bc-437e-8508-27155cf27b77','寄華陽道侶','周文璞','宋','宋诗','song-poetry','','[]','羽扇臨玄圃，霓裳上醮壇。',24,'全唐诗/poet.song.183000.json','["羽扇臨玄圃，霓裳上醮壇。", "九枝松葉冷，千葉杏花殘。"]'),
('b7813bd0-9e41-4a63-ad4d-a4b00b80d1ee','題洞霄宮','周文璞','宋','宋诗','song-poetry','','[]','久知靈境無緣到，今被春風引得來。',64,'全唐诗/poet.song.183000.json','["久知靈境無緣到，今被春風引得來。", "上帝殿頭聞雨過，仙人石面欠花開。", "便燒沈水禮三拜，快引流霞釂一杯。", "落日斷霞催去緊，掉巾祇等白鴉回。"]'),
('045d5474-63dc-4e45-923f-c0f7b9c2960e','句  其一','周文璞','宋','宋诗','song-poetry','','[]','本是離騷國裏人。',8,'全唐诗/poet.song.183000.json','["本是離騷國裏人。"]'),
('5da2e55c-e17f-4a4a-9b88-89b64fd7600e','句  其二','周文璞','宋','宋诗','song-poetry','','[]','衣篝不用綠沉煙。',8,'全唐诗/poet.song.183000.json','["衣篝不用綠沉煙。"]'),
('f84c0ab4-15a7-4bf8-b8bd-2e37de652350','句  其三','周文璞','宋','宋诗','song-poetry','','[]','凄凉一似觀堂僧。',8,'全唐诗/poet.song.183000.json','["凄凉一似觀堂僧。"]'),
('7e3d8d30-403a-49b5-85e9-b2a98648d956','句  其四','周文璞','宋','宋诗','song-poetry','','[]','淡煙疏雨又青山。',8,'全唐诗/poet.song.183000.json','["淡煙疏雨又青山。"]'),
('b25d6c77-8340-4b33-b838-9f2bc4b17c14','句  其五','周文璞','宋','宋诗','song-poetry','','[]','春梅避石開。',6,'全唐诗/poet.song.183000.json','["春梅避石開。"]'),
('9ab2c46c-bf96-406c-b097-293dd6e43ef7','句  其六','周文璞','宋','宋诗','song-poetry','','[]','西陵西又西。',6,'全唐诗/poet.song.183000.json','["西陵西又西。"]'),
('835a09ad-0874-439d-9b28-ac320c34dfb5','句  其七','周文璞','宋','宋诗','song-poetry','','[]','更無花上月。',6,'全唐诗/poet.song.183000.json','["更無花上月。"]'),
('4b6974d1-6704-4633-9ff5-59e326db753e','句  其八','周文璞','宋','宋诗','song-poetry','','[]','戲賡和靖句。',6,'全唐诗/poet.song.183000.json','["戲賡和靖句。"]'),
('2dce500a-6f63-47fd-94bd-afb75625cebb','因痔痛徹心膂爲詩','李坤臣','宋','宋诗','song-poetry','','[]','吾道由來貫古今，纖毫不假外推尋。',32,'全唐诗/poet.song.183000.json','["吾道由來貫古今，纖毫不假外推尋。", "只因疾病呻吟切，識得平生第一心。"]'),
('6cf609fd-2658-4bcc-8027-74bcd9abeb53','瀟湘八景 山市晴嵐','宋寧宗','宋','宋诗','song-poetry','','[]','藪澤趁虛人，崇朝宿雨晴。',48,'全唐诗/poet.song.183000.json','["藪澤趁虛人，崇朝宿雨晴。", "蒼崖林影動，老木日華明。", "野店收煙濕，溪橋流水聲。", "青帘何處是，彷彿聽雞鳴。"]'),
('d53e52a7-71ac-4df7-b085-2dca1021d5b6','瀟湘八景 煙寺晚鐘','宋寧宗','宋','宋诗','song-poetry','','[]','金碧招提古，高峰最上層。',48,'全唐诗/poet.song.183000.json','["金碧招提古，高峰最上層。", "喧風僧入梵，宿霧佛前燈。", "禪觀延空寂，蒲牢忽震凌。", "黄昏山路險，窘步一枝藤。"]'),
('6fb6bbd3-c3d7-4cf8-bc19-4d37675809ad','瀟湘八景 漁村夕照','宋寧宗','宋','宋诗','song-poetry','','[]','林表墮金鴉，孤村三兩家。',48,'全唐诗/poet.song.183000.json','["林表墮金鴉，孤村三兩家。", "晴光明浦溆，紅影带蒹葭。", "傍舍收魚網，隔溪橫釣槎。", "炊煙未篝火，新月一鈎斜。"]'),
('b3fd51c9-dce6-4b6b-9e6f-8d8ae14265c9','瀟湘八景 遠浦帆歸','宋寧宗','宋','宋诗','song-poetry','','[]','劈箭風帆下，春江不盡流。',48,'全唐诗/poet.song.183000.json','["劈箭風帆下，春江不盡流。", "客來登快閣，天際識歸舟。", "裂眥明千里，觀身等一漚。", "斜陽疎木外，五兩不遲留。"]'),
('f82742e8-3a82-4e43-aebe-9092210652de','瀟湘八景 瀟湘夜雨','宋寧宗','宋','宋诗','song-poetry','','[]','清泛三湘夜，中艙聽雨眠。',48,'全唐诗/poet.song.183000.json','["清泛三湘夜，中艙聽雨眠。", "楚天聞過鴈，北舘未歸船。", "濁酒飲無算，青燈冷不煙。", "對床工覓句，達旦見新編。"]'),
('1b496992-bc19-46b8-b213-d4f6e5cb2fc4','瀟湘八景 平沙鴈落','宋寧宗','宋','宋诗','song-poetry','','[]','漂泊楚天長，同群兄弟行。',48,'全唐诗/poet.song.183000.json','["漂泊楚天長，同群兄弟行。", "朔風離塞漠，落日下瀟湘。", "古磧多葭菼，平田足稻粱。", "飛鳴眇空際，布武作文章。"]'),
('020ca9d0-ae28-49b8-84f2-8d51142e35cc','瀟湘八景 洞庭秋月','宋寧宗','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','白水連天遠，吳淞一幅秋。',48,'全唐诗/poet.song.183000.json','["白水連天遠，吳淞一幅秋。", "橘洲冰魄滿，竹閣桂華留。", "鳬雁不飲啄，魚龍與拍浮。", "垂虹寓今夕，清勝庾公樓。"]'),
('b2e10326-4cf5-4965-8944-f58ff71bc7ad','瀟湘八景 江天暮雪','宋寧宗','宋','宋诗','song-poetry','','[]','朔吹掃氛埃，同雲暝不開。',48,'全唐诗/poet.song.183000.json','["朔吹掃氛埃，同雲暝不開。", "千山飛鳥盡，一水泝舟回。", "波面散鉛汞，林梢已瀉瑰。", "懷人留剡棹，野店且新醅。"]'),
('975cce1a-9762-4c89-af0d-00ebd9bc284e','賜狀元蔡仲龍','宋寧宗','宋','宋诗','song-poetry','','[]','聯魁金玉龍頭選，詔下今朝遇己知。',64,'全唐诗/poet.song.183000.json','["聯魁金玉龍頭選，詔下今朝遇己知。", "上國風光初曉日，御階恩渥暮春時。", "內庭考最稱文異，臚唱宣名奬意奇。", "故里仙才若相問，一年攀折兩重枝。"]'),
('e9d31ca4-367e-438a-b210-40d4b236979c','題馬遠踏歌圖','宋寧宗','宋','宋诗','song-poetry','','[]','宿雨清畿甸，朝陽麗帝城。',24,'全唐诗/poet.song.184000.json','["宿雨清畿甸，朝陽麗帝城。", "豐年人樂業，壠上踏歌行。"]'),
('6da7f25e-840b-4797-b38d-c6f6c049f609','贈朱質','宋寧宗','宋','宋诗','song-poetry','','[]','袖手長才世路輕，愛閑那有鬻榮名。',64,'全唐诗/poet.song.184000.json','["袖手長才世路輕，愛閑那有鬻榮名。", "挂冠便欲辭丹闕，策杖還歸老故城。", "適喜不求三仕喜，傳家惟有十分清。", "林間佳處真恬退，好向廉泉自濯纓。"]'),
('1f311c95-7fe0-4ea9-bb74-a39158195319','山居  其一','龔大明','宋','宋诗','song-poetry','','[]','山居好，山居好，鶴唳猿啼餞昏曉。',32,'全唐诗/poet.song.184000.json','["山居好，山居好，鶴唳猿啼餞昏曉。", "碧窗柏子炷爐香，趺坐蒲團誦黄老。"]'),
('90ce89e6-8420-43c7-8290-42fb7669a875','山居  其二','龔大明','宋','宋诗','song-poetry','','[]','山居好，山居好，門對青山水環遶。',32,'全唐诗/poet.song.184000.json','["山居好，山居好，門對青山水環遶。", "一榻煙霞夢寐清，我以不貪爲至寶。"]'),
('0e913840-f985-48cc-8102-fe91d0d78508','山居  其三','龔大明','宋','宋诗','song-poetry','','[]','山居好，山居好，竹杖芒鞋恣幽討。',32,'全唐诗/poet.song.184000.json','["山居好，山居好，竹杖芒鞋恣幽討。", "坐分苔石樹陰涼，閒數落花聽啼鳥。"]'),
('be9a14e7-0d4e-4669-828b-0953027dcd0b','山居  其四','龔大明','宋','宋诗','song-poetry','','[]','山居好，山居好，斸月鋤雲種瑶草。',32,'全唐诗/poet.song.184000.json','["山居好，山居好，斸月鋤雲種瑶草。", "泠泠碧澗響寒泉，蔌蔌落花風自掃。"]'),
('fac588f2-8664-4de5-b4be-4f295293e4bd','贈道友雪崖朱先生','龔大明','宋','宋诗','song-poetry','','[]','清高絕，雪崖翁，向上元機頓觀通。',32,'全唐诗/poet.song.184000.json','["清高絕，雪崖翁，向上元機頓觀通。", "金鼎有丹成九轉，凝然宴坐白雲中。"]'),
('c6ba1d75-8ce0-4513-b335-137a4d435319','贈道友怡雲潘先生','龔大明','宋','宋诗','song-poetry','','[]','九轉工夫真妙絕，丹爐進火徐徐熱。',64,'全唐诗/poet.song.184000.json','["九轉工夫真妙絕，丹爐進火徐徐熱。", "離龍坎虎自歸降，姹女嬰兒共歡悅。", "天機密運造元微，精采神光迥然別。", "枝頭結果有時紅，驂鸞跨鶴神仙列。"]'),
('c81601c1-ae0e-4846-8c1a-47ff9d4cff49','南湖','龔大明','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅霖初歇水平湖，湖上青山展畫圖。',32,'全唐诗/poet.song.184000.json','["梅霖初歇水平湖，湖上青山展畫圖。", "更著樓臺相掩映，風流端不減西湖。"]'),
('f8fe219e-c648-46ba-a53a-5a940d9a8ae6','和鶴林吳泳題艮泓軒','龔大明','宋','宋诗','song-poetry','','[]','知與坡仙有宿盟，來賢巖畔舊經行。',64,'全唐诗/poet.song.184000.json','["知與坡仙有宿盟，來賢巖畔舊經行。", "節同老柏歲寒操，心契焦桐太古聲。", "雲出九峰龍起蟄，風清五夜鶴傳鳴。", "須公一柱擎天力，妙斡洪鈞大發生。"]'),
('ff4e8dae-7dd8-4d4d-935f-ba8660224774','詩一首','章康','宋','宋诗','song-poetry','','[]','掩關作夏計，長日獨清坐。',48,'全唐诗/poet.song.184000.json','["掩關作夏計，長日獨清坐。", "戎葵競自花，安榴粲成朵。", "時芳詎容歇，幽賞無不可。", "微風忽吹來，諒亦深知我。"]'),
('cd7e8381-66ca-4716-b035-b6d43f4f5d70','秋興','章康','宋','宋诗','song-poetry','','[]','有客凋雙鬢，吟秋費幾詩。',48,'全唐诗/poet.song.184000.json','["有客凋雙鬢，吟秋費幾詩。", "天高鳥去疾，雲薄雨來遲。", "日落山川迥，風回草木悲。", "追尋十年事，佇立獨多時。"]'),
('8bdb620b-6ae9-4db6-9358-0102cca2818f','遷居親戚携酒見過','章康','宋','宋诗','song-poetry','','[]','老吾元住雪邊崖，萬事無堪兩鬢華。',64,'全唐诗/poet.song.184000.json','["老吾元住雪邊崖，萬事無堪兩鬢華。", "頃歲西河方借宅，今年東野又般家。", "巷深政恐難邀客，地空何妨學種花。", "多謝所親相暖熱，新生涯即舊生涯。"]'),
('485b23a0-83f8-4cff-a126-017444f9f039','遊龍山','章康','宋','宋诗','song-poetry','','[]','名山久相望，今日爲著屐。',168,'全唐诗/poet.song.184000.json','["名山久相望，今日爲著屐。", "到寺第一義，古松互蟠屈。", "一一龍蛇形，風雷氣蕭瑟。", "纓絡檜兩株，皆數百年物。", "燈耿青熒熒，像設暗金碧。", "空廊極徘徊，老屋共崪兀。", "僧房小槃礴，西原訪泉石。", "於其最幽絕，似可便築室。", "因而思古人，多有愛山癖。", "要之亦何爲，一賞事已畢。", "上方不及登，尚或俟他日。", "無非會心處，妙同箭鋒直。", "山靈謂何如，移文茲不必。", "作詩留山中，併可告來轍。"]'),
('1f93f958-4b05-4007-b473-01f9af00ecc8','犁春操爲謝耕道作','黄簡','宋','宋诗','song-poetry','','[]','東山兮雲浮，東磵兮雨流。',87,'全唐诗/poet.song.184000.json','["東山兮雲浮，東磵兮雨流。", "失今不勤兮，曷其有秋。", "水淫兮石齧，田碻磝兮一跬九折。", "予勞兮何辭，牛奚罪兮從予以羸。", "眇良疇兮彌野，獨功倍兮刈寡。", "雖然不愈於無田而游兮，歲晏淒其桑落之下。"]'),
('409a4e8e-ccc8-4f1c-bfb9-cd3ff6acd978','秋懷寄陳宗之','黄簡','宋','宋诗','song-poetry','','[]','秋聲四壁動，寒事日駸駸。',48,'全唐诗/poet.song.184000.json','["秋聲四壁動，寒事日駸駸。", "紅剝林閒子，青除架底陰。", "積閒殊有味，安拙本無心。", "獨愧陳徵士，賒書不問金。"]'),
('3e828b8c-b5f6-4cfd-9600-f6dc80630e58','招荆江游子','黄簡','宋','宋诗','song-poetry','','[]','衝風逐飛雲，庭葉紛墜槁。',48,'全唐诗/poet.song.184000.json','["衝風逐飛雲，庭葉紛墜槁。", "蕩子久不歸，佳人坐中老。", "蕭蕭楚山晚，湛湛江水流。", "經從望夫石，那得不回頭。"]'),
('d7e25f48-b16d-4294-9817-dc944c866df2','登武昌南樓','黄簡','宋','宋诗','song-poetry','','[]','十萬鱗鱗俯繡甍，拂雲自舊侈崢嶸。',64,'全唐诗/poet.song.184000.json','["十萬鱗鱗俯繡甍，拂雲自舊侈崢嶸。", "江趨座右雙流合，山入屏閒八字橫。", "禰史醉魂荒樹遠，庾郎塵骨古苔生。", "興來朗拍欄干立，不必重騎碧海鯨。"]'),
('5803d9c6-2065-49ac-9c4c-6f32c8e39344','過沈尚書墓','黄簡','宋','宋诗','song-poetry','','[]','履聲推早達，日燕自林泉。',48,'全唐诗/poet.song.184000.json','["履聲推早達，日燕自林泉。", "浮世若無死，貴人真是仙。", "從容將八袠，掩忽便千年。", "墓上青松合，豐碑竟不鎸。"]'),
('6a1f5698-051d-441b-b6ce-99f885f59472','懷古','黄簡','宋','宋诗','song-poetry','','[]','翠裹紅遮艷粉圍，春風夜夜可曾歸。',32,'全唐诗/poet.song.184000.json','["翠裹紅遮艷粉圍，春風夜夜可曾歸。", "十年再撫章臺馬，巷陌人家大半非。"]'),
('7a31be4d-b9d7-4d5c-8fd0-747b58febc63','公無渡河','黄簡','宋','宋诗','song-poetry','','[]','公無渡河，公無渡河，止公不已將柰何。',50,'全唐诗/poet.song.184000.json','["公無渡河，公無渡河，止公不已將柰何。", "九淵噴雪舞饞鱷，百里吼雷翻怒鼉。", "平地往往猶風波，况此瀰漫秋水多。"]'),
('5f756dc1-b716-4b34-9caa-b3d8ca1ee4d6','漫成','黄簡','宋','宋诗','song-poetry','','[]','在俗參寥子，無田靖節翁。',48,'全唐诗/poet.song.184000.json','["在俗參寥子，無田靖節翁。", "心平詩少怨，胃弱酒多中。", "熇熇蒸梅日，離離脫葉風。", "未應悲歲晏，端合幸年豐。"]'),
('30347fd1-6492-4c02-abec-28c2fb1a245b','遊浯溪','劉用行','宋','宋诗','song-poetry','','[]','祿兒豈解傾唐祚，獨使斯文壽兩翁。',64,'全唐诗/poet.song.184000.json','["祿兒豈解傾唐祚，獨使斯文壽兩翁。", "蜀道至今遺舊話，湘流澈底照孤忠。", "摧風溜雨中興字，轉地回天克復功。", "人說蒼崖磨向盡，不知磨盡幾英雄。"]'),
('54113137-f81c-4953-90dd-8899988e6d8c','無爲縣齋古梅','劉用行','宋','宋诗','song-poetry','','[]','疎疎密密卧簷牙，古縣清貧有此花。',64,'全唐诗/poet.song.184000.json','["疎疎密密卧簷牙，古縣清貧有此花。", "彭澤菊松無醖藉，河陽桃李太鉛華。", "臨池照影成雙好，與雪爭輝自一家。", "消得抱琴鳴膝上，夜深燃燭對瓊葩。"]'),
('68dfebd7-11e0-4400-a345-2aba9ca5af8a','題倉部袁公灼像','傅行簡','宋','宋诗','song-poetry','','[]','筮仕當前職度支，平衡清操畏人知。',64,'全唐诗/poet.song.184000.json','["筮仕當前職度支，平衡清操畏人知。", "宣恭在位和同列，理學傳家重一時。", "能擊武臣强似虎，寧□宰執怒如獅。", "□□猶有弦歌化，治譜真堪百世師。"]'),
('3645882c-1c4c-4709-9740-3a8ae5c862f0','題博士袁公文苑像','傅行簡','宋','宋诗','song-poetry','','[]','禽鳥春風樂與同，有將理趣道儒宗。',64,'全唐诗/poet.song.184000.json','["禽鳥春風樂與同，有將理趣道儒宗。", "兩朝褒賞衣冠舊，一德充融禮樂隆。", "天地無心馳電馬，人民有望慰雲龍。", "餘年八十無全食，獨抱青山繼祖風。"]'),
('ac1a4329-44bb-42f1-b242-da3e3989b339','賦宮人午睡','李獻可','宋','宋诗','song-poetry','','[]','御手指嬋娟，青春白晝眠。',48,'全唐诗/poet.song.184000.json','["御手指嬋娟，青春白晝眠。", "粉勻香汗濕，髻壓翠雲偏。", "柳妒眉間綠，桃嫌臉上鮮。", "夢魂何處是，應繞帝王邊。"]'),
('f28aaf5d-1674-4edb-9ab7-892a1a952698','玉泉山','楊叔蘭','宋','宋诗','song-poetry','','[]','人生天地間，今古一□觀。',168,'全唐诗/poet.song.184000.json','["人生天地間，今古一□觀。", "凌空絕虛曠，萬象羅巖巒。", "能一故□應，物化千□端。", "萬端總歸一，唯悟無□言。", "舊聞□□翁，獨釣江之干。", "不知歲月深，但覺□□寬。", "我思一訪之，意會心□看。", "作亭號□隠，半空摩高寒。", "時與二三友，登臨尋□歡。", "致君知無術，隨世聊自安。", "滾滾□下水，舟舟皆濟川。", "川流無津涯，舟去□復還。", "時聆二三策，使我心茫然。", "伊周在何許，鄉風一長歎。"]'),
('26c3db6a-d0ef-44b7-b5da-84f7991e009c','挽蔡西山先生','翁陞','宋','宋诗','song-poetry','','[]','傷哉道學不容時，力抵先生蹈至危。',64,'全唐诗/poet.song.184000.json','["傷哉道學不容時，力抵先生蹈至危。", "槐棘僉謀雖日僞，草茅公論實難欺。", "蒼梧千里地雖遠，白首一心天自知。", "借問西山近何似，白雲長護紫陽碑。"]'),
('6d7b8ae1-3a4c-4cfe-a450-dc5bdb2e100c','浯溪','趙善𧪞','宋','宋诗','song-poetry','','[]','兩載真成漫浪遊，豐碑重拂倍含羞。',64,'全唐诗/poet.song.184000.json','["兩載真成漫浪遊，豐碑重拂倍含羞。", "空憐民力疲芻粟，濫厠時賢動冕旒。", "病骨詎堪勝重寄，歸舟喜不負清流。", "家山屈指朝朝□，□老休勞念□□。"]'),
('7cad1999-27a6-42f7-8c9f-36c67ca80f12','寶華巖','趙善𧪞','宋','宋诗','song-poetry','','[]','寶色晴光合，浮嵐薄翠微。',48,'全唐诗/poet.song.184000.json','["寶色晴光合，浮嵐薄翠微。", "天開今覺路，洞鎖古神扉。", "淡拂山僧帽，閑隨野客衣。", "日斜涼吹起，林壑更依依。"]'),
('f0c72609-af80-46a7-b8c7-5578ab98aaf0','聖水寺','張衜','宋','宋诗','song-poetry','','[]','聖水山南蓮萼輝，徘徊花下蝶雙飛。',32,'全唐诗/poet.song.184000.json','["聖水山南蓮萼輝，徘徊花下蝶雙飛。", "春風助我晨遊興，月上層巒照拂衣。"]'),
('6e974ae5-6cb5-4fbe-b577-97c79a125000','禪師塔次韵','劉曈','宋','宋诗','song-poetry','','[]','皓月孤懸處，知師幾駐筇。',48,'全唐诗/poet.song.184000.json','["皓月孤懸處，知師幾駐筇。", "鐵鞋雖踏破，隻履覓無從。", "傳法燈燈火，聞經處處龍。", "可憐狂醉客，夜坐謾搥鐘。"]'),
('bc100022-c755-4a24-8f64-3a6dac994c0a','皇帝閤春帖子  其一','許應龍','宋','宋诗','song-poetry','','[]','日向皇都永，冰從太液融。',24,'全唐诗/poet.song.184000.json','["日向皇都永，冰從太液融。", "青陽纔轉律，物物被和風。"]'),
('205601ae-0272-4271-809b-8907c040ecc5','皇帝閤春帖子  其二','許應龍','宋','宋诗','song-poetry','','[]','寬大書方布，歡聲四海同。',24,'全唐诗/poet.song.184000.json','["寬大書方布，歡聲四海同。", "陽春如有脚，造物不言功。"]'),
('5cda98a2-4c29-4b84-b1f3-fd86ddbaabb2','皇帝閤春帖子  其三','許應龍','宋','宋诗','song-poetry','','[]','聖德乾坤大，皇圖日月長。',24,'全唐诗/poet.song.184000.json','["聖德乾坤大，皇圖日月長。", "遠人咸畏慕，國勢寖安强。"]'),
('96329d71-edad-4da6-bcd3-471735004aba','皇帝閤春帖子  其四','許應龍','宋','宋诗','song-poetry','','[]','金華綵勝年年巧，柏酒椒盤歲歲新。',32,'全唐诗/poet.song.184000.json','["金華綵勝年年巧，柏酒椒盤歲歲新。", "恭願吾皇千萬壽，四時無日不陽春。"]'),
('c368e44f-0966-4afb-ac55-f01e8c9fd66d','皇帝閤春帖子  其五','許應龍','宋','宋诗','song-poetry','','[]','三白從來兆歲豐，幾看瑞雪舞回風。',32,'全唐诗/poet.song.184000.json','["三白從來兆歲豐，幾看瑞雪舞回風。", "蒼龍掛闕農祥正，擊壤行歌我稼同。"]'),
('afec757f-2383-4df6-b3e2-e6c8bc398c3e','皇帝閤春帖子  其六','許應龍','宋','宋诗','song-poetry','','[]','東風昨夜掃氛埃，四表咸欣壽域開。',32,'全唐诗/poet.song.184000.json','["東風昨夜掃氛埃，四表咸欣壽域開。", "都護已飛三捷奏，凌煙同上萬年杯。"]'),
('b234ff6d-7dd4-4211-be94-a93363734c11','皇后閤春帖子  其一','許應龍','宋','宋诗','song-poetry','','[]','一氣轉洪鈞，陽和觸處新。',24,'全唐诗/poet.song.184000.json','["一氣轉洪鈞，陽和觸處新。", "上林春更早，草木已精神。"]'),
('592f0395-b81c-49c2-a471-b2f395a22631','皇后閤春帖子  其二','許應龍','宋','宋诗','song-poetry','','[]','一歲兩逢春，皇都景物新。',24,'全唐诗/poet.song.184000.json','["一歲兩逢春，皇都景物新。", "發生何處早，甲拆驗莊椿。"]'),
('371ec0eb-2fbb-4c15-9b4d-34ff49df4846','皇后閤春帖子  其三','許應龍','宋','宋诗','song-poetry','','[]','椒殿霞觴舉，金花拆勝鮮。',24,'全唐诗/poet.song.184000.json','["椒殿霞觴舉，金花拆勝鮮。", "年年慶佳節，眉壽祝綿延。"]'),
('02e05ce2-86f7-4fe9-80a9-134c4d3ffaa0','皇后閤春帖子  其四','許應龍','宋','宋诗','song-poetry','','[]','日融閬苑紅初露，冰泮瑶池碧半涵。',32,'全唐诗/poet.song.184000.json','["日融閬苑紅初露，冰泮瑶池碧半涵。", "管取新年多勝事，當知風化自周南。"]'),
('4c791bb1-3367-40f3-86c7-cf85da9324f9','皇后閤春帖子  其五','許應龍','宋','宋诗','song-poetry','','[]','臘前三白兆年豐，即更彌旬雪滿空。',32,'全唐诗/poet.song.184000.json','["臘前三白兆年豐，即更彌旬雪滿空。", "歲籥未經春已到，從今物物被和風。"]'),
('cb18ad78-5742-4190-9fbf-725ac093d775','貴妃閤春帖子  其一','許應龍','宋','宋诗','song-poetry','','[]','木德新回律，瓊壺暖不冰。',24,'全唐诗/poet.song.184000.json','["木德新回律，瓊壺暖不冰。", "舉頭聞鵲喜，翔舞下觚稜。"]'),
('788ee85a-19b1-49a8-85e6-fd860aaabd87','貴妃閤春帖子  其二','許應龍','宋','宋诗','song-poetry','','[]','月射璇題爛，風傳玉漏清。',24,'全唐诗/poet.song.184000.json','["月射璇題爛，風傳玉漏清。", "仰瞻雲漢表，輝潤四星明。"]'),
('a6078a2e-db63-483f-9c06-44dcdb99611e','貴妃閤春帖子  其三','許應龍','宋','宋诗','song-poetry','','[]','昨夜東風入律新，朝來蕙露凈無塵。',32,'全唐诗/poet.song.184000.json','["昨夜東風入律新，朝來蕙露凈無塵。", "玉觴椒酒陪歡宴，總道今春勝舊春。"]'),
('cd4e6d32-ed73-430c-aae4-c0d740a33047','貴妃閤春帖子  其四','許應龍','宋','宋诗','song-poetry','','[]','賢哉淑德繼雞鳴，密贊關雎美化行。',32,'全唐诗/poet.song.184000.json','["賢哉淑德繼雞鳴，密贊關雎美化行。", "夙夜若爲勤警戒，始終一念欲相成。"]'),
('3072ca62-6926-4023-9232-832e69f07677','貴妃閤春帖子  其五','許應龍','宋','宋诗','song-poetry','','[]','翠管銀罌舊事傳，新春賸喜在新年。',32,'全唐诗/poet.song.184000.json','["翠管銀罌舊事傳，新春賸喜在新年。", "巧裁綵勝迎佳節，更祝君王壽萬千。"]'),
('443b4b5d-3976-47ac-90d7-be9080251534','皇帝閤端午帖子  其一','許應龍','宋','宋诗','song-poetry','','[]','卑服即康功，君王儉德隆。',24,'全唐诗/poet.song.184000.json','["卑服即康功，君王儉德隆。", "却頒羅與葛，恩渥被羣工。"]'),
('4d419445-e1a6-4980-a11e-e78579648a32','皇帝閤端午帖子  其二','許應龍','宋','宋诗','song-poetry','','[]','內外期無患，兢兢理萬幾。',24,'全唐诗/poet.song.184000.json','["內外期無患，兢兢理萬幾。", "延英勤講論，遑恤汗沾衣。"]'),
('37f950c3-bd9a-4925-9613-f3aa5905ad5b','皇帝閤端午帖子  其三','許應龍','宋','宋诗','song-poetry','','[]','清凈無他好，歌風舞舜琴。',24,'全唐诗/poet.song.184000.json','["清凈無他好，歌風舞舜琴。", "阜財并解慍，總是愛民心。"]'),
('c245c644-588c-4ea3-ae16-c7154561d00c','皇帝閤端午帖子  其四','許應龍','宋','宋诗','song-poetry','','[]','離明赫赫正當中，萬物咸欣長養風。',32,'全唐诗/poet.song.184000.json','["離明赫赫正當中，萬物咸欣長養風。", "隴麥已登蠶又熟，更多膏澤兆年豐。"]'),
('6e7b15d3-ddd3-47d4-8116-134711c03721','皇帝閤端午帖子  其五','許應龍','宋','宋诗','song-poetry','','[]','誕敷文德洽寰區，赳赳明明運廟謨。',32,'全唐诗/poet.song.184000.json','["誕敷文德洽寰區，赳赳明明運廟謨。", "自是不爭應善勝，何須更佩辟兵符。"]'),
('b14ae193-3490-4abc-8bc5-1518416a9693','皇帝閤端午帖子  其六','許應龍','宋','宋诗','song-poetry','','[]','殿閣涼生晝景長，翠煙縹渺御爐香。',32,'全唐诗/poet.song.184000.json','["殿閣涼生晝景長，翠煙縹渺御爐香。", "經帷講罷看章疏，至昃猶聞食未遑。"]'),
('e6bc9087-5802-4114-aae3-ab295aac1c09','皇后閤端午帖子  其一','許應龍','宋','宋诗','song-poetry','','[]','玉切菖蒲細，金包黍角香。',24,'全唐诗/poet.song.184000.json','["玉切菖蒲細，金包黍角香。", "年年慶佳節，燕衎侍君王。"]'),
('3f2fdcbe-3231-469d-8041-d58b58fe78c6','皇后閤端午帖子  其二','許應龍','宋','宋诗','song-poetry','','[]','寶篆煙輕繞，瑶臺日正中。',24,'全唐诗/poet.song.184000.json','["寶篆煙輕繞，瑶臺日正中。", "等閑調玉瑟，聊助舜琴風。"]'),
('956dead1-6994-410c-8cdc-eca564d45eb9','皇后閤端午帖子  其三','許應龍','宋','宋诗','song-poetry','','[]','重午宮衣賜百工，香羅疊雪葛含風。',32,'全唐诗/poet.song.184000.json','["重午宮衣賜百工，香羅疊雪葛含風。", "誰知此日榮恩被，端自稱絲效繭功。"]'),
('e0cfbe87-23ca-4e15-9ba3-a60b4f3167fc','皇后閤端午帖子  其四','許應龍','宋','宋诗','song-poetry','','[]','辟邪不用符爲佩，續命何須綵結絲。',32,'全唐诗/poet.song.184000.json','["辟邪不用符爲佩，續命何須綵結絲。", "逮下徽音繼樛木，穰穰福履已來綏。"]'),
('34ae0533-65f6-4543-ab20-eea5b2a1c981','皇后閤端午帖子  其五','許應龍','宋','宋诗','song-poetry','','[]','三千玉女鬭羣芳，並蓄兼收百藥良。',32,'全唐诗/poet.song.184000.json','["三千玉女鬭羣芳，並蓄兼收百藥良。", "咸願東皇與西母，無窮眉壽等天長。"]'),
('6c7dc4b6-e8aa-432c-b231-0900ada327d4','貴妃閤端午帖子  其一','許應龍','宋','宋诗','song-poetry','','[]','擷秀鬭羣芳，兼收百藥良。',24,'全唐诗/poet.song.184000.json','["擷秀鬭羣芳，兼收百藥良。", "不因仁及物，庶草曷蕃昌。"]'),
('d4aabeeb-91bc-46c4-b3f8-14c903b0f5e4','貴妃閤端午帖子  其二','許應龍','宋','宋诗','song-poetry','','[]','淑德儀宮閫，天教受祉繁。',24,'全唐诗/poet.song.184000.json','["淑德儀宮閫，天教受祉繁。", "艾人暨桃印，奚用更懸門。"]'),
('cfd2f818-3387-4527-adf1-15e87094b258','貴妃閤端午帖子  其三','許應龍','宋','宋诗','song-poetry','','[]','丹篆釵符綵縷鮮，承恩侍宴玉皇前。',32,'全唐诗/poet.song.184000.json','["丹篆釵符綵縷鮮，承恩侍宴玉皇前。", "一年一度爲端午，此去應須億萬年。"]'),
('25a258d8-b10f-436b-95b6-cf11d4024d99','貴妃閤端午帖子  其四','許應龍','宋','宋诗','song-poetry','','[]','裁成御服進君王，霧縠雲綃疊雪香。',32,'全唐诗/poet.song.184000.json','["裁成御服進君王，霧縠雲綃疊雪香。", "却效葛覃躬節用，不忘澣濯舊衣裳。"]'),
('2677a7b8-7502-4cc9-88b4-ab6febd21432','貴妃閤端午帖子  其五','許應龍','宋','宋诗','song-poetry','','[]','檻有榴花沼有蓮，南薰拂拂晚涼天。',32,'全唐诗/poet.song.184000.json','["檻有榴花沼有蓮，南薰拂拂晚涼天。", "六宮莫度新翻曲，只理雲和伴舜絃。"]'),
('3e067f0a-6d92-4ef2-8e32-fe3725ccb93c','次韵張太博方得余所遺二程先生集辨二程戲邵子語','許應龍','宋','宋诗','song-poetry','','[]','文字未科斗，圖書未龜龍。',264,'全唐诗/poet.song.184000.json','["文字未科斗，圖書未龜龍。", "燦然天地間，此理觸處逢。", "是謂象之祖，而爲數之宗。", "昊羲古神聖，先得人所同。", "文因而繇之，旦出亦並雄。", "訖于我孔聖，天命滋益恭。", "渾然一理貫，密察而從容。", "辭變于象占，四者固所崇。", "推時以知變，象占在其中。", "荒荒秦漢後，學者昧所從。", "不以災異會，則以虛無通。", "天開周氏子，易道乃復東。", "動靜靜復動，終始始而終。", "上承千年緒，下起百世風。", "同時有邵子，講道于伊嵩。", "天地之運化，陰陽之無窮。", "即物驗消長，先機知吉凶。", "邵子極道數，獨立幾無戎。", "二程闡周孔，爲時開矇矇。", "其歸則一耳，昧者結忡忡。", "學之將奈何，矧余倍顓蒙。", "要知羲皇心，須踏周孔蹤。"]'),
('f6c4903a-81fe-4108-bc2d-d60832d771a7','送天台李守','許應龍','宋','宋诗','song-poetry','','[]','天台罹洚水，平陸幾成淵。',216,'全唐诗/poet.song.184000.json','["天台罹洚水，平陸幾成淵。", "經理閲再禩，民瘼猶未痊。", "將令田里安，須得牧守賢。", "疇咨能俾乂，僉曰蓬萊仙。", "君侯寬且明，履節金石堅。", "吏事素精敏，公心無黨偏。", "分符膺重寄，爲政將奚先。", "租賦盍蠲減，獄訟無淹延。", "姦黠須禁戢，阨窮當憫憐。", "庶銷愁嘆聲，播作謠頌傳。", "使華聞有命，丹書下日邊。", "復使茲郡民，鼓舞戴二天。", "政成徹丹扆，驛召歸甘泉。", "嗟予十載間，稠疊同班聯。", "學館暨郎省，昕夕相周旋。", "喜君駕朱轓，恨我違英躔。", "同寅舉餞觴，佳句聯華牋。", "枯腸强搜索，綴緝僅成篇。"]'),
('1f6f0ce6-23bc-4f7d-b511-d8e3952ddc16','送楊郎中守嘉興','許應龍','宋','宋诗','song-poetry','','[]','君昨倅嘉禾，施設皆儒者。',144,'全唐诗/poet.song.184000.json','["君昨倅嘉禾，施設皆儒者。", "千里稱廉平，六邑荷寬假。", "海沂雖頼祥，宣室俄思賈。", "召還甫再朞，出守榮五馬。", "舊治聞重來，懽呼溢田野。", "正苦夏日炎，將沐秋霖灑。", "君侯寬且明，義利審取舍。", "願推一片心，大作萬間厦。", "苛斂戒分肥，嚴刑去衣赭。", "當令愁嘆聲，轉作詩歌寫。", "如君梁棟才，一麾寧久把。", "祇虞席未溫，又賦公歸雅。"]'),
('398b5937-4824-40fa-bf74-c14a1a5e8ef7','送人赴倉臺','許應龍','宋','宋诗','song-poetry','','[]','帝念畿甸民，財力俱有限。',132,'全唐诗/poet.song.184000.json','["帝念畿甸民，財力俱有限。", "俗吏肆貪殘，侵漁蕩貲産。", "致治在得賢，刺史尤當揀。", "明公如范滂，清節邁楊綰。", "疏寵畀倉臺，一道俱刮眼。", "糴貴望公平，斂苛冀公剗。", "察吏貴精明，臨民當敬簡。", "高才固優爲，佇見鳩功僝。", "將令愁嘆民，喜至笑聲莞。", "繡節暫馳驅，玉堂資著譔。", "行矣促公歸，餞行聊舉盞。"]'),
('d80cdf02-4247-49a1-999a-07e9b4f5515b','贈韓倅','許應龍','宋','宋诗','song-poetry','','[]','鳳城久矣欽韓公，華胄重來振祖風。',160,'全唐诗/poet.song.184000.json','["鳳城久矣欽韓公，華胄重來振祖風。", "關决藩條明且恕，待人接物春融融。", "散爲和氣徧南土，雨順年豐民按堵。", "海沂雖喜頼王祥，驥足治中難久駐。", "向來文惠倅瀛洲，藉藉聲名動冕旒。", "願君凌厲紹前美，南澗事業當同休。", "于今且慶生申旦，敬爇瓣香祈鶴算。", "中秋節近月嬋娟，正好平分通夕宴。", "君家自有舊氈青，合上星辰聽履聲。", "明年此會知何處，宣勸黄封下帝廷。"]'),
('b2ae5797-c6c4-44a6-952a-b6a368c5a620','贈林倅','許應龍','宋','宋诗','song-poetry','','[]','元是清都紫府仙，出爲名世應半千。',192,'全唐诗/poet.song.184000.json','["元是清都紫府仙，出爲名世應半千。", "發矢兩科俱中的，英名烜赫斗橫天。", "鄞水富沙典芹泮，黜浮崇雅文風煥。", "沙陽之政寬而明，吏不忍欺民不玩。", "雙飛鳬舄造皇州，三台八座俱挽留。", "辭榮避寵姑別駕，恬退高節前無儔。", "千里提封勤贊理，恕以待人嚴律己。", "一輪秋月照無私，百尺春潭清見底。", "須知作善天降祥，俾耆而艾壽而臧。", "萱闈朱顔映蒼鬢，詵詵蘭玉如鸞翔。", "匪伊丹詔日邊至，策足烏臺陟端揆。", "年年衮繡舞萊衣，瑶池屢獻蟠桃瑞。"]'),
('d25d7b66-33da-4d42-921e-b116d59bcaa9','代上何樞密','許應龍','宋','宋诗','song-poetry','','[]','宋元憲公王沂公，妙齡擢第魁南宮。',288,'全唐诗/poet.song.184000.json','["宋元憲公王沂公，妙齡擢第魁南宮。", "清華歷徧陞諫省，雍容二府亮天工。", "却斂經綸來望郡，一鎮天雄一鎮鄆。", "政聲洋溢徹宸聰，丹詔紫泥催入覲。", "廟堂端委秉鈞衡，致君堯舜風俗醇。", "至今景祐皇祐治，振蕩人耳如雷霆。", "巍巍勳績誰能繼，三嘆真賢生不世。", "豈知今日元樞公，矯翼天衢更凌厲。", "禮闈得雋冠羣英，旋登言路攖龍鱗。", "運籌帷幄參宥密，翻私雨露澤全閩。", "生平出處總相契，左揆尚虛天有意。", "宣麻指日下彤廷，整頓乾坤邁前美。", "萱堂正富八十春，綵衣輝映衮衣新。", "二公榮貴雖同轍，如此盛事真無倫。", "先子姓名叨附驥，况復團司同典記。", "遺簪墮履儻未捐，惠顧尚期逮孫子。", "鯫生鼓篋趨賢關，朔風急勁脩塗艱。", "坱圠洪鈞轉一氣，爲借陽和先破寒。"]'),
('940cf077-4972-40da-a0c6-75bec5d9c1df','餞王郎中赴湖南倉','許應龍','宋','宋诗','song-poetry','','[]','明明天子御丹扆，首擇英賢將使指。',144,'全唐诗/poet.song.184000.json','["明明天子御丹扆，首擇英賢將使指。", "湖湘以南闕倉臺，環顧在廷誰足倚。", "蓬山蘭省輟名流，禮樂光華共心企。", "看看六轡載馳驅，爰度爰諏逮田里。", "散財發廩蘇阨窮，揚善舉賢律貪鄙。", "第恐崇臺未突黔，趣上亨衢詔泥紫。", "與君同齒復同寅，那更著庭紹英軌。", "交情金石久益堅，人雖漸遠心則邇。", "衡陽鴈過可傳書，時願劉公貽一紙。"]'),
('00a51c76-7498-48f0-93f1-50ca49d6d68c','賀同知生辰','許應龍','宋','宋诗','song-poetry','','[]','訾陬之月如陽春，君臣慶會應昌辰。',192,'全唐诗/poet.song.184000.json','["訾陬之月如陽春，君臣慶會應昌辰。", "虹星牛渚將誕聖，崧高維嶽先生申。", "日角珠庭輝綠鬢，仙風道骨真宣靖。", "才凌鐵幹四十圍，量狹銀潢三萬頃。", "端委樞庭贊化工，制勝謀謨談笑中。", "九扈告成村墅月，一塵不警戍樓風。", "勳名元是青氈舊，衮衮名公誰出右。", "黄麻昕夕下彤廷，玉带貂蟬輝衮繡。", "曈矓瑞日上公槐，宣勸黄封天上來。", "賸喜千秋佳節近，需雲復宴鳳凰臺。", "福祿固知公自有，不待占星問牛斗。", "鯫生只備三千詩，留取年年祝公壽。"]'),
('f6df26c8-a42b-4203-8ed2-d456f12d0e0f','代上庠同舍上廷評','許應龍','宋','宋诗','song-poetry','','[]','憶昔弱冠遊芹宮，潁川先生振文風。',288,'全唐诗/poet.song.184000.json','["憶昔弱冠遊芹宮，潁川先生振文風。", "躚躚媚學比如櫛，摳衣執經函丈中。", "何人才識最奇偉，惟公表裏珪璋粹。", "學精姬公經國書，賦飄司馬凌雲氣。", "詞場價湧薦爭魁，賜也何如敢望回。", "一別星霜踰十閲，側耳譽聲轟如雷。", "翩翩薦鶚翔西淛，一飛直上黄金闕。", "排雲披腹呈琅玕，蟾窟仙枝徑攀折。", "枳棘難淹鸞鳳栖，金科得雋易如携。", "趨歸立拜廷評命，青瑣黄扉指日躋。", "屈指曩年同硯席，五人已作龍門客。", "鄉書黌舍多有之，碌碌未能著奇節。", "著鞭無若祖生先，策足要津儀班聯。", "自笑塵蹤猶隠霧，拭目亨衢問天淵。", "綈袍戀戀故人意，墮履遺簪未捐棄。", "不求而薦佩私恩，高誼如公今有幾。", "雖然前事已參差，荷借鄒生律再吹。", "苦無好語爲公謝，抖擻枯腸成此詩。"]'),
('032bbaa7-0109-4bfe-aad1-3fd4e7390f65','鳳池立碑紀事','許應龍','宋','宋诗','song-poetry','','[]','閲盡衣冠盛事圖，三魁同郡古來無。',64,'全唐诗/poet.song.184000.json','["閲盡衣冠盛事圖，三魁同郡古來無。", "詞科得雋真鴻筆，仙籍聯榮總鉅儒。", "此日姓名輝石刻，他年步武接天衢。", "浯溪更把元勳勒，藉藉休聲震八區。"]'),
('5d0b17e8-918f-44f4-911c-aa6414930c4e','贈鄭樞密','許應龍','宋','宋诗','song-poetry','','[]','丘壑方將窈窕尋，肯貪斗印耀黄金。',64,'全唐诗/poet.song.184000.json','["丘壑方將窈窕尋，肯貪斗印耀黄金。", "幾頒中扆留行詔，莫返元樞勇退心。", "紅旆分藩雖足樂，丹誠戀闕自難禁。", "浮雲出岫知無意，祇恐蒼生望更深。"]'),
('84e946b4-5ac8-4b4a-97c3-6b9e051098b0','拜賜宮花紀恩詩  其一','許應龍','宋','宋诗','song-poetry','','[]','濟濟蹌蹌藹縉紳，祝堯均效華封人。',64,'全唐诗/poet.song.184000.json','["濟濟蹌蹌藹縉紳，祝堯均效華封人。", "觴稱鳳闕懽聲沸，花錫鸞枝內樣新。", "露葉巧裁隋苑彩，天葩先借漢宮春。", "舉頭仰戴君恩重，好盡忠誠報紫宸。"]'),
('f3c34af5-8d75-493d-a337-19e65455a376','拜賜宮花紀恩詩  其二','許應龍','宋','宋诗','song-poetry','','[]','不用涼州羯鼓催，陽和已逐小春來。',64,'全唐诗/poet.song.184000.json','["不用涼州羯鼓催，陽和已逐小春來。", "誰將萬點花間艷，都向百官頭上開。", "樣巧賸裁隋苑彩，影摇斜蘸漢宮杯。", "玉階再拜君恩重，洋溢懽聲遍九垓。"]'),
('c58d3446-2ed0-4094-9337-496dc549ccc7','和權郡重九韵','許應龍','宋','宋诗','song-poetry','','[]','鈴齋靜暇鎖棠陰，幽壑何妨窈窕尋。',64,'全唐诗/poet.song.184000.json','["鈴齋靜暇鎖棠陰，幽壑何妨窈窕尋。", "咳唾珠璣輝衆目，錚鏦琴瑟樂賓心。", "引杯非爲黄花醉，設席欣逢皂蓋臨。", "來歲茱萸賜朝士，看君鯨吸玉壺斟。"]'),
('9f59951d-687b-4e6a-bf36-6e06bc650762','和閩帥  其一','許應龍','宋','宋诗','song-poetry','','[]','龍飛天子攬英雄，舊德欣逢泰道通。',64,'全唐诗/poet.song.184000.json','["龍飛天子攬英雄，舊德欣逢泰道通。", "丹詔果然頒北闕，綵舟行矣駕東風。", "雨餘杉徑新添綠，暖入花粧旋姹紅。", "待得湖邊春色滿，我公已在鳳池中。"]'),
('f4591bcd-1e6d-44e5-b1be-f689ce1aea2e','和閩帥  其二','許應龍','宋','宋诗','song-poetry','','[]','新鑿南湖接海潮，油幢領客泛蘭橈。',64,'全唐诗/poet.song.184000.json','["新鑿南湖接海潮，油幢領客泛蘭橈。", "那知半夜雨聲急，却放新晴物色饒。", "盡日登臨陪步武，高談灑落挹風標。", "陽春白雪真難和，泚筆惟書道路謠。"]'),
('76c075df-755d-4977-89ed-1dec99abd3a7','和鄒守鹿鳴宴','許應龍','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','賢守聲名重泰山，肯將曲學誤儒冠。',64,'全唐诗/poet.song.184000.json','["賢守聲名重泰山，肯將曲學誤儒冠。", "相期素節終身履，不道青雲得路難。", "多士聯翩閶闔去，忠言凌厲雪霜寒。", "朱轓指日歸楓禁，廷策煩公具眼看。"]'),
('98c279f2-2ceb-4015-9f7e-ad1de95e23f2','館中和賞桂詩','許應龍','宋','宋诗','song-poetry','','[]','喜陪盛集桂叢間，擬賦新詩未敢先。',64,'全唐诗/poet.song.184000.json','["喜陪盛集桂叢間，擬賦新詩未敢先。", "忽拜清篇真寡和，難將拙語更爭妍。", "枝頭爛漫黄金粟，席上風流紫府僊。", "凡骨豈容攀俊軌，也沾賸馥醉花前。"]'),
('68993ac8-11dd-4a88-ae82-030841ffe08e','挽節使少保  其一','許應龍','宋','宋诗','song-poetry','','[]','一節忠勤紹祖風，貂蟬七葉擅華宗。',64,'全唐诗/poet.song.184000.json','["一節忠勤紹祖風，貂蟬七葉擅華宗。", "版曹羨利巍遷秩，强敵知名特斂容。", "薦士半躋青瑣闥，爲民數奏皂囊封。", "龍旂虎節今何在，紀績還須仗蔡邕。"]'),
('034b1b71-3e4c-48c0-a912-2bab8c11a92a','挽節使少保  其二','許應龍','宋','宋诗','song-poetry','','[]','衮衣赤舄我公歸，共傒登庸翊政機。',64,'全唐诗/poet.song.184000.json','["衮衣赤舄我公歸，共傒登庸翊政機。", "楓禁荐頒天語渥，薤歌我嘆露華晞。", "真王未復青氈舊，亞保空餘紫誥輝。", "突兀麒麟圖繪處，仰瞻遺像倍歔欷。"]'),
('f52c776c-2454-48fc-ab2f-be4004376c74','挽李文昌  其一','許應龍','宋','宋诗','song-poetry','','[]','顒顒德望重朝廷，况有胸中千萬兵。',64,'全唐诗/poet.song.184000.json','["顒顒德望重朝廷，况有胸中千萬兵。", "蠻獠未擒宵旰慮，軺車一出笑談平。", "囊封力沮和戎議，制閫咸推料敵精。", "壯志未酬天不憗，空餘草木識威名。"]'),
('f0fc3a95-dddc-4e90-b680-cb2142975f04','挽李文昌  其二','許應龍','宋','宋诗','song-poetry','','[]','盛名從古號難居，公獨崢嶸四紀餘。',64,'全唐诗/poet.song.184000.json','["盛名從古號難居，公獨崢嶸四紀餘。", "禁陛幾年聞曳履，帥垣三度拜除書。", "壽祺合享千齡永，往事俄驚一夢如。", "久矣辱知慚未報，仰瞻丹旐倍欷歔。"]'),
('4dcc4611-d48a-4788-92ef-7ce89bba60b6','潘上舍父挽詩  其一','許應龍','宋','宋诗','song-poetry','','[]','狗苟蠅營笑俗情，機心降盡倒風旌。',64,'全唐诗/poet.song.184000.json','["狗苟蠅營笑俗情，機心降盡倒風旌。", "人生六袠不爲夭，家累千金能享成。", "老去月評推吉德，生前天爵謝虛榮。", "悲風瑟瑟飛丹旐，行道歔欷亦失聲。"]'),
('5d7d9020-5cdd-49bc-925a-b4d2ad4c6f77','潘上舍父挽詩  其二','許應龍','宋','宋诗','song-poetry','','[]','蘭玉賢關雋譽飛，詞場幾見捷音馳。',64,'全唐诗/poet.song.184000.json','["蘭玉賢關雋譽飛，詞場幾見捷音馳。", "登雲將慰椿庭望，陟岵俄驚薤露悲。", "榮養痛嗟今日隔，嘉封頼有異時追。", "前岡已卜牛眠地，螭首行鎸九尺碑。"]'),
('35950dde-b8d7-40d1-955b-1ec4e5166ff5','夫人黄氏挽詩','許應龍','宋','宋诗','song-poetry','','[]','樞庭勇退古無前，內助端由婦德賢。',64,'全唐诗/poet.song.184000.json','["樞庭勇退古無前，內助端由婦德賢。", "燠館涼臺供燕樂，衮衣褕翟慶聯翩。", "雖云生死皆同歲，猶恨徜徉未百年。", "遥想銘旌摇曳處，江山草木亦凄然。"]'),
('3762ea6b-4a9d-4429-963a-3431d4078d42','代同舍上郎中  其一','許應龍','宋','宋诗','song-poetry','','[]','人物依然呂洞賓，冰霜風骨玉精神。',32,'全唐诗/poet.song.184000.json','["人物依然呂洞賓，冰霜風骨玉精神。", "退朝花底千官散，標格如公有幾人。"]'),
('f518c4df-7224-4810-9279-fef9b248b5de','代同舍上郎中  其二','許應龍','宋','宋诗','song-poetry','','[]','能賦人人說潁川，誰知妙訣已親傳。',32,'全唐诗/poet.song.184000.json','["能賦人人說潁川，誰知妙訣已親傳。", "詞場屢草干將句，擲地金聲震九天。"]'),
('f0d79bc6-139b-4289-9d07-6d77e8e660d9','代同舍上郎中  其三','許應龍','宋','宋诗','song-poetry','','[]','逸氣飄飄正妙年，縱橫禮樂掃三千。',32,'全唐诗/poet.song.184000.json','["逸氣飄飄正妙年，縱橫禮樂掃三千。", "臚傳玉陛星辰曉，姓字巍居鼎甲先。"]'),
('bedd2651-1978-4fb6-ab4f-0a21afd06d3c','代同舍上郎中  其四','許應龍','宋','宋诗','song-poetry','','[]','父子同時踐禁塗，一門榮耀世間無。',32,'全唐诗/poet.song.184000.json','["父子同時踐禁塗，一門榮耀世間無。", "願憑曹霸丹青筆，繪入衣冠盛事圖。"]'),
('6d7ac06f-e690-4cb4-a6f3-ca8c5a9ac6d9','代同舍上郎中  其五','許應龍','宋','宋诗','song-poetry','','[]','冊府方羊冠列仙，粉闈深處爛星躔。',32,'全唐诗/poet.song.184000.json','["冊府方羊冠列仙，粉闈深處爛星躔。", "黄扉已設屏風隔，會見絲綸下日邊。"]'),
('ef2f7ce0-9a4b-41a0-b478-aa5c7d27fd9f','題西巖寺  其一','許應龍','宋','宋诗','song-poetry','','[]','第一巖前風景殊，山僧去後野雲孤。',32,'全唐诗/poet.song.184000.json','["第一巖前風景殊，山僧去後野雲孤。", "歸來不費絲毫力，幻出天宮一畫圖。"]'),
('53c505fb-83e2-49a6-bea4-ccd6cbb29332','題西巖寺  其二','許應龍','宋','宋诗','song-poetry','','[]','修行極則到心安，靜處忙中只一般。',32,'全唐诗/poet.song.184000.json','["修行極則到心安，靜處忙中只一般。", "談笑打開新鋪席，此身元不離蒲團。"]'),
('7210acd9-67ec-4b5b-b262-0244e5f27f32','自嘆','許應龍','宋','宋诗','song-poetry','','[]','僕訴無衣婢訴饑，老妻終日不開眉。',32,'全唐诗/poet.song.184000.json','["僕訴無衣婢訴饑，老妻終日不開眉。", "十年待得齊瓜熟，又似齊瓜未熟時。"]'),
('1ab81946-e90a-4e5d-8dc7-a44343d248c7','薺菜','許應龍','宋','宋诗','song-poetry','','[]','撥雪挑來葉轉青，自刪自煮作杯羹。',32,'全唐诗/poet.song.184000.json','["撥雪挑來葉轉青，自刪自煮作杯羹。", "寶階香砌何曾識，偏向寒門滿地生。"]'),
('417be76a-6fd0-46fb-ab14-45a0c5c76943','東庵廣福禪院','許應龍','宋','宋诗','song-poetry','','[]','十年不到雪峰山，寂寂春風晝掩關。',32,'全唐诗/poet.song.184000.json','["十年不到雪峰山，寂寂春風晝掩關。", "千載祖師無盡意，門前流水綠回環。"]'),
('6d7c1fdb-9f0a-43ac-a129-2e73ead354d9','偈頌五十一首  其一','釋道沖','宋','宋诗','song-poetry','','[]','我此一門，全無肯路。',20,'全唐诗/poet.song.184000.json','["我此一門，全無肯路。", "是汝諸人，如何進步。"]'),
('b10b7044-7f76-48d6-a6bd-379bcf285f27','偈頌五十一首  其二','釋道沖','宋','宋诗','song-poetry','','[]','孰名爲佛，禮者是誰。',23,'全唐诗/poet.song.184000.json','["孰名爲佛，禮者是誰。", "設或未辨端倪，看四稜塌地。"]'),
('3a16464e-bfeb-47bb-9575-fb6ec05e478e','偈頌五十一首  其三','釋道沖','宋','宋诗','song-poetry','','[]','拄杖頭邊宇宙空，去留千聖覓無蹤。',32,'全唐诗/poet.song.184000.json','["拄杖頭邊宇宙空，去留千聖覓無蹤。", "直饒未舉知端的，猶隔白雲千萬重。"]'),
('b55056f9-6a0f-4f57-ac5d-63d082fa2926','偈頌五十一首  其四','釋道沖','宋','宋诗','song-poetry','','[]','十字街頭，有條活路。',34,'全唐诗/poet.song.184000.json','["十字街頭，有條活路。", "沒量大人，不知落處。", "無落處，擬欲追蹤，西天此土。"]'),
('9f1682d0-91af-4363-ab2b-55b7693ee6ae','偈頌五十一首  其五','釋道沖','宋','宋诗','song-poetry','','[]','今日中秋節，拄杖爲人切。',40,'全唐诗/poet.song.184000.json','["今日中秋節，拄杖爲人切。", "撥開千嶂雲，放出一輪月。", "光未生時薦得親，依然眼裏重添屑。"]'),
('60695e3a-d753-49ab-8715-311a0e84a181','偈頌五十一首  其六','釋道沖','宋','宋诗','song-poetry','','[]','凡所有相，皆是虛妄。',44,'全唐诗/poet.song.184000.json','["凡所有相，皆是虛妄。", "懷州牛喫禾，益州馬腹脹。", "若見諸相非相，即見如來。", "一切難捨，無過己財。"]'),
('919d42d2-ed1e-484d-a727-4541adcdadd8','偈頌五十一首  其七','釋道沖','宋','宋诗','song-poetry','','[]','一不得向，二不得背。',50,'全唐诗/poet.song.184000.json','["一不得向，二不得背。", "絲毫及不盡，古鏡生瑕纇。", "拈起鐵蒺蔾，一時俱擊碎。", "從教大地黑漫漫，它家自有通人會。"]'),
('3ddd1aa8-f095-4604-bb53-38d84440619c','偈頌五十一首  其八','釋道沖','宋','宋诗','song-poetry','','[]','要入此門，初無方便。',33,'全唐诗/poet.song.184000.json','["要入此門，初無方便。", "須是諸人，脚尖具眼。", "苟或未然，客情步步隨人轉。"]'),
('0dbdbb27-4948-4443-ad3b-3aa7ce7d909f','偈頌五十一首  其九','釋道沖','宋','宋诗','song-poetry','','[]','古釋迦不先，今彌勒不後。',28,'全唐诗/poet.song.184000.json','["古釋迦不先，今彌勒不後。", "禮拜燒香一線通，從教笑破衲僧口。"]'),
('27211a05-fdb0-4b2f-a682-d9d3775040b7','偈頌五十一首  其一○','釋道沖','宋','宋诗','song-poetry','','[]','摩竭提國，親行此令。',20,'全唐诗/poet.song.184000.json','["摩竭提國，親行此令。", "盡大地人，喪身失命。"]'),
('e4780422-1783-4acc-8d1e-72c97342bd8d','偈頌五十一首  其一一','釋道沖','宋','宋诗','song-poetry','','[]','坐斷毗盧頂，踏翻千差路。',22,'全唐诗/poet.song.184000.json','["坐斷毗盧頂，踏翻千差路。", "須彌燈王，無插足處。"]'),
('3d0f03cf-8e90-4f37-af3c-8219ad89096e','偈頌五十一首  其一二','釋道沖','宋','宋诗','song-poetry','','[]','瓶錫當年寄此間，山雲冉冉水潺湲。',32,'全唐诗/poet.song.184000.json','["瓶錫當年寄此間，山雲冉冉水潺湲。", "而今重到經行處，一會水雲猶儼然。"]'),
('3a8d80f3-eb44-491f-91f3-8178e4aad430','偈頌五十一首  其一三','釋道沖','宋','宋诗','song-poetry','','[]','圓悟一關天下險，寶山有寶世間稀。',32,'全唐诗/poet.song.184000.json','["圓悟一關天下險，寶山有寶世間稀。", "透得關來探得寶，猶落吾家第二機。"]'),
('43d1771e-eaa7-4950-b435-ff432671b52b','偈頌五十一首  其一四','釋道沖','宋','宋诗','song-poetry','','[]','振法雷，擊法皷，布慈雲兮洒甘露。',32,'全唐诗/poet.song.184000.json','["振法雷，擊法皷，布慈雲兮洒甘露。", "只將此法爲全提，世世願爲諸佛母。"]'),
('bc3e22b5-ac5c-446e-ac7b-e4e7fc83df0d','偈頌五十一首  其一五','釋道沖','宋','宋诗','song-poetry','','[]','須彌可裂，海水可竭。',20,'全唐诗/poet.song.184000.json','["須彌可裂，海水可竭。", "若論此事，寧可截舌。"]'),
('af412cb5-4a6a-431e-9b55-c6f779cfaaac','偈頌五十一首  其一六','釋道沖','宋','宋诗','song-poetry','','[]','方丈屋損，寢處不得。',76,'全唐诗/poet.song.184000.json','["方丈屋損，寢處不得。", "常住乏糧，著衆不得。", "舊逋積如海，無錢還不得。", "大道在目前，有口說不得。", "若人透此四重關，堪與諸方爲軌則。", "趙州親見老南泉，觀音院裏有彌勒。"]'),
('8df0f59b-264f-4fbf-ab6f-3120e0f96e1e','偈頌五十一首  其一七','釋道沖','宋','宋诗','song-poetry','','[]','枯木龍吟，一切音響俱絕。',48,'全唐诗/poet.song.184000.json','["枯木龍吟，一切音響俱絕。", "髑髏眼活，一切色相皆空。", "覷著即瞎，聽著即聾。", "堪笑觀音大士，無端也證圓通。"]'),
('bd039a8b-af3f-4ed1-9450-f2f794276f23','偈頌五十一首  其一八','釋道沖','宋','宋诗','song-poetry','','[]','是著即錯，不是猶乖，一擊萬重關鎖開。',34,'全唐诗/poet.song.184000.json','["是著即錯，不是猶乖，一擊萬重關鎖開。", "老盧不會轉身句，便道明鏡亦非臺。"]'),
('c490713b-b720-4544-9ec4-c87407ef5b13','偈頌五十一首  其一九','釋道沖','宋','宋诗','song-poetry','','[]','我與釋迦老子，有不共戴天之讎。',33,'全唐诗/poet.song.184000.json','["我與釋迦老子，有不共戴天之讎。", "今日爲什麽燒香禮拜，不是冤家不聚頭。"]'),
('1520d92c-6c43-49bc-bcbc-effce9151710','偈頌五十一首  其二○','釋道沖','宋','宋诗','song-poetry','','[]','祖師門下絕人行，深險過於萬丈坑。',32,'全唐诗/poet.song.184000.json','["祖師門下絕人行，深險過於萬丈坑。", "垂手不能空費力，任佗堂上綠苔生。"]'),
('a10659a3-eafe-4eee-879e-a8e659169514','偈頌五十一首  其二一','釋道沖','宋','宋诗','song-poetry','','[]','高拋不至天，低擲不到地，南北東西無處避。',34,'全唐诗/poet.song.184000.json','["高拋不至天，低擲不到地，南北東西無處避。", "带累雪峰老人，喚作南山鱉鼻。"]'),
('928c3279-60fa-4533-a2c2-ea87bd8b70be','偈頌五十一首  其二二','釋道沖','宋','宋诗','song-poetry','','[]','佛高一丈，魔高一丈。',34,'全唐诗/poet.song.184000.json','["佛高一丈，魔高一丈。", "月落寒潭，雲生碧嶂。", "不識慈氏如來，喚作布袋和尚。"]'),
('9d5e9388-d62b-47f4-87fb-f302b9f4e926','偈頌五十一首  其二三','釋道沖','宋','宋诗','song-poetry','','[]','衲僧家，不著佛求，不著法求。',31,'全唐诗/poet.song.184000.json','["衲僧家，不著佛求，不著法求。", "然雖如是，在佗煙焰裏，爭敢不低頭。"]'),
('46f99f3c-7a00-4085-aca6-47a9cf8ada26','偈頌五十一首  其二四','釋道沖','宋','宋诗','song-poetry','','[]','德山棒如雨點，一棒棒痛徹骨髓。',30,'全唐诗/poet.song.184000.json','["德山棒如雨點，一棒棒痛徹骨髓。", "臨濟喝似雷奔，一喝喝轟破髑髏。"]'),
('185c5339-0977-47c1-b72f-8dcfd5fc5572','偈頌五十一首  其二五','釋道沖','宋','宋诗','song-poetry','','[]','天童用底，來育王用不著。',40,'全唐诗/poet.song.184000.json','["天童用底，來育王用不著。", "育王用底，歸天童用不著。", "用不著處用有餘，一箭雙鵰隨手落。"]'),
('de350586-05c7-41e2-bb46-075c61533943','偈頌五十一首  其二六','釋道沖','宋','宋诗','song-poetry','','[]','摩竭掩室，浄名杜口。',30,'全唐诗/poet.song.184000.json','["摩竭掩室，浄名杜口。", "天網恢恢，疎而不漏。", "是汝諸人，作麽生透。"]'),
('dc4c63f1-3fa2-446c-945f-4ec17aaaaa3e','偈頌五十一首  其二七','釋道沖','宋','宋诗','song-poetry','','[]','坐斷十方國土，天上天下獨尊底，一步也行不得。',68,'全唐诗/poet.song.184000.json','["坐斷十方國土，天上天下獨尊底，一步也行不得。", "口吞三世諸佛，世出世間俱透底，一句也說不得。", "堪與衲僧爲軌則。", "普化何似一頭馿，臨濟未是白拈賊。"]'),
('c3511888-4e59-4cbc-bf75-3f003694a77f','偈頌五十一首  其二八','釋道沖','宋','宋诗','song-poetry','','[]','有一物，名不得，狀不得，取不得，捨不得。',52,'全唐诗/poet.song.184000.json','["有一物，名不得，狀不得，取不得，捨不得。", "突出天童拄杖頭，倒用橫拈無軌則。", "戳瞎達磨鬼眼睛，靠倒臨濟白拈賊。"]'),
('f2761d39-36c7-4b7d-9630-31988bdcf42c','偈頌五十一首  其二九','釋道沖','宋','宋诗','song-poetry','','[]','心隨萬境轉，轉處實能幽。',28,'全唐诗/poet.song.184000.json','["心隨萬境轉，轉處實能幽。", "漢地不收秦不管，不風流處也風流。"]'),
('0d53d576-00ab-4a6f-b374-e218392480a1','偈頌五十一首  其三○','釋道沖','宋','宋诗','song-poetry','','[]','一徑直，二周遮。',36,'全唐诗/poet.song.184000.json','["一徑直，二周遮。", "遼天射飛鶚，平地摝魚蝦。", "堪笑秘魔巖不會，見人一味只擎叉。"]'),
('ffc10df4-6882-429e-8eba-99c16fc59064','偈頌五十一首  其三一','釋道沖','宋','宋诗','song-poetry','','[]','從上佛祖無法與人傳，後代兒孫會得是障礙。',40,'全唐诗/poet.song.184000.json','["從上佛祖無法與人傳，後代兒孫會得是障礙。", "礙不礙，竹山鐵鷂刺天飛，笑倒明州憨布袋。"]'),
('91772a05-ebd5-4b71-b8d3-9db4f7faeb12','偈頌五十一首  其三二','釋道沖','宋','宋诗','song-poetry','','[]','面皮擘破，喝散鍾山之雲。',40,'全唐诗/poet.song.184000.json','["面皮擘破，喝散鍾山之雲。", "拄杖橫挑，窮盡天台之境。", "玲瓏巖下忽相逢，一笑令人發深省。"]'),
('86a749bc-1966-4811-a32e-4d0400061629','偈頌五十一首  其三三','釋道沖','宋','宋诗','song-poetry','','[]','正法眼，破沙盆。',44,'全唐诗/poet.song.184000.json','["正法眼，破沙盆。", "貴時傾國不換，賤時不直分文。", "不作貴，不作賤。", "分付石溪老子，共結佛祖深冤。"]'),
('c2356d73-d158-4a9f-860d-140f1ec91c74','偈頌五十一首  其三四','釋道沖','宋','宋诗','song-poetry','','[]','圓覺伽藍，塵塵有路。',52,'全唐诗/poet.song.184000.json','["圓覺伽藍，塵塵有路。", "坐斷去來，頓空今古。", "那裏十三，這邊十五，後先不差毫髮許。", "可笑黄面瞿曇，至今不知落處。"]'),
('b81c713f-e990-4dc7-b067-c85e2a2cb711','偈頌五十一首  其三五','釋道沖','宋','宋诗','song-poetry','','[]','羣陰剝盡，一陽來復。',50,'全唐诗/poet.song.184000.json','["羣陰剝盡，一陽來復。", "萬彙咸亨承化育，拄杖機輪轉轆轆。", "轉天關，回地軸。", "百億分身遍剎塵，應時納祐從人欲。"]'),
('22c71e83-5724-4086-b1f6-fba4f9e2acea','偈頌五十一首  其三六','釋道沖','宋','宋诗','song-poetry','','[]','祕魔擎杈，趙州喫茶。',36,'全唐诗/poet.song.184000.json','["祕魔擎杈，趙州喫茶。", "禾山打皷，歸宗斬蛇。", "慣釣鯨鯢沉巨浸，却嗟蛙步𩥇泥沙。"]'),
('62c03c53-5146-474a-95ef-65b8da6bfe21','偈頌五十一首  其三七','釋道沖','宋','宋诗','song-poetry','','[]','龍床一繞定綱宗，四海從茲信息通。',32,'全唐诗/poet.song.184000.json','["龍床一繞定綱宗，四海從茲信息通。", "但見皇風成一片，不知何處是疆封。"]'),
('6491cf52-a7ba-438b-83ce-5690dd1c7326','偈頌五十一首  其三八','釋道沖','宋','宋诗','song-poetry','','[]','釋迦出世拏空塞空，達磨西來將錯就錯。',46,'全唐诗/poet.song.184000.json','["釋迦出世拏空塞空，達磨西來將錯就錯。", "带累後代兒孫，一例隨處卜度。", "休卜度，四海浪平，百川潮落。"]'),
('898921c5-12dc-4fe3-aa7e-02a328688ccc','偈頌五十一首  其三九','釋道沖','宋','宋诗','song-poetry','','[]','欲去不去被去礙，欲住不住被住礙。',36,'全唐诗/poet.song.184000.json','["欲去不去被去礙，欲住不住被住礙。", "元不礙，十洲三島鶴乾坤，四海五湖龍世界。"]'),
('02af0e4f-a23e-479e-af63-9494e3bd2c0b','偈頌五十一首  其四○','釋道沖','宋','宋诗','song-poetry','','[]','此門深固幽遠，無人能到。',24,'全唐诗/poet.song.184000.json','["此門深固幽遠，無人能到。", "如能到，脚頭脚底長安道。"]'),
('280d2679-9b22-454c-b43a-bea290a4d41e','偈頌五十一首  其四一','釋道沖','宋','宋诗','song-poetry','','[]','閑地三寸刃鋒鋩，匝地風霜定紀綱。',32,'全唐诗/poet.song.184000.json','["閑地三寸刃鋒鋩，匝地風霜定紀綱。", "若是丈夫真意氣，任君敲磕振風光。"]'),
('1efb120c-b28d-461e-b181-06931214a5d3','偈頌五十一首  其四二','釋道沖','宋','宋诗','song-poetry','','[]','好事不出門，惡事行千里。',34,'全唐诗/poet.song.184000.json','["好事不出門，惡事行千里。", "好惡不到處，總不在這裏。", "不是俊流，徒勞側耳。"]'),
('0c364092-7793-4844-96e1-868d3b99b1c2','偈頌五十一首  其四三','釋道沖','宋','宋诗','song-poetry','','[]','相國親傳黄蘗心，移山新作古叢林。',64,'全唐诗/poet.song.184000.json','["相國親傳黄蘗心，移山新作古叢林。", "大千沙界針鋒許，十二峰巒巖壑深。", "此道明明元不古，清風浩浩至于今。", "禪流不負王臣意，行看祇園側布金。"]'),
('dcab6d0d-9a46-4098-97bc-612b187a52e6','偈頌五十一首  其四四','釋道沖','宋','宋诗','song-poetry','','[]','天無門，地無戶，可中自有凌霄路。',26,'全唐诗/poet.song.184000.json','["天無門，地無戶，可中自有凌霄路。", "普請諸人，進這一步。"]'),
('2a63be2c-9a60-42de-ae2f-dfcad844562e','偈頌五十一首  其四五','釋道沖','宋','宋诗','song-poetry','','[]','佛佛是何物，天上人間遭誑惑。',28,'全唐诗/poet.song.184000.json','["佛佛是何物，天上人間遭誑惑。", "不辭禮拜燒香，只向這裏雪屈。"]'),
('fa4d0de3-e442-4dc7-8e0f-875f958d5f37','偈頌五十一首  其四六','釋道沖','宋','宋诗','song-poetry','','[]','耳聾眼暗步龍鍾，畢竟憑何住五峰。',32,'全唐诗/poet.song.184000.json','["耳聾眼暗步龍鍾，畢竟憑何住五峰。", "天網恢恢無避處，不妨隨分展家風。"]'),
('d010fe55-e2ac-463c-8297-395184f7cc09','偈頌五十一首  其四七','釋道沖','宋','宋诗','song-poetry','','[]','國王大臣，有力檀那。',36,'全唐诗/poet.song.184000.json','["國王大臣，有力檀那。", "以佛爲心，助佛揚化。", "靈山一會儼然存，正法眼藏增高價。"]'),
('791eaefe-45c4-49d6-a3b2-ea9244da35e5','偈頌五十一首  其四八','釋道沖','宋','宋诗','song-poetry','','[]','若論此事，青天白日。',50,'全唐诗/poet.song.184000.json','["若論此事，青天白日。", "情與無情，俱無得失，自是諸人不委悉。", "山僧住持事繁，也要爲人拈出，今朝十一月初一。"]'),
('d545652a-353d-4c47-a08a-176da44ebdf4','偈頌五十一首  其四九','釋道沖','宋','宋诗','song-poetry','','[]','四九三十六，夜眠如露宿。',26,'全唐诗/poet.song.184000.json','["四九三十六，夜眠如露宿。", "凍殺無位真人，走入冰池裏浴。"]'),
('faa2cffa-edc6-41df-8b14-eabfe8ae4892','偈頌五十一首  其五○','釋道沖','宋','宋诗','song-poetry','','[]','四海一國土，乾坤一聖人。',24,'全唐诗/poet.song.184000.json','["四海一國土，乾坤一聖人。", "只憑這箇法，仰祝萬年春。"]'),
('cba753e6-8dbe-48c7-bf96-50d7647a3c11','偈頌五十一首  其五一','釋道沖','宋','宋诗','song-poetry','','[]','五日風，十日雨。',18,'全唐诗/poet.song.184000.json','["五日風，十日雨。", "君聖臣賢，歌謠滿路。"]'),
('b5118964-0c42-4290-ad32-70ef2ce1c27d','出山相','釋道沖','宋','宋诗','song-poetry','','[]','天上星，眼中睛。',40,'全唐诗/poet.song.184000.json','["天上星，眼中睛。", "星無悟人之意，睛無矚物之情。", "以理而會，自誠而明，究竟何曾有道成。"]'),
('f6ef3416-538f-46b5-a13a-c96136a7dc69','觀音大士讚','釋道沖','宋','宋诗','song-poetry','','[]','一切音聲相，是人聽以耳。',180,'全唐诗/poet.song.184000.json','["一切音聲相，是人聽以耳。", "我圜通大士，唯以眼而聽。", "非特以眼聽，六根互爲用。", "當其互用時，根境不相雜。", "譬如帝珠網，交光相融攝。", "即此融攝相，各各住自位。", "以此三昧力，普施於一切。", "俾不離聲色，透出聲色海。", "眼處若聞聲，耳處得解脫。", "共證十方空，同名觀自在。", "我作如是贊，定招妄語罪。", "既招妄語罪，畫者亦是妄。", "畫者既是妄，此相非真實。", "於非真實處，此相常現前。", "應作如是觀，是真法供養。"]'),
('fc4ee95c-4e0b-4d36-9415-fe87c5f2c471','達磨大師讚  其一','釋道沖','宋','宋诗','song-poetry','','[]','楊子江心，波濤鼎沸。',43,'全唐诗/poet.song.184000.json','["楊子江心，波濤鼎沸。", "一葦可航，如履平地。", "蓋亦暫時之游戲，豈足以盡此老十萬里西來之本意。"]'),
('ef1fcc6a-3224-45c4-a6f3-c47c5c0a5cba','達磨大師讚  其二','釋道沖','宋','宋诗','song-poetry','','[]','人皆有心，人皆作佛。',46,'全唐诗/poet.song.184000.json','["人皆有心，人皆作佛。", "胡爲西來，遞相誑惑。", "心在何處，佛是何物。", "带累神光無處尋，後代兒孫廝淈𣸩。"]'),
('46afad5f-dd57-4881-b5a2-5e6344f047e7','曹源和尚讚  其一','釋道沖','宋','宋诗','song-poetry','','[]','遭密庵駡，恨入骨髓。',48,'全唐诗/poet.song.184000.json','["遭密庵駡，恨入骨髓。", "此恨難忘，充塞天地。", "四海五湖無處避，能有幾人著它底。", "著它底，冤冤相報無窮已。"]'),
('01ec5d13-dc7e-4981-aee2-837f3c077f84','曹源和尚讚  其二','釋道沖','宋','宋诗','song-poetry','','[]','父曹源，祖密庵。',65,'全唐诗/poet.song.184000.json','["父曹源，祖密庵。", "碧落碑，無贋本。", "破沙盆，正法眼。", "清廟瑟有遺音，坐者立者，以心印心。", "不肖之子，作如是讚。", "非特旌於往古，亦乃詔於來今。"]'),
('cdf72b7a-4b6f-407e-b3b9-150bce8dd0c6','丙辰年別龜峰曹源和尚  其一','釋道沖','宋','宋诗','song-poetry','','[]','葛溪深處定宗綱，一任乾坤大地荒。',32,'全唐诗/poet.song.184000.json','["葛溪深處定宗綱，一任乾坤大地荒。", "但得棒頭明似日，可無臨濟解承當。"]'),
('57da9c9c-3efa-436e-b0b6-d565627f8e3e','丙辰年別龜峰曹源和尚  其二','釋道沖','宋','宋诗','song-poetry','','[]','拚命來經蠱毒家，不嘗滴水喪生涯。',32,'全唐诗/poet.song.184000.json','["拚命來經蠱毒家，不嘗滴水喪生涯。", "尚餘窮相一雙手，要向諸方癢處爬。"]'),
('3f733ca6-0802-49f9-824a-aba254c6a8ee','丙辰年別龜峰曹源和尚  其三','釋道沖','宋','宋诗','song-poetry','','[]','破袱從東挾過西，何時再上惡鉗鎚。',32,'全唐诗/poet.song.184000.json','["破袱從東挾過西，何時再上惡鉗鎚。", "怒雷一吼聾三日，自有怨憎會苦時。"]'),
('ee34181e-8051-4b2b-a00b-ef7d64c86a31','戊午在靈隠聞曹源和尚訃音兼小師舉老爲開語錄  其一','釋道沖','宋','宋诗','song-poetry','','[]','杖藜隨處是乾坤，迦葉峰前便垛根。',32,'全唐诗/poet.song.184000.json','["杖藜隨處是乾坤，迦葉峰前便垛根。", "貪看煙巒三十二，到頭不識老曹源。"]'),
('c8e9d035-6b66-4861-a48e-6d537145567c','戊午在靈隠聞曹源和尚訃音兼小師舉老爲開語錄  其二','釋道沖','宋','宋诗','song-poetry','','[]','悔不當初放拍盲，爛椎一頓快平生。',32,'全唐诗/poet.song.184000.json','["悔不當初放拍盲，爛椎一頓快平生。", "近聞活陷阿鼻獄，撫掌呵呵樂太平。"]'),
('70432b9a-ecc4-4e8d-8be2-8dee978509d3','戊午在靈隠聞曹源和尚訃音兼小師舉老爲開語錄  其三','釋道沖','宋','宋诗','song-poetry','','[]','三處移場定紀綱，曾無一字落諸方。',32,'全唐诗/poet.song.184000.json','["三處移場定紀綱，曾無一字落諸方。", "破家種草癡狂甚，醜惡無端向外揚。"]'),
('872cf02f-7dfc-4b5a-951c-450fb5eee35d','看相撲','釋道沖','宋','宋诗','song-poetry','','[]','拳來踢去疾如飛，畢竟輸贏是阿誰。',32,'全唐诗/poet.song.184000.json','["拳來踢去疾如飛，畢竟輸贏是阿誰。", "閙裏有人能著眼，未曾交輥已先知。"]'),
('c18f06b1-ed3c-4731-bb10-aad81f676d2b','上尖竿','釋道沖','宋','宋诗','song-poetry','','[]','百尺琅玕摩碧空，四方八面絕羅籠。',32,'全唐诗/poet.song.184000.json','["百尺琅玕摩碧空，四方八面絕羅籠。", "等閑進得竿頭步，千聖齊教立下風。"]'),
('2374e7fc-ed8f-41ca-b257-646ad7ad98d0','退靈隠京尹節齋大資相公堅挽辭免','釋道沖','宋','宋诗','song-poetry','','[]','叢林虛得譽，無一補宗門。',48,'全唐诗/poet.song.184000.json','["叢林虛得譽，無一補宗門。", "有誤王臣鑑，徒霑聖主恩。", "豈堪持鈯斧，只合傍雲根。", "默感始終惠，此生難盡言。"]'),
('7ad9542a-1717-4405-a906-45424632515d','佛成道','釋道沖','宋','宋诗','song-poetry','','[]','正覺山前失眼睛，是凡是聖盡盲生。',32,'全唐诗/poet.song.184000.json','["正覺山前失眼睛，是凡是聖盡盲生。", "至今夜夜明星現，誰肯向伊行處行。"]'),
('20277736-6274-44d6-9d39-3d5e49a374ec','佛涅槃','釋道沖','宋','宋诗','song-poetry','','[]','山花如錦水如藍，觸目熙熙春正酣。',32,'全唐诗/poet.song.184000.json','["山花如錦水如藍，觸目熙熙春正酣。", "若謂雙林曾滅度，分明蹉過老瞿曇。"]'),
('af8b4146-b6b1-488d-941e-8f62a0e37447','二祖贊','釋道沖','宋','宋诗','song-poetry','','[]','隻臂冷隨霜刃落，雪花分墜立齊腰。',32,'全唐诗/poet.song.184000.json','["隻臂冷隨霜刃落，雪花分墜立齊腰。", "覓心無得安心竟，行到窮源逢斷橋。"]'),
('d9a003c3-993f-47d3-88dd-a5acfde8fc2d','三祖贊  其一','釋道沖','宋','宋诗','song-poetry','','[]','了知罪性本來無，絕後何曾得載甦。',32,'全唐诗/poet.song.184000.json','["了知罪性本來無，絕後何曾得載甦。", "元是從前風恙病，被佗斷臂强塗糊。"]'),
('98bebc1c-ad4a-42a6-b6a6-db006003ff62','三祖贊  其二','釋道沖','宋','宋诗','song-poetry','','[]','通身是病骨粘皮，舉世無人識得伊。',32,'全唐诗/poet.song.184000.json','["通身是病骨粘皮，舉世無人識得伊。", "縱使罪根都懺了，依前失却兩莖眉。"]'),
('9f3ca29b-16b9-442b-b4ca-83f50c4b48f2','四祖贊  其一','釋道沖','宋','宋诗','song-poetry','','[]','抹過從前解脫坑，雙溪路上絕人行。',32,'全唐诗/poet.song.184000.json','["抹過從前解脫坑，雙溪路上絕人行。", "衣盂至老無分付，逼得栽松死復生。"]'),
('6a0c6fe5-82cb-4370-aa7d-7a156f9720c9','四祖贊  其二','釋道沖','宋','宋诗','song-poetry','','[]','破頭峰頂掩禪關，三却天書不下山。',32,'全唐诗/poet.song.184000.json','["破頭峰頂掩禪關，三却天書不下山。", "究竟全無些氣息，有何面目見龍顔。"]'),
('4c387db7-552b-4364-9a45-15e48cf79c58','五祖贊','釋道沖','宋','宋诗','song-poetry','','[]','萬本青松手自栽，老來無復强追陪。',32,'全唐诗/poet.song.184000.json','["萬本青松手自栽，老來無復强追陪。", "可憐溪畔周家女，也被渠儂脫賺來。"]'),
('f22d0c60-b54d-44ff-8232-16ba2574eff1','六祖贊  其一','釋道沖','宋','宋诗','song-poetry','','[]','七百高僧總會禪，眼空四海鼻遼天。',32,'全唐诗/poet.song.184000.json','["七百高僧總會禪，眼空四海鼻遼天。", "黄梅若也無私曲，有甚衣盂到汝傳。"]'),
('8161a75c-270c-4d30-8559-8f8c8e546392','六祖贊  其二','釋道沖','宋','宋诗','song-poetry','','[]','菱花撲碎已誵訛，夜半傳衣事轉多。',32,'全唐诗/poet.song.184000.json','["菱花撲碎已誵訛，夜半傳衣事轉多。", "從此曹溪玄路絕，無風夜起拍天波。"]'),
('78b7cf9b-841d-4697-8810-bdb7c93b9abe','談命','釋道沖','宋','宋诗','song-poetry','','[]','無位真人赤骨律，面門出入有誰知。',32,'全唐诗/poet.song.184000.json','["無位真人赤骨律，面門出入有誰知。", "太虛元與渠同壽，庚申憑君子細推。"]'),
('a3a30b12-8ffc-47f8-b416-c0fdfb6181a2','省親','釋道沖','宋','宋诗','song-poetry','','[]','娘生面目既分明，遠不疎兮近不親。',32,'全唐诗/poet.song.184000.json','["娘生面目既分明，遠不疎兮近不親。", "試向途中問歸客，不知誰是倚門人。"]'),
('a9fb8263-89a5-4b41-8072-6ad0de607c45','水燈','釋道沖','宋','宋诗','song-poetry','','[]','萬里烟波接素秋，銀缸耿耿泛中流。',32,'全唐诗/poet.song.184000.json','["萬里烟波接素秋，銀缸耿耿泛中流。", "自從一點光明後，逐浪隨波未肯休。"]'),
('023c60a7-33bd-4d3f-af1a-71d2ea397ee6','宗派圖','釋道沖','宋','宋诗','song-poetry','','[]','列派分宗定此圖，繩繩相貫茲聯珠。',32,'全唐诗/poet.song.184000.json','["列派分宗定此圖，繩繩相貫茲聯珠。", "不知佛祖未興日，還有許多消息無。"]'),
('2468a526-3b50-466e-9e3c-76d2f215cad0','苕菷','釋道沖','宋','宋诗','song-poetry','','[]','五藴山頭脫得身，草茆因此不同倫。',32,'全唐诗/poet.song.184000.json','["五藴山頭脫得身，草茆因此不同倫。", "幾番信手拈來用，大地從教絕點塵。"]'),
('97aaef95-7af1-478f-a6e8-1d4eabf423ec','面桶','釋道沖','宋','宋诗','song-poetry','','[]','做時不費工夫，用處全無滲漏。',28,'全唐诗/poet.song.184000.json','["做時不費工夫，用處全無滲漏。", "任是鼻孔遼天，未免低頭相就。"]'),
('1ff6d61b-11e9-4765-ad3c-a09bddcd09d4','臨終偈','釋道沖','宋','宋诗','song-poetry','','[]','末後一句，無可商量。',20,'全唐诗/poet.song.184000.json','["末後一句，無可商量。", "只要箇人，直下承當。"]'),
('ec43d2cd-9fb0-4c0c-950f-6237cfadf8c0','頌古六首  其一','釋道沖','宋','宋诗','song-poetry','','[]','正覺山前失眼睛，是凡是聖盡生盲。',32,'全唐诗/poet.song.184000.json','["正覺山前失眼睛，是凡是聖盡生盲。", "至今夜夜明星現，誰肯向伊行處行。"]'),
('864e4a66-f7bd-4b2d-be3b-590d6182ebe1','頌古六首  其二','釋道沖','宋','宋诗','song-poetry','','[]','平生罪性覓無蹤，直得乾坤大地空。',32,'全唐诗/poet.song.184000.json','["平生罪性覓無蹤，直得乾坤大地空。", "天地依然高突兀，潜溪一派自朝宗。"]'),
('490a3a79-8a0b-4f1e-9660-e7eea9b65637','頌古六首  其三','釋道沖','宋','宋诗','song-poetry','','[]','掀翻解脫脫巢窠，從此縵天布網羅。',32,'全唐诗/poet.song.184000.json','["掀翻解脫脫巢窠，從此縵天布網羅。", "落賺小兒猶自可，一枝橫出轉譊訛。"]'),
('8c880558-0f8a-4496-8b24-5661b61a00d9','頌古六首  其四','釋道沖','宋','宋诗','song-poetry','','[]','汝蒸飯時吾著火，汝行益時吾展鉢。',52,'全唐诗/poet.song.184000.json','["汝蒸飯時吾著火，汝行益時吾展鉢。", "尋常恁麽老婆心，自是你儂機不活。", "機若活，夾山本無奇特事，百川倒流閙聒聒。"]'),
('24266a96-412b-48dd-a628-a591c9598098','頌古六首  其五','釋道沖','宋','宋诗','song-poetry','','[]','賓主機先有路通，筆端不是判虛空。',32,'全唐诗/poet.song.184000.json','["賓主機先有路通，筆端不是判虛空。", "筯頭再運回天力，千聖齊教立下風。"]'),
('bebf30d4-45ee-4bdf-a87f-36c5016aa356','頌古六首  其六','釋道沖','宋','宋诗','song-poetry','','[]','到與不到，一得一失。',52,'全唐诗/poet.song.184000.json','["到與不到，一得一失。", "不是砒霜，便是石蜜。", "舌端無眼如何喫，侍者剛要詢端的。", "莫怪同坑無異土，閃電未收轟霹靂。"]'),
('44cade83-85d2-47f2-a542-64ad11e97b7f','淳祐辛酉立秋後一日遊鼓山','釋道沖','宋','宋诗','song-poetry','','[]','野徑斜連石澗傍，草根昵昵語寒螿。',64,'全唐诗/poet.song.184000.json','["野徑斜連石澗傍，草根昵昵語寒螿。", "郊原經雨多秋意，庭院無人自夕陽。", "風捲暮雲歸碧嶂，葉隨野水入寒塘。", "數家籬落楓林外，枳殻垂青菊綻黄。"]'),
('80fc7eaf-9912-4500-8ecb-def6131fd77a','徑山玉芝庵主源上人持癡絕老人語錄求作行狀留連踰月談論鏗鏘音吐鴻暢衆中之龍象也臨別書二絕贈行  其一','趙若琚','宋','宋诗','song-poetry','','[]','暑入單絺雨壓塵，扣門仍喜客來頻。',32,'全唐诗/poet.song.184000.json','["暑入單絺雨壓塵，扣門仍喜客來頻。", "從容爲說西來意，庭柏青青正可人。"]'),
('4e2a7aff-4145-4f24-8573-8008bff7476f','徑山玉芝庵主源上人持癡絕老人語錄求作行狀留連踰月談論鏗鏘音吐鴻暢衆中之龍象也臨別書二絕贈行  其二','趙若琚','宋','宋诗','song-poetry','','[]','應密單傳的的真，一番舉起一番新。',32,'全唐诗/poet.song.184000.json','["應密單傳的的真，一番舉起一番新。", "老師末後殷勤語，直下承當正要人。"]'),
('98e52b3e-d9e9-456d-b208-a3866051117f','呈癡絕庵主頌','徐敏子','宋','宋诗','song-poetry','','[]','癡絕有菴不肯住，弄老挑雲徑山去。',192,'全唐诗/poet.song.184000.json','["癡絕有菴不肯住，弄老挑雲徑山去。", "地水火風分裂時，親書贈予黄葛布。", "蛻封讀罷咽無語，會得龍鬚能辟暑。", "豈知玉骨本清涼，書則珍藏布不取。", "源老忽踏幽深路，道在隔山遥望處。", "巨帙已載閑葛藤，何堪又送閑家具。", "開眼一看笑呵呵，猶有這箇可奈何。", "來而不往非世法，聊效芹忱媿不多。", "兩角茶，十袋麵，寶瓶飛錢五十萬。", "虔心獻此一瓣香，奉爲禪師作清薦。", "且問先師來不來，玉山菴頂碧雲開。", "更煩大衆打圓相，撥取青蓮火裏灰。"]'),
('d511018f-9981-4dd1-9cea-7a4ba70ae53d','臘月初三日虜人攻城以强弩射退獲捷','趙萬年','宋','宋诗','song-poetry','','[]','四圍鉦鼓震天鳴，虜騎平明盡逼城。',32,'全唐诗/poet.song.184000.json','["四圍鉦鼓震天鳴，虜騎平明盡逼城。", "萬弩應絃因退走，却疑城上有神兵。"]'),
('4e48f0c7-6496-4346-997d-6eb7733b2621','臘八危家餉粥有感','趙萬年','宋','宋诗','song-poetry','','[]','襄陽城外漲胡塵，矢石叢中未死身。',32,'全唐诗/poet.song.184000.json','["襄陽城外漲胡塵，矢石叢中未死身。", "不爲主人供粥餉，爭知臘八是今辰。"]'),
('7ffa0b3b-3f53-4986-8f79-a7e92a465790','歲暮','趙萬年','宋','宋诗','song-poetry','','[]','歲暮嗟爲客，那堪復被圍。',24,'全唐诗/poet.song.184000.json','["歲暮嗟爲客，那堪復被圍。", "一心惟許國，視死已如歸。"]');
